INSERT INTO "public"."lesson" ("id", "class_id", "program_id", "title", "chapter", "order", "description", "theory_modules", "video_modules", "quizzes", "story_slides", "challenges", "game", "is_premium", "created_at", "updated_at", "intro_video_url") VALUES ('hoa10_kntt_bai1', 10, 'ketnoi', 'Bài 1: Thành phần của nguyên tử', 'Chương 1: Cấu tạo nguyên tử', 1, 'Tìm hiểu về hạt nhân (proton, neutron) and lớp vỏ electron của nguyên tử.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khám phá Electron: Thí nghiệm của J.J. Thomson","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Năm 1897, nhà vật lý J.J. Thomson đã thực hiện thí nghiệm phóng điện qua ống thủy tinh gần như chân không (ống tia âm cực). Ông quan sát thấy một chùm tia phát ra từ cực âm (cathode) lan truyền thẳng and bị lệch về phía cực dương khi đặt trong điện trường.\\n\\nKết luận: Chùm tia âm cực gồm những hạt cực nhỏ mang điện tích âm, gọi là **electron** (kí hiệu là $e$). Đây là thành phần cấu tạo nên mọi nguyên tử."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Đặc điểm của các hạt cơ bản","content":"| Hạt | Kí hiệu | Điện tích (C) | Điện tích quy ước | Khối lượng (kg) | Khối lượng (amu) |\\n| :--- | :--- | :--- | :--- | :--- | :--- |\\n| Electron | $e$ | $-1,602 \\\\times 10^{-19}$ | $-1$ | $9,11 \\\\times 10^{-31}$ | $0,00055$ |\\n| Proton | $p$ | $+1,602 \\\\times 10^{-19}$ | $+1$ | $1,673 \\\\times 10^{-27}$ | $1$ |\\n| Neutron | $n$ | $0$ | $0$ | $1,675 \\\\times 10^{-27}$ | $1$ |"}},{"id":"mod4","type":"heading","content":{"text":"2. Khám phá Hạt nhân: Thí nghiệm của E. Rutherford","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Năm 1911, Ernest Rutherford thực hiện thí nghiệm bắn phá một lá vàng mỏng bằng các hạt alpha ($\\\\alpha$) mang điện dương.\\n- **Kết quả**: Hầu hết các hạt $\\\\alpha$ đi thẳng, một số ít bị lệch hướng and rất ít hạt bị bật ngược lại.\\n- **Kết luận**:\\n  + Nguyên tử có **cấu tạo rỗng**.\\n  + Ở tâm nguyên tử có một vùng kích thước cực nhỏ nhưng tập trung toàn bộ điện tích dương and gần như toàn bộ khối lượng nguyên tử, gọi là ** hạt nhân **."}},{"id":"mod6","type":"heading","content":{"text":"3. Cấu trúc nguyên tử","level":"h2"}},{"id":"mod7","type":"paragraph","content":{"text":"Nguyên tử gồm hai phần chính:\\n\\n1. **Hạt nhân**: Nằm ở tâm, gồm các hạt **Proton** ($p$) and **Neutron** ($n$). Vì nguyên tử trung hòa về điện, nên số đơn vị điện tích dương của hạt nhân luôn bằng số electron ở lớp vỏ ($Z = p = e$).\\n2. **Lớp vỏ**: Chứa các **electron** chuyển động rất nhanh trong không gian xung quanh hạt nhân.\\n\\n**Kích thước**: Đường kính nguyên tử lớn gấp khoảng $10.000$ đến $100.000$ lần đường kính hạt nhân. Nếu coi nguyên tử như một sân vận động thì hạt nhân chỉ như một quả bóng tennis đặt ở trung tâm."}},{"id":"mod8","type":"warningBox","content":{"color":"orange","title":"Ghi nhớ quan trọng","content":"Khối lượng của electron rất nhỏ (không đáng kể so với p and n), do đó khối lượng của nguyên tử được coi là tập trung hoàn toàn ở hạt nhân."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=UuoLVALlxz0","title":"Bài giảng: Thành phần của nguyên tử","thumbnail":"https://img.youtube.com/vi/UuoLVALlxz0/0.jpg","description":"Tìm hiểu về cấu tạo nguyên tử, các loại hạt cơ bản p, n, e (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Thành phần của nguyên tử là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Thành phần của nguyên tử là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Thành phần của nguyên tử?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Thành phần của nguyên tử thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Thành phần của nguyên tử?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Thành phần của nguyên tử?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Thành phần của nguyên tử trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Thành phần của nguyên tử?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Thành phần của nguyên tử, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Thành phần của nguyên tử giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Thành phần của nguyên tử là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Thành phần của nguyên tử là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Thành phần của nguyên tử?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Thành phần của nguyên tử thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Thành phần của nguyên tử?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Thành phần của nguyên tử?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Thành phần của nguyên tử trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Thành phần của nguyên tử?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Thành phần của nguyên tử, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Thành phần của nguyên tử giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Thành phần của nguyên tử tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Thành phần của nguyên tử với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Thành phần của nguyên tử thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Thành phần của nguyên tử, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Thành phần của nguyên tử?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Thành phần của nguyên tử vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Thành phần của nguyên tử?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Thành phần của nguyên tử lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Thành phần của nguyên tử?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Thành phần của nguyên tử là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227691/chemistry-odyssey/curriculum/xlvfq6mc1gpvfk6jpl1z.mp4'), ('hoa10_kntt_bai10', 10, 'ketnoi', 'Bài 10: Quy tắc octet', 'Chương 3: Liên kết hóa học', 10, 'Lý do vì sao các nguyên tử liên kết với nhau.', '[{"id":"mod1","type":"heading","content":{"text":"1. Nội dung quy tắc Octet (Quy tắc bát tử)","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Trong quá trình hình thành liên kết hóa học, nguyên tử của các nguyên tố Nhóm A có xu hướng nhường, nhận hoặc góp chung electron lớp ngoài cùng để đạt được cấu hình electron bền vững của khí hiếm gần nhất với **8 electron** (hoặc 2 electron đối với trường hợp của Helium).\\n\\nĐây là động lực chính thúc đẩy các phản ứng hóa học xảy ra, giúp các nguyên tử chuyển từ trạng thái năng lượng cao, kém bền sang trạng thái năng lượng thấp hơn and bền vững hơn trong các phân tử hoặc tinh thể."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Cơ chế đạt cấu hình Octet","content":"Nguyên tử có thể đạt được cấu hình bền vững thông qua 2 con đường chính:\\n1. **Sự nhường hoặc nhận electron**: Hình thành các ion trái dấu (Liên kết ion). Thường xảy ra giữa kim loại điển hình and phi kim điển hình.\\n2. **Sự góp chung electron**: Hình thành các cặp electron chung giữa hai nguyên tử (Liên kết cộng hóa trị). Thường xảy ra giữa các phi kim với nhau."}},{"id":"mod4","type":"heading","content":{"text":"2. Ví dụ về sự áp dụng quy tắc Octet","level":"h2"}},{"id":"mod5","type":"list","content":{"type":"bullet","items":["**Nguyên tử Sodium ($Na$)**: Có cấu hình $[Ne] 3s^1$. Để đạt octet, $Na$ dễ dàng nhường $1e$ ở lớp ngoài cùng để trở thành ion $Na^+$, có cấu hình electron của khí hiếm Neon.","**Nguyên tử Oxygen ($O$)**: Có cấu hình $1s^2 2s^2 2p^4$. Để đạt octet, $O$ cần nhận thêm $2e$ để trở thành ion $O^{2-}$, đạt cấu hình bền vững của Neon."]}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Lưu ý về phạm vi áp dụng","content":"Mặc dù quy tắc Octet giải thích rất tốt cho hầu hết các hợp chất của nguyên tố nhóm A, nhưng nó vẫn có một số ngoại lệ như các hợp chất có số electron lẻ ($NO, NO_2$), hợp chất thiếu octet ($BF_3, BeCl_2$) hoặc các nguyên tố có lớp vỏ ngoài cùng mở rộng ($PCl_5, SF_6$)."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=l7T-GgisrxE","title":"Bài giảng: Quy tắc octet","thumbnail":"https://img.youtube.com/vi/l7T-GgisrxE/0.jpg","description":"Giải thích vì sao các nguyên tử liên kết với nhau để đạt cấu hình 8 electron bền vững (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Quy tắc octet là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Quy tắc octet là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Quy tắc octet?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Quy tắc octet thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Quy tắc octet?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Quy tắc octet?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Quy tắc octet trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Quy tắc octet?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Quy tắc octet, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Quy tắc octet giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Quy tắc octet là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Quy tắc octet là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Quy tắc octet?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Quy tắc octet thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Quy tắc octet?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Quy tắc octet?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Quy tắc octet trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Quy tắc octet?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Quy tắc octet, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Quy tắc octet giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Quy tắc octet tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Quy tắc octet với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Quy tắc octet thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Quy tắc octet, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Quy tắc octet?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Quy tắc octet vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Quy tắc octet?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Quy tắc octet lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Quy tắc octet?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Quy tắc octet là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227695/chemistry-odyssey/curriculum/ytemyjlvnrt7h6yhpdbd.mp4'), ('hoa10_kntt_bai11', 10, 'ketnoi', 'Bài 11: Liên kết ion', 'Chương 3: Liên kết hóa học', 11, 'Sự hình thành ion, lực hút tĩnh điện and đặc điểm của tinh thể ion.', '[{"id":"mod1","type":"heading","content":{"text":"1. Sự tạo thành ion (Cation and Anion)","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Để đạt được cấu hình e bền vững của khí hiếm, các nguyên tử có xu hướng nhường hoặc nhận electron để trở thành các phần tử mang điện gọi là ion:\\n- **Cation (Ion dương)**: Các nguyên tử kim loại có 1, 2 hoặc 3 electron ở lớp ngoài cùng dễ dàng nhường electron để tạo thành cation. Ví dụ: $Na \\\\rightarrow Na^+ + 1e$, $Mg \\\\rightarrow Mg^{2+} + 2e$.\\n- **Anion (Ion âm)**: Các nguyên tử phi kim có 5, 6 hoặc 7 electron lớp ngoài cùng có xu hướng nhận thêm electron để đạt octet. Ví dụ: $Cl + 1e \\\\rightarrow Cl^-$, $O + 2e \\\\rightarrow O^{2-}$."}},{"id":"mod3","type":"heading","content":{"text":"2. Bản chất của liên kết ion","level":"h2"}},{"id":"mod4","type":"paragraph","content":{"text":"**Liên kết ion** là liên kết được hình thành bởi lực hút tĩnh điện giữa các ion mang điện tích trái dấu ($Cation$ and $Anion$). Loại liên kết này thường hình thành giữa các nguyên tố có độ âm điện khác biệt lớn (hiệu độ âm điện $\\\\Delta \\\\chi \\\\ge 1,7$), điển hình là giữa kim loại điển hình (nhóm IA, IIA) and phi kim điển hình (nhóm VIA, VIIA)."}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Tinh thể ion and mạng lưới lập phương","content":"Trong điều kiện thường, các hợp chất ion tồn tại dưới dạng tinh thể. Ví dụ trong tinh thể muối ăn ($NaCl$), các ion $Na^+$ and $Cl^-$ được sắp xếp xen kẽ một cách tuần hoàn theo các nút mạng, tạo thành một khối lập phương bền vững nhờ lực hút tĩnh điện lan tỏa theo mọi hướng."}},{"id":"mod6","type":"heading","content":{"text":"3. Tính chất vật lí của hợp chất ion","level":"h2"}},{"id":"mod7","type":"list","content":{"type":"bullet","items":["**Trạng thái**: Thường là chất rắn, bền vững and khó bay hơi do lực hút tĩnh điện mạnh.","**Nhiệt độ nóng chảy/sôi**: Rất cao. Để phá vỡ mạng tinh thể ion cần cung cấp một lượng nhiệt năng lớn.","**Tính tan**: Tan tốt trong các dung môi phân cực như nước.","**Tính dẫn điện**: Ở trạng thái rắn chúng không dẫn điện, nhưng khi nóng chảy hoặc hòa tan trong nước, các ion tự do di chuyển giúp chúng dẫn điện tốt."]}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=icL76OZLQ-4","title":"Bài giảng: Liên kết ion","thumbnail":"https://img.youtube.com/vi/icL76OZLQ-4/0.jpg","description":"Sự hình thành ion, liên kết ion and tính chất của hợp chất ion (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Liên kết ion là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Liên kết ion là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Liên kết ion?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Liên kết ion thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Liên kết ion?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Liên kết ion?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Liên kết ion trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Liên kết ion?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Liên kết ion, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Liên kết ion giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Liên kết ion là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Liên kết ion là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Liên kết ion?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Liên kết ion thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Liên kết ion?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Liên kết ion?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Liên kết ion trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Liên kết ion?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Liên kết ion, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Liên kết ion giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Liên kết ion tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Liên kết ion với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Liên kết ion thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Liên kết ion, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Liên kết ion?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Liên kết ion vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Liên kết ion?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Liên kết ion lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Liên kết ion?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Liên kết ion là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227699/chemistry-odyssey/curriculum/d0tfa3tnp8w66phpymps.mp4'), ('hoa10_kntt_bai12', 10, 'ketnoi', 'Bài 12: Liên kết cộng hóa trị', 'Chương 3: Liên kết hóa học', 12, 'Sự dùng chung electron, phân cực and không phân cực.', '[{"id":"mod1","type":"heading","content":{"text":"1. Sự hình thành liên kết cộng hóa trị","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Liên kết cộng hóa trị được hình thành giữa các nguyên tử (thường là phi kim) bằng cách **góp chung một hoặc nhiều cặp electron**. Mỗi cặp electron dùng chung được tính cho cả hai nguyên tử, giúp chúng cùng đạt được cấu hình electron bền vững của khí hiếm.\\n\\nDựa trên số cặp electron dùng chung, ta có:\\n- **Liên kết đơn**: Góp chung 1 cặp electron (Kí hiệu bằng 1 gạch nối: $H-H$, $Cl-Cl$).\\n- **Liên kết đôi**: Góp chung 2 cặp electron (Kí hiệu bằng 2 gạch nối: $O=O$).\\n- **Liên kết ba**: Góp chung 3 cặp electron (Kí hiệu bằng 3 gạch nối: $N\\\\equiv N$)."}},{"id":"mod3","type":"heading","content":{"text":"2. Liên kết cộng hóa trị phân cực and không phân cực","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Sự lệch của cặp electron dùng chung","content":"- **Liên kết cộng hóa trị không phân cực**: Cặp electron dùng chung phân bố đối xứng giữa hai nguyên tử. Thường xảy ra giữa hai nguyên tử của cùng một nguyên tố (như $H_2, N_2, Cl_2$).\\n- **Liên kết cộng hóa trị phân cực**: Cặp electron dùng chung bị lệch về phía nguyên tử có độ âm điện lớn hơn. Nguyên tử đó sẽ mang một phần điện tích âm ($\\\\delta^-$), nguyên tử còn lại mang một phần điện tích dương ($\\\\delta^+$). Ví dụ trong phân tử $HCl$, cặp e lệch về phía $Cl$."}},{"id":"mod5","type":"heading","content":{"text":"3. Phân loại liên kết theo hiệu độ âm điện ($\\\\Delta \\\\chi$)","level":"h2"}},{"id":"mod6","type":"paragraph","content":{"text":"Để dự đoán loại liên kết một cách định lượng, ta tính hiệu độ âm điện giữa hai nguyên tử liên kết:\\n- $0 \\\\le \\\\Delta\\\\chi < 0,4$: Liên kết cộng hóa trị **không phân cực**.\\n- $0,4 \\\\le \\\\Delta\\\\chi < 1,7$: Liên kết cộng hóa trị **phân cực**.\\n- $\\\\Delta\\\\chi \\\\ge 1,7$: Liên kết **ion**."}},{"id":"mod7","type":"warningBox","content":{"color":"orange","title":"Liên kết cho - nhận (Liên kết phối trí)","content":"Đây là một trường hợp đặc biệt của liên kết cộng hóa trị, trong đó cặp electron dùng chung chỉ do một nguyên tử đóng góp. Kí hiệu bằng mũi tên ($\\\\rightarrow$) hướng từ nguyên tử cho sang nguyên tử nhận."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=_IIyj5zf37M","title":"Bài giảng: Liên kết cộng hóa trị","thumbnail":"https://img.youtube.com/vi/_IIyj5zf37M/0.jpg","description":"Sự hình thành liên kết cộng hóa trị bằng cách dùng chung electron (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Liên kết cộng hóa trị là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Liên kết cộng hóa trị là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Liên kết cộng hóa trị?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Liên kết cộng hóa trị thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Liên kết cộng hóa trị?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Liên kết cộng hóa trị?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Liên kết cộng hóa trị trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Liên kết cộng hóa trị?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Liên kết cộng hóa trị, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Liên kết cộng hóa trị giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Liên kết cộng hóa trị là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Liên kết cộng hóa trị là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Liên kết cộng hóa trị?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Liên kết cộng hóa trị thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Liên kết cộng hóa trị?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Liên kết cộng hóa trị?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Liên kết cộng hóa trị trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Liên kết cộng hóa trị?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Liên kết cộng hóa trị, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Liên kết cộng hóa trị giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Liên kết cộng hóa trị tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Liên kết cộng hóa trị với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Liên kết cộng hóa trị thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Liên kết cộng hóa trị, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Liên kết cộng hóa trị?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Liên kết cộng hóa trị vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Liên kết cộng hóa trị?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Liên kết cộng hóa trị lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Liên kết cộng hóa trị?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Liên kết cộng hóa trị là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227703/chemistry-odyssey/curriculum/rswsxahfnf8accyd92ll.mp4'), ('hoa10_kntt_bai13', 10, 'ketnoi', 'Bài 13: Liên kết hydrogen and Tương tác van der Waals', 'Chương 3: Liên kết hóa học', 13, 'Tương tác yếu giữa các phân tử giải thích nhiệt độ sôi, độ tan.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm về tương tác giữa các phân tử","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Bên cạnh các liên kết hóa học (ion, cộng hóa trị) giữ các nguyên tử lại với nhau trong một phân tử, còn tồn tại các lực hút yếu hơn giữ các phân tử lại với nhau. Những tương tác này quyết định trạng thái tập hợp (rắn, lỏng, khí) and các tính chất vật lí như nhiệt độ nóng chảy, nhiệt độ sôi and độ tan của chất."}},{"id":"mod3","type":"heading","content":{"text":"2. Liên kết hydrogen","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Bản chất and điều kiện hình thành","content":"Liên kết hydrogen là một loại tương tác tĩnh điện yếu giữa nguyên tử $H$ đã liên kết cộng hóa trị với một nguyên tử có độ âm điện lớn (như $F, O, N$) với một nguyên tử có độ âm điện lớn khác (còn cặp electron hóa trị chưa tham gia liên kết).\\\\n\\\\n- **Kí hiệu**: Biểu diễn bằng các dấu chấm (....) nối giữa các phân tử.\\\\n- **Hệ quả**: Làm tăng đáng kể nhiệt độ sôi and nhiệt độ nóng chảy của chất. Ví dụ: Nước ($H_2O$) có nhiệt độ sôi cao bất thường ($100^\\\\circ C$) so với $H_2S$ ($-60^\\\\circ C$) do có hệ thống liên kết hydrogen liên phân tử bền vững."}},{"id":"mod5","type":"heading","content":{"text":"3. Tương tác van der Waals","level":"h2"}},{"id":"mod6","type":"paragraph","content":{"text":"Tương tác van der Waals là lực hút yếu giữa các phân tử, hình thành do sự xuất hiện của các lưỡng cực tạm thời hoặc vĩnh cửu.\\\\n\\\\n- **Đặc điểm**: Lực này yếu hơn liên kết hydrogen nhưng có mặt ở tất cả các phân tử.\\\\n- **Xu hướng**: Khi khối lượng phân tử and kích thước đám mây electron tăng lên, tương tác van der Waals sẽ mạnh dần. Điều này giải thích tại sao trong nhóm khí hiếm hoặc nhóm halogen, nhiệt độ sôi tăng dần từ trên xuống dưới."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=Zhz4_isWfRQ","title":"Bài giảng: Liên kết hydrogen and tương tác van der Waals","thumbnail":"https://img.youtube.com/vi/Zhz4_isWfRQ/0.jpg","description":"Tìm hiểu về các loại lực liên kết yếu nhưng quan trọng giữa các phân tử (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Liên kết hydrogen and Tương tác van der Waals là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Liên kết hydrogen and Tương tác van der Waals là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Liên kết hydrogen and Tương tác van der Waals?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Liên kết hydrogen and Tương tác van der Waals thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Liên kết hydrogen and Tương tác van der Waals?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Liên kết hydrogen and Tương tác van der Waals?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Liên kết hydrogen and Tương tác van der Waals trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Liên kết hydrogen and Tương tác van der Waals?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Liên kết hydrogen and Tương tác van der Waals, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Liên kết hydrogen and Tương tác van der Waals giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Liên kết hydrogen and Tương tác van der Waals là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Liên kết hydrogen and Tương tác van der Waals là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Liên kết hydrogen and Tương tác van der Waals?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Liên kết hydrogen and Tương tác van der Waals thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Liên kết hydrogen and Tương tác van der Waals?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Liên kết hydrogen and Tương tác van der Waals?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Liên kết hydrogen and Tương tác van der Waals trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Liên kết hydrogen and Tương tác van der Waals?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Liên kết hydrogen and Tương tác van der Waals, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Liên kết hydrogen and Tương tác van der Waals giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Liên kết hydrogen and Tương tác van der Waals tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Liên kết hydrogen and Tương tác van der Waals với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Liên kết hydrogen and Tương tác van der Waals thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Liên kết hydrogen and Tương tác van der Waals, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Liên kết hydrogen and Tương tác van der Waals?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Liên kết hydrogen and Tương tác van der Waals vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Liên kết hydrogen and Tương tác van der Waals?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Liên kết hydrogen and Tương tác van der Waals lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Liên kết hydrogen and Tương tác van der Waals?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Liên kết hydrogen and Tương tác van der Waals là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227708/chemistry-odyssey/curriculum/k5jz84nmfg5j0w3lnzvf.mp4'), ('hoa10_kntt_bai14', 10, 'ketnoi', 'Bài 14: Ôn tập chương 3', 'Chương 3: Liên kết hóa học', 14, 'Tổng kết Liên kết ion, Cộng hóa trị, and quy tắc Octet.', '[{"id":"mod1","type":"heading","content":{"text":"1. Hệ thống hóa các loại liên kết hóa học","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Trong chương này, chúng ta đã tìm hiểu về cách các nguyên tử liên kết với nhau để đạt được cấu hình electron bền vững theo quy tắc Octet:\\n- **Liên kết ion**: Hình thành do lực hút tĩnh điện giữa cation kim loại and anion phi kim. Đặc trưng bởi sự nhường-nhận electron hoàn toàn.\\n- **Liên kết cộng hóa trị**: Hình thành bằng việc góp chung các cặp electron. Bao gồm liên kết không phân cực (e dùng chung ở giữa) and phân cực (e lệch về phía nguyên tử độ âm điện lớn hơn).\\n- **Tương tác yếu**: Liên kết hydrogen and tương tác van der Waals giữ các phân tử lại với nhau, ảnh hưởng trực tiếp đến trạng thái and nhiệt độ sôi của chất."}},{"id":"mod3","type":"heading","content":{"text":"2. Phân biệt and nhận diện nhanh loại liên kết","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Dự đoán dựa trên thành phần nguyên tố","content":"1. **Kim loại điển hình + Phi kim điển hình** $\\\\rightarrow$ Liên kết Ion (Ví dụ: $NaCl, KBr, MgO$).\\n2. **Phi kim + Phi kim giống nhau** $\\\\rightarrow$ Liên kết cộng hóa trị không phân cực (Ví dụ: $O_2, H_2, Cl_2$).\\n3. **Phi kim + Phi kim khác nhau** $\\\\rightarrow$ Liên kết cộng hóa trị phân cực (Ví dụ: $HCl, H_2O, NH_3$)."}},{"id":"mod5","type":"warningBox","content":{"color":"orange","title":"Mối quan hệ Vị trí - Liên kết - Tính chất","content":"Loại liên kết quyết định tính chất vật lí: Hợp chất ion thường là chất rắn, khó nóng chảy. Hợp chất cộng hóa trị có thể là rắn, lỏng hoặc khí, thường có nhiệt độ sôi thấp hơn and tính dẫn điện kém hơn ở trạng thái nguyên chất."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=DD1CDQaEslI","title":"Bài giảng: Ôn tập chương 3","thumbnail":"https://img.youtube.com/vi/DD1CDQaEslI/0.jpg","description":"Hệ thống hóa các loại liên kết hóa học: ion, cộng hóa trị and liên kết yếu (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Ôn tập chương 3 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 3 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 3?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 3 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 3?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 3?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 3 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 3?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 3, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 3 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Ôn tập chương 3 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 3 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 3?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 3 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 3?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 3?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 3 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 3?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 3, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 3 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Ôn tập chương 3 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Ôn tập chương 3 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Ôn tập chương 3 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Ôn tập chương 3, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Ôn tập chương 3?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Ôn tập chương 3 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Ôn tập chương 3?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Ôn tập chương 3 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Ôn tập chương 3?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Ôn tập chương 3 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227713/chemistry-odyssey/curriculum/kyb31w4ymbghjdzeqksg.mp4'), ('hoa10_kntt_bai15', 10, 'ketnoi', 'Bài 15: Phản ứng oxi hóa - khử', 'Chương 4: Phản ứng oxi hóa - khử', 15, 'Cách xác định số oxi hóa and bản chất phản ứng nhường, nhận electron.', '[{"id":"mod1","type":"heading","content":{"text":"1. Số oxi hóa and quy tắc xác định","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Số oxi hóa là một đại lượng giả định, đại diện cho điện tích của nguyên tử trong phân tử nếu giả định rằng các liên kết cộng hóa trị là liên kết ion hoàn toàn. Việc xác định đúng số oxi hóa là bước tiên quyết để nhận diện phản ứng oxi hóa - khử.\\n\\n**Các quy tắc cơ bản:**\\n1. **Đơn chất**: Số oxi hóa bằng 0.\\n2. **Trong hợp chất**: Hydrogen thường là $+1$, Oxygen là $-2$ (trừ các peroxide and hợp chất với fluorine).\\n3. **Ion đơn nguyên tử**: Số oxi hóa bằng điện tích ion.\\n4. **Tổng số oxi hóa**: Trong phân tử trung hòa bằng 0; trong ion đa nguyên tử bằng điện tích của ion đó."}},{"id":"mod3","type":"heading","content":{"text":"2. Bản chất của phản ứng oxi hóa - khử","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Khái niệm ''Khử cho - O nhận''","content":"- **Chất khử**: Là chất nhường electron, số oxi hóa của nó tăng sau phản ứng. Quá trình nhường electron gọi là **quá trình oxi hóa**.\\n- **Chất oxi hóa**: Là chất nhận electron, số oxi hóa của nó giảm sau phản ứng. Quá trình nhận electron gọi là **quá trình khử**.\\n\\nPhản ứng oxi hóa - khử là phản ứng trong đó có sự chuyển dịch electron giữa các chất phản ứng, dẫn đến sự thay đổi số oxi hóa của một số nguyên tố."}},{"id":"mod5","type":"warningBox","content":{"color":"orange","title":"Phương pháp thăng bằng electron","content":"Để cân bằng một phản ứng redox phức tạp, ta thực hiện: \\n1. Xác định số oxi hóa biến thiên.\\n2. Viết các quá trình oxi hóa and quá trình khử.\\n3. Tìm hệ số sao cho **Tổng số electron nhường = Tổng số electron nhận**.\\n4. Đưa hệ số vào phương trình and kiểm tra sự cân bằng nguyên tố (thường là kim loại -> phi kim -> hydrogen -> oxygen)."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=HUUkv87RnSM","title":"Bài giảng: Phản ứng oxi hóa - khử","thumbnail":"https://img.youtube.com/vi/HUUkv87RnSM/0.jpg","description":"Cách xác định số oxi hóa, khái niệm chất khử, chất oxi hóa and cân bằng phản ứng (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Phản ứng oxi hóa - khử là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Phản ứng oxi hóa - khử là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Phản ứng oxi hóa - khử?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Phản ứng oxi hóa - khử thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Phản ứng oxi hóa - khử?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Phản ứng oxi hóa - khử?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Phản ứng oxi hóa - khử trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Phản ứng oxi hóa - khử?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Phản ứng oxi hóa - khử, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Phản ứng oxi hóa - khử giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Phản ứng oxi hóa - khử là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Phản ứng oxi hóa - khử là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Phản ứng oxi hóa - khử?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Phản ứng oxi hóa - khử thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Phản ứng oxi hóa - khử?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Phản ứng oxi hóa - khử?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Phản ứng oxi hóa - khử trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Phản ứng oxi hóa - khử?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Phản ứng oxi hóa - khử, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Phản ứng oxi hóa - khử giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Phản ứng oxi hóa - khử tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Phản ứng oxi hóa - khử với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Phản ứng oxi hóa - khử thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Phản ứng oxi hóa - khử, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Phản ứng oxi hóa - khử?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Phản ứng oxi hóa - khử vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Phản ứng oxi hóa - khử?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Phản ứng oxi hóa - khử lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Phản ứng oxi hóa - khử?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Phản ứng oxi hóa - khử là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227716/chemistry-odyssey/curriculum/yiob7zpkz00iewetle0e.mp4'), ('hoa10_kntt_bai16', 10, 'ketnoi', 'Bài 16: Ôn tập chương 4', 'Chương 4: Phản ứng oxi hóa - khử', 16, 'Luyện tập cân bằng and xác định vai trò các chất trong phản ứng khử.', '[{"id":"mod1","type":"heading","content":{"text":"1. Hệ thống hóa kiến thức về phản ứng oxi hóa - khử","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Phản ứng oxi hóa - khử là lớp phản ứng quan trọng nhất trong hóa học vô cơ, đặc trưng bởi sự thay đổi số oxi hóa của các nguyên tố. Cần nắm vững:\\n- **Dấu hiệu nhận biết**: Có sự thay đổi số oxi hóa của ít nhất một nguyên tố. Hầu hết các phản ứng có đơn chất tham gia hoặc tạo thành đều là phản ứng redox.\\n- **Quy tắc cốt lõi**: Tổng số electron do chất khử nhường phải bằng tổng số electron mà chất oxi hóa nhận."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Kĩ năng cân bằng phương trình phức tạp","content":"Đối với các phản ứng trong môi trường acid ($H^+$) hoặc base ($OH^-$), cần chú ý bảo toàn điện tích and bảo toàn nguyên tố hydrogen, oxygen ở bước cuối cùng. Việc xác định đúng tỉ lệ giữa chất oxi hóa and chất khử là chìa khóa để giải quyết các bài toán định lượng liên quan đến bảo toàn electron."}},{"id":"mod4","type":"heading","content":{"text":"2. Vai trò của phản ứng oxi hóa - khử trong thực tiễn","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Phản ứng oxi hóa - khử tồn tại phổ biến xung quanh chúng ta:\\n- **Trong đời sống**: Sự hô hấp của sinh vật, quá trình quang hợp của cây xanh, sự cháy của nhiên liệu cung cấp năng lượng.\\n- **Trong công nghiệp**: Luyện kim (chiết xuất kim loại từ quặng), sản xuất hóa chất (phân bón, thuốc nổ), and hoạt động của các nguồn điện hóa học (pin, ắc quy).\\n- **Mặt tiêu cực**: Sự ăn mòn kim loại gây hư hại các công trình xây dựng and máy móc."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=Bzy5osIoU3w","title":"Bài giảng: Ôn tập chương 4","thumbnail":"https://img.youtube.com/vi/Bzy5osIoU3w/0.jpg","description":"Tổng hợp kiến thức về phản ứng oxi hóa - khử and các dạng bài tập trọng tâm (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Ôn tập chương 4 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 4 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 4?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 4 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 4?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 4?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 4 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 4?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 4, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 4 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Ôn tập chương 4 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 4 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 4?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 4 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 4?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 4?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 4 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 4?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 4, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 4 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Ôn tập chương 4 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Ôn tập chương 4 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Ôn tập chương 4 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Ôn tập chương 4, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Ôn tập chương 4?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Ôn tập chương 4 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Ôn tập chương 4?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Ôn tập chương 4 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Ôn tập chương 4?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Ôn tập chương 4 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227720/chemistry-odyssey/curriculum/fu54yevbaggadic3zzez.mp4'), ('hoa10_kntt_bai17', 10, 'ketnoi', 'Bài 17: Biến thiên enthalpy trong các phản ứng hóa học', 'Chương 5: Năng lượng hóa học', 17, 'Khái niệm enthalpy, phản ứng tỏa nhiệt and thu nhiệt.', '[{"id":"mod1","type":"heading","content":{"text":"1. Biến thiên Enthalpy của phản ứng ($\\\\Delta_rH$)","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Trong hóa học, Enthalpy ($H$) là đại lượng đặc trưng cho nội năng của hệ cộng với tích của áp suất and thể tích. Tuy nhiên, ta không thể đo giá trị tuyệt đối của enthalpy mà chỉ đo được sự thay đổi của nó trong quá trình phản ứng, gọi là **Biến thiên Enthalpy ($\\\\Delta_rH$)**.\\\\n\\\\nDựa vào dấu của $\\\\Delta_rH$, phản ứng được chia làm hai loại:\\\\n- **Phản ứng tỏa nhiệt ($\\\\Delta_rH < 0$)**: Hệ giải phóng năng lượng dưới dạng nhiệt ra môi trường xung quanh (Ví dụ: phản ứng cháy, phản ứng trung hòa). Tống năng lượng của sản phẩm thấp hơn chất tham gia.\\\\n- **Phản ứng thu nhiệt ($\\\\Delta_rH > 0$)**: Hệ hấp thụ nhiệt từ môi trường để xảy ra phản ứng (Ví dụ: nhiệt phân đá vôi, phản ứng quang hợp). Tổng năng lượng của sản phẩm cao hơn chất tham gia."}},{"id":"mod3","type":"heading","content":{"text":"2. Enthalpy tạo thành chuẩn ($\\\\Delta_fH_{298}^o$)","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Khái niệm and quy ước chuẩn","content":"**Enthalpy tạo thành chuẩn** là biến thiên enthalpy của phản ứng tạo thành 1 mol hợp chất từ các đơn chất bền vững nhất ở điều kiện chuẩn ($25^\\\\circ C$ hay $298 K$, áp suất $1 bar$).\\\\n\\\\n- **Quy ước**: Enthalpy tạo thành chuẩn của các đơn chất bền vững nhất (như $O_2(g), H_2(g), Fe(s)$) bằng 0."}},{"id":"mod5","type":"heading","content":{"text":"3. Tính biến thiên enthalpy chuẩn của phản ứng","level":"h2"}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Công thức tính từ Enthalpy tạo thành","content":"Biến thiên enthalpy chuẩn của phản ứng được tính bằng tổng enthalpy tạo thành chuẩn của các sản phẩm trừ đi tổng enthalpy tạo thành chuẩn của các chất đầu (có nhân với hệ số tỉ lượng):\\\\n$$\\\\Delta_rH_{298}^o = \\\\sum \\\\Delta_fH_{298}^o (SP) - \\\\sum \\\\Delta_fH_{298}^o (CD)$$ "}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=PLltqnGR34E","title":"Bài giảng: Biến thiên enthalpy trong các phản ứng hóa học","thumbnail":"https://img.youtube.com/vi/PLltqnGR34E/0.jpg","description":"Phản ứng thu nhiệt, tỏa nhiệt and cách tính biến thiên enthalpy chuẩn (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Biến thiên enthalpy trong các phản ứng hóa học là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Biến thiên enthalpy trong các phản ứng hóa học là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Biến thiên enthalpy trong các phản ứng hóa học?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Biến thiên enthalpy trong các phản ứng hóa học thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Biến thiên enthalpy trong các phản ứng hóa học?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Biến thiên enthalpy trong các phản ứng hóa học?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Biến thiên enthalpy trong các phản ứng hóa học trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Biến thiên enthalpy trong các phản ứng hóa học?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Biến thiên enthalpy trong các phản ứng hóa học, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Biến thiên enthalpy trong các phản ứng hóa học giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Biến thiên enthalpy trong các phản ứng hóa học là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Biến thiên enthalpy trong các phản ứng hóa học là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Biến thiên enthalpy trong các phản ứng hóa học?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Biến thiên enthalpy trong các phản ứng hóa học thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Biến thiên enthalpy trong các phản ứng hóa học?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Biến thiên enthalpy trong các phản ứng hóa học?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Biến thiên enthalpy trong các phản ứng hóa học trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Biến thiên enthalpy trong các phản ứng hóa học?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Biến thiên enthalpy trong các phản ứng hóa học, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Biến thiên enthalpy trong các phản ứng hóa học giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Biến thiên enthalpy trong các phản ứng hóa học tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Biến thiên enthalpy trong các phản ứng hóa học với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Biến thiên enthalpy trong các phản ứng hóa học thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Biến thiên enthalpy trong các phản ứng hóa học, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Biến thiên enthalpy trong các phản ứng hóa học?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Biến thiên enthalpy trong các phản ứng hóa học vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Biến thiên enthalpy trong các phản ứng hóa học?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Biến thiên enthalpy trong các phản ứng hóa học lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Biến thiên enthalpy trong các phản ứng hóa học?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Biến thiên enthalpy trong các phản ứng hóa học là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227724/chemistry-odyssey/curriculum/ctccm3hocop5xzty6nbq.mp4'), ('hoa10_kntt_bai18', 10, 'ketnoi', 'Bài 18: Ôn tập chương 5', 'Chương 5: Năng lượng hóa học', 18, 'Luyện tập tư duy về dấu ΔH.', '[{"id":"mod1","type":"heading","content":{"text":"1. Hệ thống hóa về biến thiên enthalpy ($\\\\Delta_rH$)","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Trong chương này, chúng ta đã làm quen với khía cạnh năng lượng của các phản ứng hóa học thông qua đại lượng biến thiên enthalpy:\\n- **Phản ứng tỏa nhiệt ($\\\\Delta_rH < 0$)**: Thường là các phản ứng xảy ra thuận lợi ở điều kiện thường (như phản ứng cháy nhiên liệu). Sản phẩm bền vững hơn về mặt năng lượng so với chất đầu.\\n- **Phản ứng thu nhiệt ($\\\\Delta_rH > 0$)**: Cần cung cấp nhiệt liên tục từ bên ngoài để duy trì (như nung vôi, điện phân). Sản phẩm có mức năng lượng cao hơn chất đầu."}},{"id":"mod3","type":"heading","content":{"text":"2. Phương pháp tính biến thiên enthalpy chuẩn","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"So sánh hai phương pháp tính phổ biến","content":"1. **Dựa vào enthalpy tạo thành chuẩn ($\\\\Delta_fH_{298}^o$)**: Lấy tổng nhiệt tạo thành của Sản phẩm trừ đi tổng nhiệt tạo thành của Chất đầu.\\n   $$\\\\Delta_rH_{298}^o = \\\\sum \\\\Delta_fH^o(SP) - \\\\sum \\\\Delta_fH^o(CD)$$\\n2. **Dựa vào năng lượng liên kết ($E_b$)**: Áp dụng cho các phản ứng ở trạng thái khí. Lấy tổng năng lượng bẻ gãy liên kết ở Chất đầu trừ đi tổng năng lượng hình thành liên kết ở Sản phẩm.\\n   $$\\\\Delta_rH_{298}^o = \\\\sum E_b(CD) - \\\\sum E_b(SP)$$ "}},{"id":"mod5","type":"warningBox","content":{"color":"orange","title":"Lưu ý về chiều trừ trong công thức","content":"Rất nhiều học sinh nhầm lẫn giữa hai công thức này. Hãy nhớ: Với **Nhiệt tạo thành** thì dùng **Sau - Đầu** (SP - CD), còn với **Năng lượng liên kết** thì dùng **Đầu - Sau** (CD - SP)."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=g8G07i_XGOk","title":"Bài giảng: Ôn tập chương 5","thumbnail":"https://img.youtube.com/vi/g8G07i_XGOk/0.jpg","description":"Hệ thống hóa kiến thức về năng lượng hóa học and các bài tập enthalpy (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Ôn tập chương 5 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 5 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 5?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 5 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 5?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 5?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 5 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 5?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 5, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 5 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Ôn tập chương 5 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 5 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 5?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 5 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 5?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 5?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 5 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 5?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 5, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 5 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Ôn tập chương 5 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Ôn tập chương 5 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Ôn tập chương 5 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Ôn tập chương 5, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Ôn tập chương 5?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Ôn tập chương 5 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Ôn tập chương 5?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Ôn tập chương 5 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Ôn tập chương 5?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Ôn tập chương 5 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227728/chemistry-odyssey/curriculum/jvcu220ywz0mlawqj5nw.mp4'), ('hoa10_kntt_bai19', 10, 'ketnoi', 'Bài 19: Tốc độ phản ứng', 'Chương 6: Tốc độ phản ứng', 19, 'Tốc độ nhanh chậm and các yếu tố ảnh hưởng.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm về tốc độ phản ứng","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Tốc độ phản ứng hóa học là đại lượng đặc trưng cho sự biến thiên nồng độ của một trong các chất phản ứng hoặc sản phẩm trong một đơn vị thời gian.\\n\\n**Tốc độ trung bình ($\\\\bar{v}$)** của phản ứng được tính bằng công thức: \\n$$\\\\bar{v} = \\\\frac{1}{a} \\\\frac{|\\\\Delta C_A|}{\\\\Delta t}$$ \\n(Trong đó $a$ là hệ số tỉ lượng của chất $A$, $\\\\Delta C_A$ là biến thiên nồng độ, and $\\\\Delta t$ là khoảng thời gian xảy ra biến thiên)."}},{"id":"mod3","type":"heading","content":{"text":"2. Các yếu tố ảnh hưởng đến tốc độ phản ứng","level":"h2"}},{"id":"mod4","type":"list","content":{"type":"bullet","items":["**Nồng độ**: Khi tăng nồng độ chất phản ứng, số va chạm hiệu quả giữa các phân tử tăng lên, dẫn đến tốc độ phản ứng tăng.","**Áp suất**: Đối với phản ứng có chất khí tham gia, việc tăng áp suất (giảm thể tích hệ) làm tăng nồng độ các chất khí, từ đó làm tăng tốc độ phản ứng.","**Nhiệt độ**: Tốc độ phản ứng thường tăng khi nhiệt độ tăng. Quy tắc Van''t Hoff cho biết khi nhiệt độ tăng thêm $10^\\\\circ C$, tốc độ phản ứng tăng từ 2 đến 4 lần ($v_2 = v_1 \\\\cdot \\\\gamma^{\\\\frac{t_2-t_1}{10}}$).","**Diện tích bề mặt**: Đối với các phản ứng có chất rắn tham gia, việc chia nhỏ chất rắn (nghiền bột) làm tăng diện tích tiếp xúc, giúp các phân tử va chạm với nhau dễ dàng hơn, làm tăng tốc độ phản ứng.","**Chất xúc tác**: Là chất làm tăng tốc độ phản ứng nhưng không bị biến đổi về lượng and chất sau phản ứng. Xúc tác hoạt động bằng cách tạo ra một lộ trình phản ứng mới có năng lượng hoạt hóa ($E_a$) thấp hơn."]}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=Ml076ca2VHc","title":"Bài giảng: Tốc độ phản ứng","thumbnail":"https://img.youtube.com/vi/Ml076ca2VHc/0.jpg","description":"Các yếu tố ảnh hưởng đến tốc độ phản ứng: nồng độ, áp suất, nhiệt độ, diện tích bề mặt (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Tốc độ phản ứng là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Tốc độ phản ứng là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Tốc độ phản ứng?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Tốc độ phản ứng thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Tốc độ phản ứng?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Tốc độ phản ứng?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Tốc độ phản ứng trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Tốc độ phản ứng?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Tốc độ phản ứng, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Tốc độ phản ứng giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Tốc độ phản ứng là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Tốc độ phản ứng là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Tốc độ phản ứng?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Tốc độ phản ứng thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Tốc độ phản ứng?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Tốc độ phản ứng?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Tốc độ phản ứng trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Tốc độ phản ứng?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Tốc độ phản ứng, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Tốc độ phản ứng giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Tốc độ phản ứng tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Tốc độ phản ứng với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Tốc độ phản ứng thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Tốc độ phản ứng, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Tốc độ phản ứng?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Tốc độ phản ứng vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Tốc độ phản ứng?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Tốc độ phản ứng lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Tốc độ phản ứng?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Tốc độ phản ứng là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227732/chemistry-odyssey/curriculum/eruoa6zvemxr1uvvwkih.mp4'), ('hoa10_kntt_bai2', 10, 'ketnoi', 'Bài 2: Nguyên tố hóa học', 'Chương 1: Cấu tạo nguyên tử', 2, 'Số hiệu nguyên tử, số khối, kí hiệu nguyên tử and nguyên tử đồng vị.', '[{"id":"mod1","type":"heading","content":{"text":"1. Nguyên tố hóa học and Số hiệu nguyên tử","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Nguyên tố hóa học là tập hợp những nguyên tử có cùng **số đơn vị điện tích hạt nhân** (số proton). Những nguyên tử của cùng một nguyên tố hóa học sẽ có cùng số electron and do đó có tính chất hóa học tương tự nhau.\\n\\n**Số hiệu nguyên tử (Z)**: Là số đơn vị điện tích hạt nhân của một nguyên tố. Số hiệu nguyên tử cho biết số proton trong hạt nhân and số electron ở lớp vỏ nguyên tử ($Z = p = e$). Mỗi nguyên tố hóa học có một số hiệu nguyên tử duy nhất, được coi là \\"số định danh\\" của nguyên tố đó."}},{"id":"mod3","type":"heading","content":{"text":"2. Số khối and Kí hiệu nguyên tử","level":"h2"}},{"id":"mod4","type":"paragraph","content":{"text":"**Số khối (A)** là tổng số hạt proton (Z) and tổng số hạt neutron (N) của hạt nhân đó: \\n$$A = Z + N$$\\n\\n**Kí hiệu nguyên tử**: Để đặc trưng cho một nguyên tử, người ta quy ước ghi số hiệu nguyên tử Z ở phía dưới bên trái and số khối A ở phía trên bên trái của kí hiệu hóa học X:\\n$${}^A_Z X$$\\nVí dụ: ${}^{23}_{11}Na$ cho biết Sodium có $11$ proton, $11$ electron and $23 - 11 = 12$ neutron."}},{"id":"mod5","type":"heading","content":{"text":"3. Đồng vị and Nguyên tử khối trung bình","level":"h2"}},{"id":"mod6","type":"paragraph","content":{"text":"**Đồng vị (Isotopes)**: Là những nguyên tử của cùng một nguyên tố, có cùng số proton ($Z$) nhưng khác nhau về số neutron ($N$), do đó số khối ($A$) của chúng khác nhau.\\n- Ví dụ: Nguyên tố Hydrogen có 3 đồng vị: ${}^1_1H$ (Protium), ${}^2_1H$ (Deuterium), ${}^3_1H$ (Tritium).\\n\\n**Nguyên tử khối trung bình ($overline{A}$)**: Hầu hết các nguyên tố trong tự nhiên là hỗn hợp của nhiều đồng vị với tỉ lệ phần trăm xác định. Nguyên tử khối ghi trong bảng tuần hoàn là nguyên tử khối trung bình, được tính theo công thức:\\n$$\\\\overline{A} = \\\\frac{a \\\\times A_1 + b \\\\times A_2 + ...}{100}$$\\nTrong đó: $A_1, A_2...$ là số khối của các đồng vị; $a, b...$ là tỉ lệ phần trăm số nguyên tử tương ứng."}},{"id":"mod7","type":"warningBox","content":{"color":"orange","title":"Phân biệt Số hiệu and Số khối","content":"Hãy ghi nhớ: Số proton định nghĩa nguyên tố, còn số neutron quyết định đồng vị. Tính chất hóa học của các đồng vị gần như giống hệt nhau, nhưng tính chất vật lý (khối lượng, độ bền hạt nhân) có thể khác nhau."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=MnvBN_7DD6g","title":"Bài giảng: Nguyên tố hóa học","thumbnail":"https://img.youtube.com/vi/MnvBN_7DD6g/0.jpg","description":"Khái niệm nguyên tố, số hiệu nghiên tử, số khối and đồng vị (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Nguyên tố hóa học là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Nguyên tố hóa học là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Nguyên tố hóa học?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Nguyên tố hóa học thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Nguyên tố hóa học?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Nguyên tố hóa học?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Nguyên tố hóa học trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Nguyên tố hóa học?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Nguyên tố hóa học, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Nguyên tố hóa học giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Nguyên tố hóa học là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Nguyên tố hóa học là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Nguyên tố hóa học?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Nguyên tố hóa học thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Nguyên tố hóa học?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Nguyên tố hóa học?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Nguyên tố hóa học trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Nguyên tố hóa học?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Nguyên tố hóa học, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Nguyên tố hóa học giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Nguyên tố hóa học tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Nguyên tố hóa học với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Nguyên tố hóa học thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Nguyên tố hóa học, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Nguyên tố hóa học?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Nguyên tố hóa học vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Nguyên tố hóa học?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Nguyên tố hóa học lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Nguyên tố hóa học?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Nguyên tố hóa học là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227736/chemistry-odyssey/curriculum/ks4wzhm62g621jmmn20r.mp4'), ('hoa10_kntt_bai20', 10, 'ketnoi', 'Bài 20: Ôn tập chương 6', 'Chương 6: Tốc độ phản ứng', 20, 'Luyện tập ứng dụng tăng giảm tốc độ phản ứng trong thực tiễn.', '[{"id":"mod1","type":"heading","content":{"text":"1. Ứng dụng kiểm soát tốc độ phản ứng trong thực tiễn","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["**Tăng tốc độ phản ứng**: Sử dụng quạt thổi không khí vào lò than (tăng nồng độ $O_2$), chẻ nhỏ củi hoặc nghiền mịn quặng (tăng diện tích tiếp xúc), đun nấu thực phẩm ở nhiệt độ cao hoặc dùng nồi áp suất (tăng nhiệt độ and áp suất).","**Giảm tốc độ phản ứng**: Bảo quản thực phẩm trong tủ lạnh hoặc kho lạnh (giảm nhiệt độ làm chậm quá trình ôi thiu), sử dụng chất ức chế để chống ăn mòn kim loại, sơn phủ bề mặt để ngăn tiếp xúc với môi trường.","**Sử dụng xúc tác**: Dùng các loại men trong sản xuất rượu, giấm, sữa chua; sử dụng các bộ chuyển đổi xúc tác trong ống xả ô tô để giảm thiểu khí thải độc hại."]}},{"id":"mod3","type":"heading","content":{"text":"2. Tổng kết phương pháp tính toán","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Mối liên hệ giữa các chất trong phản ứng","content":"Đối với phản ứng tổng quát: $aA + bB \\\\rightarrow cC + dD$, tốc độ phản ứng trung bình có thể tính theo bất kỳ chất nào theo biểu thức:\\\\n$$\\\\bar{v} = -\\\\frac{1}{a} \\\\frac{\\\\Delta [A]}{\\\\Delta t} = -\\\\frac{1}{b} \\\\frac{\\\\Delta [B]}{\\\\Delta t} = \\\\frac{1}{c} \\\\frac{\\\\Delta [C]}{\\\\Delta t} = \\\\frac{1}{d} \\\\frac{\\\\Delta [D]}{\\\\Delta t}$$\\\\nLưu ý dấu âm (-) dành cho chất tham gia (nồng độ giảm) and dấu dương (+) dành cho sản phẩm (nồng độ tăng)."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=LKnym_nPwrg","title":"Bài giảng: Ôn tập chương 6","thumbnail":"https://img.youtube.com/vi/LKnym_nPwrg/0.jpg","description":"Tổng hợp các quy tắc về tốc độ phản ứng and bài tập tính toán liên quan (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Ôn tập chương 6 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 6 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 6?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 6 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 6?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 6?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 6 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 6?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 6, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 6 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Ôn tập chương 6 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 6 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 6?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 6 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 6?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 6?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 6 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 6?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 6, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 6 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Ôn tập chương 6 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Ôn tập chương 6 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Ôn tập chương 6 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Ôn tập chương 6, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Ôn tập chương 6?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Ôn tập chương 6 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Ôn tập chương 6?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Ôn tập chương 6 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Ôn tập chương 6?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Ôn tập chương 6 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227741/chemistry-odyssey/curriculum/cxsdpfa4lwr9mlxpw6qw.mp4'), ('hoa10_kntt_bai21', 10, 'ketnoi', 'Bài 21: Nhóm halogen', 'Chương 7: Nguyên tố nhóm VIIA (Helogen)', 21, 'Vị trí, tính chất vật lí and tính oxi hóa đặc trưng của nhóm.', '[{"id":"mod1","type":"heading","content":{"text":"1. Vị trí and cấu hình electron của nhóm Halogen","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Nhóm Halogen bao gồm các nguyên tố thuộc nhóm VIIA trong bảng tuần hoàn: **Fluorine ($F$), Chlorine ($Cl$), Bromine ($Br$), Iodine ($I$)** and nguyên tố phóng xạ Astatine ($At$).\\\\n- **Cấu hình electron lớp ngoài cùng**: Đều có dạng **$ns^2 np^5$**, với 7 electron lớp ngoài cùng. Điều này khiến chúng cực kỳ kém bền and luôn có xu hướng nhận thêm 1 electron để đạt cấu hình octet bền vững của khí hiếm."}},{"id":"mod3","type":"list","content":{"type":"bullet","items":["**Trạng thái and màu sắc (ở điều kiện chuẩn):**","- Fluorine ($F_2$): Chất khí, màu vàng lục nhạt, cực độc.","- Chlorine ($Cl_2$): Chất khí, màu vàng lục, mùi hắc, độc.","- Bromine ($Br_2$): Chất lỏng, màu đỏ nâu, dễ bay hơi, gây bỏng nặng.","- Iodine ($I_2$): Chất rắn, màu đen tím, có tính thăng hoa (chuyển trực tiếp từ rắn sang khí)."]}},{"id":"mod4","type":"heading","content":{"text":"2. Tính chất hóa học đặc trưng: Tính oxi hóa mạnh","level":"h2"}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Xu hướng biến đổi tính oxi hóa","content":"Tính oxi hóa của các halogen **giảm dần** từ Fluorine đến Iodine do bán kính nguyên tử tăng dần, khả năng hút electron giảm xuống:\\\\n**$F_2 > Cl_2 > Br_2 > I_2$**.\\\\n\\\\nChúng có thể oxi hóa hầu hết các kim loại tạo thành muối halide and oxi hóa nhiều phi kim khác."}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Phản ứng đẩy halogen (Tính oxi hóa mạnh đẩy yếu)","content":"Một halogen có tính oxi hóa mạnh hơn có thể đẩy halogen yếu hơn ra khỏi dung dịch muối halide của nó (trừ Fluorine vì $F_2$ sẽ phản ứng mãnh liệt với nước trước khi kịp đẩy halogen khác).\\\\n- $Cl_2 + 2NaBr \\\\rightarrow 2NaCl + Br_2$\\\\n- $Br_2 + 2NaI \\\\rightarrow 2NaBr + I_2$"}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=VwXu4hm9s1U","title":"Bài giảng: nhóm halogen","thumbnail":"https://img.youtube.com/vi/VwXu4hm9s1U/0.jpg","description":"Đặc điểm cấu tạo, tính chất vật lí and hóa học của các nguyên tố nhóm VIIA (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Nhóm halogen là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Nhóm halogen là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Nhóm halogen?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Nhóm halogen thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Nhóm halogen?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Nhóm halogen?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Nhóm halogen trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Nhóm halogen?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Nhóm halogen, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Nhóm halogen giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Nhóm halogen là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Nhóm halogen là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Nhóm halogen?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Nhóm halogen thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Nhóm halogen?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Nhóm halogen?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Nhóm halogen trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Nhóm halogen?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Nhóm halogen, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Nhóm halogen giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Nhóm halogen tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Nhóm halogen với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Nhóm halogen thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Nhóm halogen, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Nhóm halogen?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Nhóm halogen vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Nhóm halogen?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Nhóm halogen lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Nhóm halogen?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Nhóm halogen là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227749/chemistry-odyssey/curriculum/azlyv0gsidx71xnkrhf4.mp4'), ('hoa10_kntt_bai22', 10, 'ketnoi', 'Bài 22: Hydrogen halide and Muối halide', 'Chương 7: Nguyên tố nhóm VIIA (Helogen)', 22, 'Hợp chất của halogen, dung dịch acid and phản ứng nhận biết.', '[{"id":"mod1","type":"heading","content":{"text":"1. Tính chất của các Hydrogen halide and acid tương ứng","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Hydrogen halide ($HX$) is các hợp chất khí không màu, có mùi xộc and tan rất tốt trong nước tạo thành dung dịch acid hydrohalic.\\\\n- **Độ bền liên kết**: Giảm dần từ $HF$ đến $HI$ do bán kính nguyên tử halogen tăng dần, làm liên kết $H-X$ dài ra and yếu đi.\\\\n- **Tính acid**: Tăng dần theo dãy: **$HF < HCl < HBr < HI$**. Trong đó $HF$ là acid yếu, còn $HCl, HBr, HI$ là các acid mạnh."}},{"id":"mod3","type":"list","content":{"type":"bullet","items":["**Đặc điểm riêng của $HF$**: Dù là acid yếu, nhưng $HF$ có tính chất đặc biệt là ăn mòn thủy tinh ($SiO_2$), do đó nó không được đựng trong bình thủy tinh mà phải đựng trong bình nhựa chuyên dụng.\\\\n  $$SiO_2 + 4HF \\\\rightarrow SiF_4\\\\uparrow + 2H_2O$$","**Tính khử của các ion halide ($X^-$)**: Tính khử tăng dần từ $Cl^-$ đến $I^-$. Ví dụ, $HBr$ and $HI$ có thể khử được $H_2SO_4$ đặc, trong khi $HCl$ thì không."]}},{"id":"mod1","type":"heading","content":{"text":"2. Nhận biết ion halide trong dung dịch","level":"h2"}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Sử dụng thuốc thử Bạc nitrate ($AgNO_3$)","content":"Để phân biệt các muối halide, ta cho tác dụng với dung dịch $AgNO_3$:\\\\n- **Fluoride ($F^-$)**: Không có hiện tượng (AgF tan).\\\\n- **Chloride ($Cl^-$)**: Xuất hiện **kết tủa trắng** ($AgCl$).\\\\n- **Bromide ($Br^-$)**: Xuất hiện **kết tủa vàng nhạt** ($AgBr$).\\\\n- **Iodide ($I^-$)**: Xuất hiện **kết tủa vàng đậm** ($AgI$)."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=RZDVl7THNmY","title":"Bài giảng: Hydrogen halide and một số phản ứng của ion halide","thumbnail":"https://img.youtube.com/vi/RZDVl7THNmY/0.jpg","description":"Tính chất acid của hydrogen halide and các phản ứng đặc trưng nhận biết ion halide (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Hydrogen halide and Muối halide là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Hydrogen halide and Muối halide là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Hydrogen halide and Muối halide?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Hydrogen halide and Muối halide thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Hydrogen halide and Muối halide?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Hydrogen halide and Muối halide?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Hydrogen halide and Muối halide trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Hydrogen halide and Muối halide?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Hydrogen halide and Muối halide, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Hydrogen halide and Muối halide giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Hydrogen halide and Muối halide là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Hydrogen halide and Muối halide là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Hydrogen halide and Muối halide?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Hydrogen halide and Muối halide thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Hydrogen halide and Muối halide?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Hydrogen halide and Muối halide?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Hydrogen halide and Muối halide trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Hydrogen halide and Muối halide?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Hydrogen halide and Muối halide, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Hydrogen halide and Muối halide giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Hydrogen halide and Muối halide tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Hydrogen halide and Muối halide với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Hydrogen halide and Muối halide thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Hydrogen halide and Muối halide, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Hydrogen halide and Muối halide?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Hydrogen halide and Muối halide vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Hydrogen halide and Muối halide?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Hydrogen halide and Muối halide lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Hydrogen halide and Muối halide?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Hydrogen halide and Muối halide là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227753/chemistry-odyssey/curriculum/yd89d5z1so0nyyxdzyyo.mp4'), ('hoa10_kntt_bai23', 10, 'ketnoi', 'Bài 23: Ôn tập chương 7', 'Chương 7: Nguyên tố nhóm VIIA (Helogen)', 23, 'Luyện tập về Halogen and tính chất oxi hóa đặc biệt.', '[{"id":"mod1","type":"heading","content":{"text":"1. Hệ thống hóa tính chất của nhóm Halogen","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Trong chương này, chúng ta đã nghiên cứu về nhóm phi kim hoạt động nhất trong bảng tuần hoàn. Cần lưu ý các quy luật biến đổi ngược chiều nhau giữa đơn chất and hợp chất acid:\\\\n1. **Tính oxi hóa của đơn chất**: Giảm dần từ **$F_2 > Cl_2 > Br_2 > I_2$**. Fluorine is phi kim mạnh nhất, có thể oxi hóa được hầu hết các chất."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Quy luật biến đổi tính acid của HX","content":"Trái ngược với tính oxi hóa của đơn chất, tính acid của các dung dịch hydrogen halide **tăng dần** từ $HF$ đến $HI$:\\\\n**$HF \\\\ll HCl < HBr < HI$**.\\\\nNguyên nhân là do kích thước nguyên tử halogen tăng dần, làm độ bền liên kết $H-X$ giảm, giúp phân tử dễ dàng phân li ra ion $H^+$."}},{"id":"mod4","type":"heading","content":{"text":"2. Các phản ứng nhận biết đặc trưng","level":"h2"}},{"id":"mod5","type":"list","content":{"type":"bullet","items":["**Nhận biết hồ tinh bột**: Iodine ($I_2$) tác dụng với hồ tinh bột tạo thành hợp chất có **màu xanh tím** đặc trưng. Phản ứng này được dùng để nhận biết Iodine hoặc tinh bột trong thực phẩm.","**Nhận biết ion halide ($X^-$)**: Dùng dung dịch $AgNO_3$ để tạo ra các kết tủa có màu sắc khác nhau ($AgCl$ trắng, $AgBr$ vàng nhạt, $AgI$ vàng đậm)."]}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Ứng dụng and an toàn","content":"Các halogen and hợp chất của chúng có ứng dụng rộng rãi trong sát trùng ($Cl_2, Iodine$), sản xuất thuốc trừ sâu, and dược phẩm. Tuy nhiên, chúng đều là những chất độc hại, cần tuyệt đối tuân thủ quy tắc an toàn trong phòng thí nghiệm and công nghiệp."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=Tmhkuq-g750","title":"Bài giảng: Ôn tập chương 7","thumbnail":"https://img.youtube.com/vi/Tmhkuq-g750/0.jpg","description":"Hệ thống hóa toàn bộ kiến thức về nhóm Halogen and hợp chất của chúng (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Ôn tập chương 7 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 7 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 7?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 7 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 7?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 7?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 7 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 7?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 7, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 7 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Ôn tập chương 7 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 7 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 7?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 7 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 7?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 7?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 7 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 7?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 7, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 7 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Ôn tập chương 7 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Ôn tập chương 7 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Ôn tập chương 7 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Ôn tập chương 7, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Ôn tập chương 7?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Ôn tập chương 7 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Ôn tập chương 7?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Ôn tập chương 7 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Ôn tập chương 7?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Ôn tập chương 7 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227758/chemistry-odyssey/curriculum/zwmteltpfmg0x9neewmw.mp4'), ('hoa10_kntt_bai3', 10, 'ketnoi', 'Bài 3: Cấu trúc lớp vỏ electron nguyên tử', 'Chương 1: Cấu tạo nguyên tử', 3, 'Sự phân bố electron theo lớp, phân lớp and nguyên tắc viết cấu hình electron.', '[{"id":"mod1","type":"heading","content":{"text":"1. Lớp and phân lớp electron","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Trong lớp vỏ nguyên tử, các electron được phân bố vào các mức năng lượng khác nhau gọi là các **lớp electron** (kí hiệu n = 1, 2, 3... tương ứng với tên lớp K, L, M, N...). Lớp càng xa hạt nhân thì mức năng lượng càng cao.\\n\\nMỗi lớp electron lại được chia thành các **phân lớp** (kí hiệu là $s, p, d, f$). Số lượng phân lớp trong một lớp đúng bằng số thứ tự của lớp đó (ví dụ lớp n=3 có 3 phân lớp là $3s, 3p, 3d$)."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Sức chứa electron tối đa","content":"- Mỗi phân lớp có số electron tối đa xác định: $s^2, p^6, d^{10}, f^{14}$.\\n- Số electron tối đa trong lớp thứ $n$ là **$2n^2$**. Chẳng hạn lớp M (n=3) có tối đa 18 electron.\\n- Các electron trên cùng một phân lớp có mức năng lượng bằng nhau."}},{"id":"mod4","type":"heading","content":{"text":"2. Cấu hình electron nguyên tử","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"**Cấu hình electron** biểu diễn sự phân bố electron trên các phân lớp thuộc các lớp khác nhau. Việc viết cấu hình tuân theo các quy tắc khắt khe:\\n1. **Nguyên lý vững bền**: Electron chiếm các mức năng lượng từ thấp đến cao (1s < 2s < 2p < 3s < 3p < 4s < 3d < 4p...).\\n2. **Nguyên lý Pauli**: Mỗi orbital chứa tối đa 2 electron ngược chiều nhau.\\n3. **Quy tắc Hund**: Electron phân bố sao cho số electron độc thân là tối đa."}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Lưu ý về trật tự phân mức năng lượng","content":"Phân lớp $4s$ có mức năng lượng thấp hơn $3d$, nên electron sẽ điền đầy $4s^2$ trước khi điền vào $3d$. Tuy nhiên, khi viết cấu hình electron sau cùng, ta phải sắp xếp lại theo từng lớp: $...3s^2 3p^6 3d^{n} 4s^m$."}},{"id":"mod7","type":"heading","content":{"text":"3. Ý nghĩa của Lớp electron ngoài cùng","level":"h2"}},{"id":"mod8","type":"paragraph","content":{"text":"Số electron lớp ngoài cùng (valence electrons) quyết định tính chất hóa học cơ bản của nguyên tố:\\n- **1, 2, 3 electron**: Nguyên tố Kim loại (trừ H, He, B).\\n- **5, 6, 7 electron**: Nguyên tố Phi kim.\\n- **8 electron**: Nguyên tố Khí hiếm (trừ He có 2e), cực kỳ bền vững về mặt hóa học.\\n- **4 electron**: Có thể là kim loại hoặc phi kim. \\n\\nĐây là cơ sở để giải thích sự hình thành liên kết hóa học trong các phản ứng."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=6zZqqyuwrOU","title":"Bài giảng: Cấu trúc lớp vỏ electron nguyên tử","thumbnail":"https://img.youtube.com/vi/6zZqqyuwrOU/0.jpg","description":"Sự phân bố electron vào các lớp, phân lớp and cách viết cấu hình electron (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Cấu trúc lớp vỏ electron nguyên tử là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Cấu trúc lớp vỏ electron nguyên tử là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Cấu trúc lớp vỏ electron nguyên tử?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Cấu trúc lớp vỏ electron nguyên tử thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Cấu trúc lớp vỏ electron nguyên tử?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Cấu trúc lớp vỏ electron nguyên tử?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Cấu trúc lớp vỏ electron nguyên tử trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Cấu trúc lớp vỏ electron nguyên tử?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Cấu trúc lớp vỏ electron nguyên tử, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Cấu trúc lớp vỏ electron nguyên tử giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Cấu trúc lớp vỏ electron nguyên tử là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Cấu trúc lớp vỏ electron nguyên tử là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Cấu trúc lớp vỏ electron nguyên tử?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Cấu trúc lớp vỏ electron nguyên tử thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Cấu trúc lớp vỏ electron nguyên tử?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Cấu trúc lớp vỏ electron nguyên tử?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Cấu trúc lớp vỏ electron nguyên tử trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Cấu trúc lớp vỏ electron nguyên tử?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Cấu trúc lớp vỏ electron nguyên tử, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Cấu trúc lớp vỏ electron nguyên tử giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Cấu trúc lớp vỏ electron nguyên tử tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Cấu trúc lớp vỏ electron nguyên tử với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Cấu trúc lớp vỏ electron nguyên tử thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Cấu trúc lớp vỏ electron nguyên tử, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Cấu trúc lớp vỏ electron nguyên tử?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Cấu trúc lớp vỏ electron nguyên tử vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Cấu trúc lớp vỏ electron nguyên tử?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Cấu trúc lớp vỏ electron nguyên tử lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Cấu trúc lớp vỏ electron nguyên tử?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Cấu trúc lớp vỏ electron nguyên tử là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227763/chemistry-odyssey/curriculum/v0pnu37fdoyvau3owmtw.mp4'), ('hoa10_kntt_bai4', 10, 'ketnoi', 'Bài 4: Ôn tập chương 1', 'Chương 1: Cấu tạo nguyên tử', 4, 'Luyện tập kỹ năng tính toán p, n, e, số khối and viết cấu hình electron.', '[{"id":"mod1","type":"heading","content":{"text":"1. Hệ thống hóa cấu tượng hạt nhân nguyên tử","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Mỗi nguyên tử được đặc trưng bởi hai đại lượng quan trọng:\\n- **Số hiệu nguyên tử (Z)**: Bằng số đơn vị điện tích hạt nhân, xác định vị trí của nguyên tố trong bảng tuần hoàn.\\n- **Số khối (A)**: Tổng số hạt proton and neutron ($A = Z + N$).\\n\\n**Đồng vị**: Là những nguyên tử có cùng số proton nhưng khác nhau về số neutron, dẫn đến sự khác biệt về số khối. Khối lượng nguyên tử trung bình ($overline{A}$) được tính theo trọng số phần trăm của các đồng vị tự nhiên."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Công thức tính toán cơ bản","content":"1. $Z = p = e$.\\n2. $A = Z + N \\\\rightarrow N = A - Z$. \\n3. Tổng số hạt trong nguyên tử: $S = p + n + e = 2Z + N$."}},{"id":"mod4","type":"heading","content":{"text":"2. Cấu trúc lớp vỏ and Cấu hình electron","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Sự phân bố electron tuân theo trật tự mức năng lượng tăng dần: $1s\\\\ 2s\\\\ 2p\\\\ 3s\\\\ 3p\\\\ 4s\\\\ 3d\\\\ 4p...$\\n\\n- **Nguyên tố s, p**: Electron cuối cùng điền vào phân lớp s hoặc p.\\n- **Nguyên tố d, f**: Electron cuối cùng điền vào phân lớp d hoặc f.\\n\\n**Phân loại nguyên tố**: Dựa trên số electron lớp ngoài cùng để xác định là kim loại (1, 2, 3e), phi kim (5, 6, 7e) hay khí hiếm (8e)."}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Các trường hợp cấu hình electron đặc biệt","content":"Cần lưu ý trạng thái **bán bão hòa** and **bão hòa** phân lớp d giúp nguyên tử bền vững hơn:\\n- Chromium ($Z=24$): $[Ar] 3d^5 4s^1$ (thay vì $3d^4 4s^2$).\\n- Copper ($Z=29$): $[Ar] 3d^{10} 4s^1$ (thay vì $3d^9 4s^2$)."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=to9d40c5kbI","title":"Bài giảng: Ôn tập chương 1","thumbnail":"https://img.youtube.com/vi/to9d40c5kbI/0.jpg","description":"Hệ thống hóa kiến thức chương 1 về cấu tạo nguyên tử (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Ôn tập chương 1 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 1 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 1?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 1 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 1?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 1?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 1 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 1?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 1, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 1 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Ôn tập chương 1 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 1 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 1?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 1 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 1?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 1?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 1 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 1?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 1, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 1 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Ôn tập chương 1 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Ôn tập chương 1 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Ôn tập chương 1 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Ôn tập chương 1, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Ôn tập chương 1?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Ôn tập chương 1 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Ôn tập chương 1?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Ôn tập chương 1 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Ôn tập chương 1?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Ôn tập chương 1 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227767/chemistry-odyssey/curriculum/mgxp1f9422xpqfcshndm.mp4'), ('hoa10_kntt_bai5', 10, 'ketnoi', 'Bài 5: Cấu tạo của bảng tuần hoàn', 'Chương 2: Bảng tuần hoàn các nguyên tố hóa học', 5, 'Nguyên tắc sắp xếp, ô nguyên tố, chu kì and nhóm.', '[{"id":"mod1","type":"heading","content":{"text":"1. Nguyên tắc sắp xếp các nguyên tố hóa học","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Bảng tuần hoàn các nguyên tố hóa học hiện đại được xây dựng dựa trên 3 nguyên tắc cốt lõi:\\n1. Các nguyên tố được sắp xếp theo chiều **tăng dần của điện tích hạt nhân** ($Z$).\\n2. Các nguyên tố có cùng **số lớp electron** được xếp vào cùng một hàng (Chu kì).\\n3. Các nguyên tố có cùng **số electron hóa trị** (có cấu hình electron tương tự nhau) được xếp vào cùng một cột (Nhóm)."}},{"id":"mod3","type":"heading","content":{"text":"2. Cấu trúc bảng tuần hoàn: Ô, Chu kì and Nhóm","level":"h2"}},{"id":"mod4","type":"paragraph","content":{"text":"- **Ô nguyên tố**: Cung cấp các thông tin cơ bản về một nguyên tố (Số hiệu nguyên tử $Z$, kí hiệu, tên nguyên tố, độ âm điện, cấu hình electron, nguyên tử khối trung bình).\\n- **Chu kì**: Là dãy các nguyên tố có cùng số lớp electron. Số thứ tự chu kì = Số lớp electron. Bảng tuần hoàn có 7 chu kì (3 chu kì nhỏ and 4 chu kì lớn).\\n- **Nhóm**: Là tập hợp các nguyên tố có cấu hình electron tương tự nhau, do đó có tính chất hóa học tương tự nhau.\\n  + **Nhóm A**: Gồm các nguyên tố s and p. Số thứ tự nhóm A = Số electron lớp ngoài cùng.\\n  + **Nhóm B**: Gồm các nguyên tố d and f (kim loại chuyển tiếp)."}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Xác định vị trí nguyên tố từ cấu hình electron","content":"Để xác định tọa độ của một nguyên tố trong bảng tuần hoàn:\\n1. **Số thứ tự ô** = Tổng số electron ($Z$).\\n2. **Số thứ tự chu kì** = Số lớp electron.\\n3. **Số thứ tự nhóm**: \\n   - Nếu electron cuối cùng điền vào phân lớp s hoặc p $\\\\rightarrow$ Nhóm A.\\n   - Nếu electron cuối cùng điền vào phân lớp d hoặc f $\\\\rightarrow$ Nhóm B."}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Phân chia khối nguyên tố (Blocks)","content":"Dựa trên phân lớp electron đang điền dở dang, các nguyên tố được chia thành 4 khối: Khối s (Nhóm IA, IIA), khối p (IIIA đến VIIIA), khối d (Các nhóm B) and khối f (Lanthanides, Actinides)."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=ZFj67NxAwRM","title":"Bài giảng: Cấu tạo của bảng tuần hoàn","thumbnail":"https://img.youtube.com/vi/ZFj67NxAwRM/0.jpg","description":"Nguyên tắc sắp xếp and cấu trúc các ô, chu kì, nhóm trong bảng tuần hoàn (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Cấu tạo của bảng tuần hoàn là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Cấu tạo của bảng tuần hoàn là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Cấu tạo của bảng tuần hoàn?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Cấu tạo của bảng tuần hoàn thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Cấu tạo của bảng tuần hoàn?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Cấu tạo của bảng tuần hoàn?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Cấu tạo của bảng tuần hoàn trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Cấu tạo của bảng tuần hoàn?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Cấu tạo của bảng tuần hoàn, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Cấu tạo của bảng tuần hoàn giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Cấu tạo của bảng tuần hoàn là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Cấu tạo của bảng tuần hoàn là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Cấu tạo của bảng tuần hoàn?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Cấu tạo của bảng tuần hoàn thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Cấu tạo của bảng tuần hoàn?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Cấu tạo của bảng tuần hoàn?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Cấu tạo của bảng tuần hoàn trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Cấu tạo của bảng tuần hoàn?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Cấu tạo của bảng tuần hoàn, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Cấu tạo của bảng tuần hoàn giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Cấu tạo của bảng tuần hoàn tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Cấu tạo của bảng tuần hoàn với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Cấu tạo của bảng tuần hoàn thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Cấu tạo của bảng tuần hoàn, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Cấu tạo của bảng tuần hoàn?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Cấu tạo của bảng tuần hoàn vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Cấu tạo của bảng tuần hoàn?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Cấu tạo của bảng tuần hoàn lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Cấu tạo của bảng tuần hoàn?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Cấu tạo của bảng tuần hoàn là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227772/chemistry-odyssey/curriculum/e9zp3h6sb4l1vidkpj2y.mp4'), ('hoa10_kntt_bai6', 10, 'ketnoi', 'Bài 6: Xu hướng biến đổi tính chất của nguyên tử', 'Chương 2: Bảng tuần hoàn các nguyên tố hóa học', 6, 'Biết quy luật biến đổi bán kính, năng lượng ion hóa and độ âm điện.', '[{"id":"mod1","type":"heading","content":{"text":"1. Biến đổi bán kính nguyên tử ($r$)","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Bán kính nguyên tử chịu ảnh hưởng của hai yếu tố chính: số lớp electron and lực hút của hạt nhân đối với các electron lớp ngoài cùng.\\n\\n- **Trong một chu kì (trái sang phải)**: Số lớp electron không đổi, nhưng điện tích hạt nhân ($Z$) tăng dần làm tăng lực hút tĩnh điện lên lớp vỏ, khiến bán kính nguyên tử **giảm dần**.\\n- **Trong một nhóm A (trên xuống dưới)**: Số lớp electron tăng lên nhanh chóng, hiệu ứng chắn của các lớp electron bên trong làm giảm lực hút của hạt nhân. Kết quả là bán kính nguyên tử **tăng dần**."}},{"id":"mod3","type":"heading","content":{"text":"2. Độ âm điện ($\\\\chi$)","level":"h2"}},{"id":"mod4","type":"paragraph","content":{"text":"Độ âm điện là đại lượng đặc trưng cho khả năng hút electron của một nguyên tử khi hình thành liên kết hóa học. Đây là chỉ số quan trọng để dự đoán loại liên kết and tính chất của hợp chất.\\n\\n- **Trong một chu kì**: Khi điện tích hạt nhân tăng and bán kính giảm, khả năng hút electron tăng lên, dẫn đến độ âm điện **tăng dần** (nguyên tố Fluorine có độ âm điện lớn nhất).\\n- **Trong một nhóm A**: Bán kính nguyên tử tăng nhanh làm giảm lực hút của hạt nhân đối với electron liên kết, khiến độ âm điện **giảm dần**."}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Năng lượng ion hóa thứ nhất ($I_1$)","content":"Là năng lượng tối thiểu cần thiết để dứt một electron ra khỏi nguyên tử ở trạng thái cơ bản. Quy luật biến đổi của năng lượng ion hóa tương đồng với độ âm điện: **Tăng dần** trong chu kì and **Giảm dần** trong nhóm A. Nguyên tử càng nhỏ, electron lớp ngoài cùng càng bị giữ chặt, năng lượng ion hóa càng cao."}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Mối quan hệ tổng quát","content":"Ghi nhớ: Bán kính nguyên tử biến đổi theo chiều ngược lại với Độ âm điện and Năng lượng ion hóa. Đây là chìa khóa để giải các bài tập về so sánh tính chất giữa các nguyên tố trong bảng tuần hoàn."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=8P9ML8URq6M","title":"Bài giảng: Xu hướng biến đổi tính chất của nguyên tử","thumbnail":"https://img.youtube.com/vi/8P9ML8URq6M/0.jpg","description":"Quy luật biến đổi bán kính nguyên tử, độ âm điện and năng lượng ion hóa (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Xu hướng biến đổi tính chất của nguyên tử là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Xu hướng biến đổi tính chất của nguyên tử là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Xu hướng biến đổi tính chất của nguyên tử?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Xu hướng biến đổi tính chất của nguyên tử thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Xu hướng biến đổi tính chất của nguyên tử?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Xu hướng biến đổi tính chất của nguyên tử?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Xu hướng biến đổi tính chất của nguyên tử trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Xu hướng biến đổi tính chất của nguyên tử?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Xu hướng biến đổi tính chất của nguyên tử, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Xu hướng biến đổi tính chất của nguyên tử giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Xu hướng biến đổi tính chất của nguyên tử là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Xu hướng biến đổi tính chất của nguyên tử là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Xu hướng biến đổi tính chất của nguyên tử?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Xu hướng biến đổi tính chất của nguyên tử thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Xu hướng biến đổi tính chất của nguyên tử?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Xu hướng biến đổi tính chất của nguyên tử?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Xu hướng biến đổi tính chất của nguyên tử trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Xu hướng biến đổi tính chất của nguyên tử?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Xu hướng biến đổi tính chất của nguyên tử, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Xu hướng biến đổi tính chất của nguyên tử giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Xu hướng biến đổi tính chất của nguyên tử tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Xu hướng biến đổi tính chất của nguyên tử với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Xu hướng biến đổi tính chất của nguyên tử thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Xu hướng biến đổi tính chất của nguyên tử, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Xu hướng biến đổi tính chất của nguyên tử?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Xu hướng biến đổi tính chất của nguyên tử vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Xu hướng biến đổi tính chất của nguyên tử?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Xu hướng biến đổi tính chất của nguyên tử lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Xu hướng biến đổi tính chất của nguyên tử?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Xu hướng biến đổi tính chất của nguyên tử là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227776/chemistry-odyssey/curriculum/roazimemv1pbrdxt2vn6.mp4'), ('hoa10_kntt_bai7', 10, 'ketnoi', 'Bài 7: Xu hướng biến đổi tính chất của hợp chất', 'Chương 2: Bảng tuần hoàn các nguyên tố hóa học', 7, 'Sự biến đổi tính acid - base của oxide and hydroxide theo chu kì.', '[{"id":"mod1","type":"heading","content":{"text":"1. Xu hướng biến đổi tính Kim loại and Phi kim","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Tính kim loại (khả năng nhường electron) and tính phi kim (khả năng nhận electron) biến đổi một cách tuần hoàn theo sự thay đổi của cấu hình electron and bán kính nguyên tử:\\n\\n- **Trong một chu kì**: Từ trái sang phải, bán kính nguyên tử giảm and điện tích hạt nhân tăng làm khả năng giữ electron mạnh lên. Do đó, **tính kim loại giảm dần** and **tính phi kim tăng dần**.\\n- **Trong một nhóm A**: Từ trên xuống dưới, bán kính nguyên tử tăng nhanh làm suy yếu lực hút của hạt nhân lên electron hóa trị. Vì vậy, **tính kim loại tăng dần** and **tính phi kim giảm dần**."}},{"id":"mod3","type":"heading","content":{"text":"2. Sự biến đổi tính Acid - Base của Oxide cao nhất","level":"h2"}},{"id":"mod4","type":"paragraph","content":{"text":"Xét các oxide cao nhất của các nguyên tố thuộc Chu kì 3: $Na_2O$, $MgO$, $Al_2O_3$, $SiO_2$, $P_2O_5$, $SO_3$, $Cl_2O_7$. Theo chiều tăng dần của điện tích hạt nhân:\\n- **Tính Base giảm dần**: $Na_2O$ (Base mạnh) $\\\\rightarrow$ $MgO$ (Base trung bình).\\n- **Xuất hiện tính Lưỡng tính**: $Al_2O_3$ (có thể phản ứng với cả acid and base mạnh).\\n- **Tính Acid tăng dần**: $SiO_2$ (Acid rất yếu) $\\\\rightarrow$ $P_2O_5$ (Acid trung bình) $\\\\rightarrow$ $SO_3$ (Acid mạnh) $\\\\rightarrow$ $Cl_2O_7$ (Acid rất mạnh)."}},{"id":"mod5","type":"heading","content":{"text":"3. Sự biến đổi tính Acid - Base của các Hydroxide","level":"h2"}},{"id":"mod6","type":"paragraph","content":{"text":"Sự biến đổi tính acid - base của các hợp chất hydroxide tương ứng với oxide cao nhất cũng tuân theo quy luật tương tự trong một chu kì:\\n\\n- **Tính Base yếu đi**: $NaOH$ (kiềm mạnh) $\\\\rightarrow$ $Mg(OH)_2$ (base yếu) $\\\\rightarrow$ $Al(OH)_3$ (lưỡng tính).\\n- **Tính Acid mạnh lên**: $H_2SiO_3$ (acid rất yếu) $\\\\rightarrow$ $H_3PO_4$ (acid trung bình) $\\\\rightarrow$ $H_2SO_4$ (acid mạnh) $\\\\rightarrow$ $HClO_4$ (acid rất mạnh)."}},{"id":"mod7","type":"warningBox","content":{"color":"orange","title":"Định luật tuần hoàn","content":"Tính chất của các nguyên tố and đơn chất, cũng như thành phần and tính chất của các hợp chất tạo nên từ các nguyên tố đó biến đổi tuần hoàn theo chiều tăng của điện tích hạt nhân nguyên tử."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=1v0kTZLSNog","title":"Bài giảng: Xu hướng biến đổi tính chất của hợp chất","thumbnail":"https://img.youtube.com/vi/1v0kTZLSNog/0.jpg","description":"Sự biến đổi tính acid - base của các oxide and hydroxide (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Xu hướng biến đổi tính chất của hợp chất là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Xu hướng biến đổi tính chất của hợp chất là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Xu hướng biến đổi tính chất của hợp chất?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Xu hướng biến đổi tính chất của hợp chất thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Xu hướng biến đổi tính chất của hợp chất?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Xu hướng biến đổi tính chất của hợp chất?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Xu hướng biến đổi tính chất của hợp chất trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Xu hướng biến đổi tính chất của hợp chất?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Xu hướng biến đổi tính chất của hợp chất, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Xu hướng biến đổi tính chất của hợp chất giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Xu hướng biến đổi tính chất của hợp chất là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Xu hướng biến đổi tính chất của hợp chất là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Xu hướng biến đổi tính chất của hợp chất?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Xu hướng biến đổi tính chất của hợp chất thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Xu hướng biến đổi tính chất của hợp chất?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Xu hướng biến đổi tính chất của hợp chất?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Xu hướng biến đổi tính chất của hợp chất trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Xu hướng biến đổi tính chất của hợp chất?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Xu hướng biến đổi tính chất của hợp chất, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Xu hướng biến đổi tính chất của hợp chất giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Xu hướng biến đổi tính chất của hợp chất tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Xu hướng biến đổi tính chất của hợp chất với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Xu hướng biến đổi tính chất của hợp chất thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Xu hướng biến đổi tính chất của hợp chất, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Xu hướng biến đổi tính chất của hợp chất?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Xu hướng biến đổi tính chất của hợp chất vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Xu hướng biến đổi tính chất của hợp chất?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Xu hướng biến đổi tính chất của hợp chất lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Xu hướng biến đổi tính chất của hợp chất?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Xu hướng biến đổi tính chất của hợp chất là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227781/chemistry-odyssey/curriculum/kbddj8omhgn81vt1vtsw.mp4'), ('hoa10_kntt_bai8', 10, 'ketnoi', 'Bài 8: Định luật tuần hoàn and ý nghĩa', 'Chương 2: Bảng tuần hoàn các nguyên tố hóa học', 8, 'Nội dung định luật and ứng dụng dự đoán cấu tạo, tính chất nguyên tố.', '[{"id":"mod1","type":"heading","content":{"text":"1. Nội dung Định luật tuần hoàn","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Định luật tuần hoàn là nền tảng của hóa học hiện đại, được Dmitri Mendeleev tìm ra and sau này được hoàn thiện dựa trên cấu tạo nguyên tử:\\n\\n**\\"Tính chất của các đơn chất cũng như thành phần and tính chất của các hợp chất tạo nên từ các nguyên tố hóa học biến đổi tuần hoàn theo chiều tăng của điện tích hạt nhân nguyên tử.\\"**\\n\\nSự lặp lại tuần hoàn các tính chất hóa học thực chất là do sự lặp lại tuần hoàn cấu hình electron lớp ngoài cùng của nguyên tử khi điện tích hạt nhân tăng dần."}},{"id":"mod3","type":"heading","content":{"text":"2. Ý nghĩa của Bảng tuần hoàn các nguyên tố","level":"h2"}},{"id":"mod4","type":"paragraph","content":{"text":"Bảng tuần hoàn giúp thiết lập sự liên hệ mật thiết giữa **Vị trí** and **Tính chất** của các nguyên tố:\\n\\n1. **Từ vị trí suy ra cấu tạo and tính chất**: Nếu biết vị trí của nguyên tố (ô, chu kì, nhóm), ta có thể suy ra cấu hình e, tính kim loại/phi kim, hóa trị cao nhất với oxygen and công thức các hợp chất tương ứng.\\n2. **Dự đoán tính chất so sánh**: Dựa trên quy luật biến đổi, ta có thể so sánh bán kính, độ âm điện hoặc tính acid/base của một nguyên tố với các nguyên tố lân cận trong cùng chu kì hoặc cùng nhóm."}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Ví dụ ứng dụng: Nguyên tố Chlorine ($Z=17$)","content":"- **Vị trí**: Ô 17, Chu kì 3, Nhóm VIIA.\\n- **Cấu tạo**: $1s^2 2s^2 2p^6 3s^2 3p^5$ (có 7e lớp ngoài cùng).\\n- **Tính chất**: Là phi kim điển hình, có tính oxi hóa mạnh.\\n- **Hợp chất**: Oxide cao nhất là $Cl_2O_7$ (acidic oxide), hydroxide tương ứng là $HClO_4$ (acid rất mạnh)."}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Tầm quan trọng của Bảng tuần hoàn","content":"Bảng tuần hoàn không chỉ là công cụ để tra cứu mà còn là chìa khóa để hệ thống hóa toàn bộ kiến thức hóa học vô cơ, giúp các nhà khoa học dự đoán sự tồn tại and tính chất của các nguyên tố mới."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=l--e5b_1tYI","title":"Bài giảng: Định luật tuần hoàn and ý nghĩa","thumbnail":"https://img.youtube.com/vi/l--e5b_1tYI/0.jpg","description":"Nội dung định luật tuần hoàn and ứng dụng trong dự đoán tính chất nguyên tố (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Định luật tuần hoàn and ý nghĩa là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Định luật tuần hoàn and ý nghĩa là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Định luật tuần hoàn and ý nghĩa?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Định luật tuần hoàn and ý nghĩa thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Định luật tuần hoàn and ý nghĩa?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Định luật tuần hoàn and ý nghĩa?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Định luật tuần hoàn and ý nghĩa trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Định luật tuần hoàn and ý nghĩa?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Định luật tuần hoàn and ý nghĩa, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Định luật tuần hoàn and ý nghĩa giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Định luật tuần hoàn and ý nghĩa là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Định luật tuần hoàn and ý nghĩa là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Định luật tuần hoàn and ý nghĩa?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Định luật tuần hoàn and ý nghĩa thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Định luật tuần hoàn and ý nghĩa?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Định luật tuần hoàn and ý nghĩa?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Định luật tuần hoàn and ý nghĩa trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Định luật tuần hoàn and ý nghĩa?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Định luật tuần hoàn and ý nghĩa, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Định luật tuần hoàn and ý nghĩa giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Định luật tuần hoàn and ý nghĩa tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Định luật tuần hoàn and ý nghĩa với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Định luật tuần hoàn and ý nghĩa thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Định luật tuần hoàn and ý nghĩa, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Định luật tuần hoàn and ý nghĩa?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Định luật tuần hoàn and ý nghĩa vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Định luật tuần hoàn and ý nghĩa?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Định luật tuần hoàn and ý nghĩa lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Định luật tuần hoàn and ý nghĩa?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Định luật tuần hoàn and ý nghĩa là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227785/chemistry-odyssey/curriculum/qddrexnepujjexrvnqg5.mp4'), ('hoa10_kntt_bai9', 10, 'ketnoi', 'Bài 9: Ôn tập chương 2', 'Chương 2: Bảng tuần hoàn các nguyên tố hóa học', 9, 'Tổng kết mảng kiến thức quy luật tuần hoàn and bảng HTTH.', '[{"id":"mod1","type":"heading","content":{"text":"1. Hệ thống hóa cấu trúc Bảng tuần hoàn","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Bảng tuần hoàn các nguyên tố hóa học là sự sắp xếp khoa học dựa trên cấu hình electron nguyên tử:\\n- **Chu kì**: Gồm các nguyên tố có cùng số lớp electron. Số thứ tự chu kì = Số lớp e.\\n- **Nhóm**: Gồm các nguyên tố có cấu hình electron tương tự nhau, dẫn đến tính chất hóa học tương đồng. Nhóm A (nguyên tố s, p) có số thứ tự nhóm = số electron hóa trị (lớp ngoài cùng)."}},{"id":"mod3","type":"heading","content":{"text":"2. Quy luật biến đổi tuần hoàn","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Tóm tắt xu hướng biến đổi (Trái $\\\\rightarrow$ Phải trong Chu kì)","content":"1. **Tăng dần**: Điện tích hạt nhân, Độ âm điện, Năng lượng ion hóa, Tính phi kim, Tính acid của oxide and hydroxide tương ứng.\\n2. **Giảm dần**: Bán kính nguyên tử, Tính kim loại, Tính base của oxide and hydroxide tương ứng."}},{"id":"mod5","type":"paragraph","content":{"text":"Trong một nhóm A, theo chiều từ trên xuống dưới, các xu hướng trên biến đổi ngược lại do sự tăng lên của số lớp electron làm giảm lực hút của hạt nhân đối với các electron lớp ngoài cùng."}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Mẹo ghi nhớ nhanh","content":"Hãy lấy **Fluorine (F)** làm chuẩn cho tính phi kim mạnh nhất (góc trên bên phải) and **Francium (Fr)** làm chuẩn cho tính kim loại mạnh nhất (góc dưới bên trái). Các nguyên tố càng nằm gần F thì tính phi kim càng mạnh, càng gần Fr thì tính kim loại càng mạnh."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=CC8ROS3QNAI","title":"Bài giảng: Ôn tập chương 2","thumbnail":"https://img.youtube.com/vi/CC8ROS3QNAI/0.jpg","description":"Tổng kết and giải đáp các thắc mắc về bảng tuần hoàn and quy luật tuần hoàn (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Ôn tập chương 2 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 2 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 2?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 2 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 2?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 2?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 2 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 2?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 2, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 2 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Ôn tập chương 2 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ôn tập chương 2 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ôn tập chương 2?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ôn tập chương 2 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ôn tập chương 2?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ôn tập chương 2?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ôn tập chương 2 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ôn tập chương 2?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ôn tập chương 2, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ôn tập chương 2 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Ôn tập chương 2 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Ôn tập chương 2 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Ôn tập chương 2 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Ôn tập chương 2, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Ôn tập chương 2?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Ôn tập chương 2 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Ôn tập chương 2?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Ôn tập chương 2 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Ôn tập chương 2?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Ôn tập chương 2 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227789/chemistry-odyssey/curriculum/urtirmkvcwdmrqef4hnd.mp4'), ('hoa11_kntt_bai1', 11, 'ketnoi', 'Bài 1. Khái niệm về cân bằng hóa học', 'Chương 1. Cân bằng hóa học', 1, 'Phân biệt phản ứng một chiều and phản ứng thuận nghịch. Tìm hiểu về sự chuyển dịch cân bằng and hằng số cân bằng.', '[{"id":"mod1","type":"heading","content":{"text":"1. Phản ứng một chiều and phản ứng thuận nghịch","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Phản ứng hóa học được phân loại dựa trên chiều hướng tiến trình. **Phản ứng một chiều (Irreversible Reaction):** Là phản ứng chỉ diễn ra theo một chiều duy nhất từ chất tham gia (Reactants) tạo ra sản phẩm (Products), miễn là vẫn duy trì cùng một điều kiện nhiệt độ - áp suất. Đặc trưng của phản ứng này là sản phẩm sinh ra rất trơ hoặc thoát hẳn khỏi hệ (bay hơi, kết tủa) nên không thể tương tác ngược lại để tái tạo chất đầu. Phương trình dùng một mũi tên duy nhất (\\\\(\\\\rightarrow\\\\)). Ví dụ: Đốt cháy than $C + O_2 \\\\rightarrow CO_2$."}},{"id":"mod3","type":"paragraph","content":{"text":"**Phản ứng thuận nghịch (Reversible Reaction):** Xảy ra khi trong cùng một bình phản ứng (cùng điều kiện t°, p), các chất sản phẩm vừa mới tạo thành lại lập tức tương tác với nhau để phân hủy hoặc tái tổng hợp ngược lại thành các chất tham gia ban đầu. Quá trình này diễn ra đồng thời theo 2 chiều ngược nhau (chiều Thuận and chiều Nghịch). Phương trình dùng mũi tên 2 chiều (\\\\(\\\\rightleftharpoons\\\\)). Phản ứng này không bao giờ đạt hiệu suất 100%, luôn còn dư chất tham gia."}},{"id":"mod4","type":"heading","content":{"text":"2. Cân bằng hóa học","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"**Trạng thái cân bằng hóa học:** Khởi đầu phản ứng, tốc độ chiều thuận ($v_{thuận}$) cực lớn do nồng độ chất phản ứng dồi dào, trong khi tốc độ chiều nghịch ($v_{nghịch}$) bằng không. Theo thời gian, $v_{thuận}$ giảm dần and $v_{nghịch}$ tăng lên. Cho tới một thời điểm t, hai tốc độ này bằng nhau ($v_t = v_n$). Lúc này, hệ thống đạt \\"Trạng thái cân bằng hóa học\\". Đặc điểm là: Nồng độ, áp suất, màu sắc của mọi chất trong hệ lúc này trở nên BẤT BIẾN theo thời gian."}},{"id":"mod6","type":"infoBox","content":{"color":"blue","title":"Bản chất Động của Cân Bằng","content":"Cân bằng hóa học là một **Trạng thái Động**, không phải tĩnh. Nghĩa là tại thời điểm nồng độ không đổi, thực chất hàng tỷ phân tử chất phản ứng vẫn đang tiếp tục va chạm sinh ra sản phẩm, and lượng sản phẩm tương đương cũng đang phân hủy ngược lại bù trừ chính xác lượng mất đi. Hệ phải là **Hệ kín** (không rò rỉ khí hoặc khối lượng ra ngoài)."}},{"id":"mod7","type":"heading","content":{"text":"3. Hằng số cân bằng (Kc)","level":"h2"}},{"id":"mod8","type":"paragraph","content":{"text":"Nhà bác học Guldberg and Waage đã khái quát hóa Định luật Tác dụng khối lượng. Ở trạng thái cân bằng của phản ứng thuận nghịch: $aA + bB \\\\rightleftharpoons cC + dD$. Thương số nồng độ đo ở thời điểm cân bằng của sản phẩm chia cho chất tham gia luôn đạt một giá trị hằng số không đổi, gọi là **Hằng số cân bằng $K_c$**."}},{"id":"mod9","type":"infoBox","content":{"color":"green","title":"Thuộc tính cốt lõi của hằng số Kc","content":"Công thức: $K_c = \\\\frac{[C]^c \\\\cdot [D]^d}{[A]^a \\\\cdot [B]^b}$.\\nLưu ý tử huyệt: Giá trị $K_c$ CHỈ PHỤ THUỘC duy nhất vào **Nhiệt độ**. Nếu không đổi nhiệt độ, dù bạn nén bình hay châm thêm chất thì $K_c$ dứt khoát không suy suyển. Khi viết biểu thức tính $K_c$, tuyệt đối BỎ QUA các chất ở trạng thái Rắn (Solid) do nồng độ của chúng mặc định bằng 1 hằng số."}},{"id":"mod10","type":"heading","content":{"text":"4. Sự chuyển dịch cân bằng & Nguyên lí Le Chatelier","level":"h2"}},{"id":"mod11","type":"paragraph","content":{"text":"Mọi hệ tĩnh lặng đều chống lại sự xáo trộn. Nhà hóa học Pháp Le Chatelier đã phát biểu một nguyên lý chủ đạo chi phối Vũ trụ: **Nguyên lí chuyển dịch cân bằng Le Chatelier**: Khi một hệ cân bằng hóa học đang yên ổn bị tác động bởi sự biến đổi của Nồng độ, Áp suất, hoặc Nhiệt độ từ bên ngoài, hệ thống sẽ LẬP TỨC tự động phản kháng bằng cách chuyển dịch tốc độ phản ứng nghiêng sang cái chiều làm **GIẢM BỚT** hoặc **TRIỆT TIÊU** tác động đó."}},{"id":"mod12","type":"list","content":{"type":"bullet","items":["**1. Yếu tố Nồng độ:** Thêm chất A vào hệ $\\\\rightarrow$ Hệ vội vàng làm giảm chất A (phản ứng tự động trôi theo chiều tiêu thụ A). Hút bớt chất B $\\\\rightarrow$ Hệ dịch theo chiều sinh ra bù đắp chất B.","**2. Yếu tố Áp suất:** Chỉ đụng chạm tới hệ phản ứng chứa chất KHÍ. Tăng áp suất bình (nén nhỏ thể tích) $\\\\rightarrow$ Hệ phản kháng bằng cách chuyển dịch chạy về phía bên nào có TỔNG SỐ MOL KHÍ NHỎ HƠN (để làm tụt áp suất xuống).","**3. Yếu tố Nhiệt độ:** Tăng nhiệt độ nung bình $\\\\rightarrow$ Hệ hoảng loạn cần làm mát, nên nó dịch chuyển theo chiều phản ứng THU NHIỆT (ΔH > 0: hút bớt nhiệt nóng). Ngược lại, ném bình vào xô đá (giảm nhiệt) $\\\\rightarrow$ Hệ dịch theo chiều TỎA NHIỆT (ΔH < 0)."]}},{"id":"mod13","type":"warningBox","content":{"color":"orange","title":"Cái bẫy Xúc tác and Phản ứng Cân Bằng Mol Khí","content":"Một khi phản ứng có tổng số mol khí 2 vế bằng nhau (Ví dụ $H_2 + I_2 \\\\rightleftharpoons 2HI$), việc nén hay xả áp suất vô tác dụng, cân bằng đứng im.\\n**Chất xúc tác:** Hoàn toàn KHÔNG làm chuyển dịch cân bằng. Nó chỉ bơm tốc độ cả chiều thuận and nghịch lên cùng 1 bội số, giúp hệ Đạt Tới Cân Bằng Nhanh Hơn mà thôi."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=2wD8sFFjddw","title":"Bài giảng: Khái niệm về cân bằng hóa học","thumbnail":"https://img.youtube.com/vi/2wD8sFFjddw/0.jpg","description":"Khái niệm về phản ứng thuận nghịch and trạng thái cân bằng hóa học (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 1. Khái niệm về cân bằng hóa học là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 1. Khái niệm về cân bằng hóa học là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 1. Khái niệm về cân bằng hóa học?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 1. Khái niệm về cân bằng hóa học thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 1. Khái niệm về cân bằng hóa học?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 1. Khái niệm về cân bằng hóa học?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 1. Khái niệm về cân bằng hóa học trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 1. Khái niệm về cân bằng hóa học?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 1. Khái niệm về cân bằng hóa học, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 1. Khái niệm về cân bằng hóa học giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 1. Khái niệm về cân bằng hóa học là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 1. Khái niệm về cân bằng hóa học là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 1. Khái niệm về cân bằng hóa học?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 1. Khái niệm về cân bằng hóa học thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 1. Khái niệm về cân bằng hóa học?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 1. Khái niệm về cân bằng hóa học?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 1. Khái niệm về cân bằng hóa học trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 1. Khái niệm về cân bằng hóa học?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 1. Khái niệm về cân bằng hóa học, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 1. Khái niệm về cân bằng hóa học giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 1. Khái niệm về cân bằng hóa học tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 1. Khái niệm về cân bằng hóa học với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 1. Khái niệm về cân bằng hóa học thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 1. Khái niệm về cân bằng hóa học, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 1. Khái niệm về cân bằng hóa học?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 1. Khái niệm về cân bằng hóa học vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 1. Khái niệm về cân bằng hóa học?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 1. Khái niệm về cân bằng hóa học lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 1. Khái niệm về cân bằng hóa học?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 1. Khái niệm về cân bằng hóa học là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai10', 11, 'ketnoi', 'Bài 10. Hợp chất hữu cơ and hóa học hữu cơ', 'Chương 3. Đại cương về hóa học hữu cơ', 10, 'Khái niệm Hóa học hữu cơ, đặc điểm chung của hợp chất hữu cơ and cách phân loại.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm Hóa học hữu cơ","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Bước qua ranh giới Vô Cơ, Hóa học mở toang cánh cửa Vĩ Đại nhất Vũ trụ sinh học mang tên Hóa Học Hữu Cơ. Đây là Lãnh địa độc tôn nghiên cứu CÁC HỢP CHẤT CỦA NGUYÊN TỐ CARBON (Bộ Khung Sự Sống Của Hành Tinh). Từ Dầu Mỏ Nhớt Thô, Sợi Bông Quần Áo, Vỏ Gai Xưng Mộc, Dược Phẩm Thuốc Chống Đau, cho đến Cơ Nhục Máu màng gen Di Truyền, tất cả đều là các dải Khung Hữu Cơ Chứa Carbon.\\nTuy vậy, xin loại bỏ nhầm lẫn vài mảnh vỡ của Carbon Vô Cơ (Khí CO, CO2, Muối sủi bọt Đá Voi CaCo3, tinh quặng Xyanua NaCN...)."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Mạng Lưới Vạn Hóa của Khung Carbon","content":"Thành Phần Khai Mở Bảng Thần Chú: \\nÔng Hoàng Bá Chủ Tuyệt đối **C (Carbon)** là bắt buộc hiện diện khung xương. Phó Tướng Hợp tác Mọi ngõ ngách **H (Hydrogen)** kìm kẹp vỏ bọc. Nhóm Tham Tán Điểm Chức Biến Dịch gồm **O, N, Halogen (Cl, Br), S, P** gắn vào thân gốc tạo nên đủ Hệ Loại Rượu, Acid, Amino bốc vị."}},{"id":"mod4","type":"heading","content":{"text":"2. Đặc điểm chung của Hợp chất hữu cơ","level":"h2"}},{"id":"mod5","type":"list","content":{"type":"bullet","items":["Đặc Tính Đồng Bộ - Thể Dáng Nhận Diện Hữu Cơ:","1. Liên Kết Lũng Bắt Cặp Cộng Hóa Trị: Không chơi trò chia rẽ Nhường Tách Ion hăm hở vô cơ. Carbon chèn dính với nhau rịt kẹp Đôi Electron Chung thành Dây Sợi Chằng Trị siêu bền Khung Cacbon.","2. Vật Lí Bay Hơi Mong Lanh: Đa số tản mác mây khói, Nóng Chảy Sôi cực Thấp bé (Cồn Alcohol bóp là bốc sát khuẩn tay, Xăng xe vút hơi trạm mĩ).","3. Khắc Tinh Với Nước - Đam Mê Dung Môi: Mỡ Ẩm Heo, Dầu Thô Nhớt KHÔNG tan rỉ chìm trong Nước mà nổi bềnh trương phềnh. Chúng chỉ tan trong Cồn Xăng Benzene, Dung Môi Tẩy.","4. Đặc Điểm Bùng Lửa Đen: Rất nhạy bắt mồi Cháy Sinh Nhiệt (Khí Đốt Thành Phố). Thường nướng cháy đen xém đứt than.","5. Tốc Đo Phản Ứng Trì Trệ Ục Ịch: Không Bòm nổ tan như pháo. Phản ứng Hóa Hữu Cơ rề rà, chậm lụt, dắt kẹp xúc tác nhiệt độ đun tăm and thường vỡ vụn lóc cóc ra Nhiều Sản Phẩm Phụ Mảng dính rể."]}},{"id":"mod6","type":"heading","content":{"text":"3. Phân loại","level":"h2"}},{"id":"mod7","type":"paragraph","content":{"text":"Để phân loài hàng Trăm Căn triệu Dãy Hữu Cơ dạo bước, Ngành Học chia nhánh Thành 2 Nhánh Cây Rèn Chính:\\n**1. Tổ Kiếm Hydrocarbon (Kẻ Trọc Thân):** Đảo Dầu Mỏ nguyên dải. Trong ruột Toàn Vẹn CHỈ CÓ c and H (Đơn Giản Tinh Tuyến). (Ví dụ Khí Gas Nấu Ăn CH4, Ống Nhựa Ethylene C2H4, Vòng Benzene Hóa dầu Lắng).\\n**2. Thế Giới Dẫn Xuất Hydrocarbon (Kẻ Nhồi Bom Chức Năng):** Gắn thọc thêm ngòi O, N, CL, vào thân tảng. Gây ra Khí Chức. (Ví Dụ Cồn Nhậu C2H5-OH chứa gốc OH Rượu. Hoặc Dấm Chua Ăn Cơm CH3-COOH chứa gốc chua rỗng Axit)."}},{"id":"mod8","type":"warningBox","content":{"color":"orange","title":"Khí Thở Vượt Não Ranh Giới Chức Năng Nhóm Chức","content":"Khái niệm Cực Đại Học: Nhóm Chức Học Hữu Cơ. Toàn bộ Cái Khung Carbon Hydro dù bự hàng ngàn hạt C cũng chỉ là cái Cán Chổi mộc vô dụng. Cái Cục Nối Điểm Đuôi (Nhóm Chức) mới quyết định Năng Lực Pháp Thuật Của Hữu Cơ. Chứa gốc (-OH) là bốc hơi Mùi men cồn Nhậu Say. Chứa Gốc (-COOH) là cắn răng nhăn trán Vị Giấm Chua Axit cặn sỏi ngứa. Học Hữu cơ Chính là môn Ráp Chức Đổi Thuộc Tính Khớp Module."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=woTztyoYXiU","title":"Bài giảng: Hợp chất hữu cơ and hóa học hữu cơ","thumbnail":"https://img.youtube.com/vi/woTztyoYXiU/0.jpg","description":"Giới thiệu về thế giới hợp chất hữu cơ and các nhóm chức phổ biến (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 10. Hợp chất hữu cơ and hóa học hữu cơ là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 10. Hợp chất hữu cơ and hóa học hữu cơ là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 10. Hợp chất hữu cơ and hóa học hữu cơ?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 10. Hợp chất hữu cơ and hóa học hữu cơ?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 10. Hợp chất hữu cơ and hóa học hữu cơ?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 10. Hợp chất hữu cơ and hóa học hữu cơ là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 10. Hợp chất hữu cơ and hóa học hữu cơ là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 10. Hợp chất hữu cơ and hóa học hữu cơ?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 10. Hợp chất hữu cơ and hóa học hữu cơ?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 10. Hợp chất hữu cơ and hóa học hữu cơ?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 10. Hợp chất hữu cơ and hóa học hữu cơ tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 10. Hợp chất hữu cơ and hóa học hữu cơ với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 10. Hợp chất hữu cơ and hóa học hữu cơ thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 10. Hợp chất hữu cơ and hóa học hữu cơ, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 10. Hợp chất hữu cơ and hóa học hữu cơ vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 10. Hợp chất hữu cơ and hóa học hữu cơ lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 10. Hợp chất hữu cơ and hóa học hữu cơ là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai11', 11, 'ketnoi', 'Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ', 'Chương 3. Đại cương về hóa học hữu cơ', 11, 'Nguyên tắc các phương pháp tách and tinh chế thông dụng: chiết, chưng cất, kết tinh and sắc kí.', '[{"id":"mod1","type":"heading","content":{"text":"1. Phương pháp Chiết","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Trong thiên nhiên, các hợp chất hữu cơ hiếm khi đứng đơn lẻ mà luôn pha trộn thành những mớ bòng bong hỗn hợp (tinh dầu gộp trong lá, diệp lục trộn bùn tế bào). Để lấy ra được chất Tinh Khiết, Hóa học hữu cơ sử dụng 4 tuyệt kĩ cơ bản dựa vào sự chênh lệch **TÍNH CHẤT VẬT LÍ** (Độ hòa tan, Nhiệt độ sôi, Độ hấp phụ). Phương pháp số 1: **Chiết (Extraction)**."}},{"id":"mod3","type":"list","content":{"type":"bullet","items":["Chiết là nghệ thuật đi mượn một \\"Dung Môi Thần Tài\\" để kéo rứt chất cần tìm ra khỏi hỗn hợp. Dựa vào nguyên lí: Chất tan khác nhau trong 2 dung môi Không Thể Trộn Lẫn.","**1. Chiết lỏng - lỏng (Dùng Phễu Chiết):** Tách chất hữu cơ từ dung dịch nước. Ví dụ cho tinh dầu lẫn nước vào Phễu thủy tinh có vòi. Đổ Ether (dung môi Hữu cơ hôi hắc) vào $\\\\rightarrow$ Lắc mạnh. Tinh dầu cực thèm Ether nên bỏ Nước bơi hết sạch lên lớp Eter nhẹ nổi bề mặt. Nước nặng chìm dưới rỗng tuếch. Mở khóa vòi xả bỏ Nước, ta thu được lớp Ether chứa tinh dầu.","**2. Chiết lỏng - rắn (Ngâm Rượu/Hầm):** Khai thác dược liệu. Ngâm rễ sâm cứng vào cồn Rượu (Dung môi lỏng). Cốt nhân sâm nhả tan vào rượu thành Rượu Thuốc."]}},{"id":"mod4","type":"heading","content":{"text":"2. Phương pháp Chưng cất","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Phương pháp 2: **Chưng cất (Distillation)**. Là màn tra tấn bằng Lửa để phân tách các Cặp Chất Lỏng Tan Lẫn Toàn Phần. Dựa trên ranh giới: **Nhiệt Độ Sôi Khác Biệt**. Chất nào có Nhiệt độ sôi Ảo Thấp hơn $\\\\rightarrow$ Nhẹ dạ bốc hơi bay lên trước. Băng qua ống sinh hàn (ống ruột gà ngâm lạnh) $\\\\rightarrow$ Khí ngưng tụ rót thành giọt lỏng rơi xuống bình hứng."}},{"id":"mod6","type":"infoBox","content":{"color":"blue","title":"Chưng cất Nấu Rượu Truyền Thống","content":"Ví dụ kinh điển đun hèm rượu (Hỗn hợp Cồn Ethyl Alcohol sôi 78°C trộn with Nước sôi 100°C). Khi đun nóng Tới 78 độ, nồi nấu chưa để nước kịp sôi thì toàn bộ bộ Cồn Hữu Cơ đã bốc hơi bay ào ạt trào lên mặt $\\\\rightarrow$ Dẫn ống qua thau nước lạnh ngưng tụ lại thành Tinh Chất Rượu Trong vắt."}},{"id":"mod7","type":"heading","content":{"text":"3. Phương pháp Kết tinh","level":"h2"}},{"id":"mod8","type":"paragraph","content":{"text":"Phương pháp 3: **Kết tinh (Crystallization)**. Áp dụng cho Chất Rắn. Dựa trên chân lí: Độ tan của Chất Rắn biến thiên cực độ theo Nhiệt độ (Nóng thì tan tốt, Lạnh thì đẩy văng ra). \\nThực hành: Đun nóng hòa tan chất rắn lẫn tạp bẩn vào dung dịch sôi tơi tả $\\\\rightarrow$ Lọc cặn rác nóng $\\\\rightarrow$ Rót Nước ra để Nguội Chậm (Hoặc ủ ngâm đá). Do lạnh đột ngột, Chất Tinh Khiết sẽ tuôn trào tủa mọc thành những Tinh Thể Kim Cương Móng Cọp bắt mắt lóng lánh (Lọc ra tinh chế mía xốp thành Đường Phèn Trắng)."}},{"id":"mod9","type":"heading","content":{"text":"4. Phương pháp Sắc kí (Sắc kí cột, lớp mỏng)","level":"h2"}},{"id":"mod10","type":"paragraph","content":{"text":"Phương pháp 4 Đỉnh Cao: **Sắc kí (Chromatography)**. Vượt mọi ranh giới phân tách cả Lượng Mẫu Hiển Vi giọt xíu xiu. Trò chơi vượt chướng ngại vật giữa Pha Động (Dung môi lỏng/khí lùa chạy) mang theo Cà Mẫu rượt đuổi trượt trên Pha Tĩnh (Cột cát Gel tĩnh lặng). Chất nào bị Pha Tĩnh Giữ Lại Bám Ưa Hơn $\\\\rightarrow$ Bị kẹt chạy luẩn quẩn Rất Chậm Cụt Lùi sau and bị Tách rớt hẳn Lớp with thằng chạy nhanh. Dùng Sắc kí lớp Mỏng Tách màu Vi khuẩn, Giọt Lệ Máu."}},{"id":"mod11","type":"warningBox","content":{"color":"orange","title":"Báo Động Sinh Tử Lửa Trần Hữu Cơ","content":"Vì hóa chất hữu cơ (Ether, Xăng, Cồn, Chloroform) vô cùng tàn nhẫn khát lửa, Bốc Hơi Lẹ and Cháy Điên Cuồng thảm sát nổ. Toàn bộ các quá trình Chưng Cất đun nấu ở phòng Lab NGHIÊM CẤM 100% bật quẹt Mồi Lửa Đèn cồn rọi trực tiếp dưới đáy bình cầu (Nguy cơ bể bình Phụt Cháy Nhà). BẮT BUỘC dùng \\"Bếp Điện Cách Thủy\\" hay \\"Bếp Trát Hạt Cát\\" tản nhiệt êm ái."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=GbGGVDoUOF8","title":"Bài giảng: Phương pháp tách biệt and tinh chế hợp chất hữu cơ","thumbnail":"https://img.youtube.com/vi/GbGGVDoUOF8/0.jpg","description":"Các phương pháp chưng cất, chiết, kết tinh and sắc ký cột trong thực hành hóa hữu cơ (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 11. Phương pháp tách biệt and tinh chế hợp chất hữu cơ là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai12', 11, 'ketnoi', 'Bài 12. Công thức phân tử hợp chất hữu cơ', 'Chương 3. Đại cương về hóa học hữu cơ', 12, 'Các loại công thức biểu diễn hợp chất hữu cơ. Cách xác định công thức phân tử từ phần trăm khối lượng hoặc dữ kiện đốt cháy.', '[{"id":"mod1","type":"heading","content":{"text":"1. Công thức phân tử and Công thức đơn giản nhất","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["Giải mãi bản đồ cấu tạo, Hữu cơ dùng ba loại biển báo công thức:","1. **Công thức Tổng Quát (CTTQ):** Lấy chữ X Y Z làm mốc chỉ tỉ lệ chùm (Ví dụ $C_xH_yO_z$) để lập hệ phương trình khối lượng.","2. **Công thức Đơn Giản Nhất (CTĐGN):** Là phép CHIA TỐI GIẢN CHÓT LỌT Tỉ Lệ số lựơng nguyên tử C:H:O xuống còn phân số bần cùng cực tiểu. (Ví dụ Chùm Nho $C_6H_{12}O_6$ chia đứt cho 6 ra CTĐGN là $CH_2O$). Không thể hiện đúng bản thân chất.","3. **Công thức Phân Tử (CTPT):** Kính chiếu yêu phản ánh ĐÚNG THẬT 100% Số Nguyên Tử Thực Hiện Diện trói buộc 1 phân tử (M). Cách tính duy nhất là lấy $(CTĐGN) \\\\times n$ lần."]}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Vũ Khí Kết Nối Lập Công Thức","content":"Để lập Công thức Đơn giản nhất, ta thiết lập hàng ngang Phân số Số Mol (n): $x : y : z = \\\\frac{m_C}{12} : \\\\frac{m_H}{1} : \\\\frac{m_O}{16} = \\\\frac{\\\\%C}{12} : \\\\frac{\\\\%H}{1} : \\\\frac{\\\\%O}{16}$. Ra các phân chia lẻ $\\\\rightarrow$ Đưa về Tỉ lệ nguyên bé nhất.\\nHệ Nới Rộng CTPT: $(CTĐGN)_n = M_{thực\\\\ tế}$. Giải nhẩm ra hệ số Mệnh $n$ rồi nhân lòi n vô công thức con để phình phập lồi ra chất Thực."}},{"id":"mod4","type":"heading","content":{"text":"2. Phân tích nguyên tố and Lập công thức","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Kĩ Thuật Dựng Lại Chân Dung Hữu Cơ Qua Lò Thiêu Đốt Cháy (Phân tích nguyên tố). Do 100% Carbon rã hết thành CO2, 100% Hydrogen vắt tụi rớt thành H2O mồ hôi. Nên ta Phản Truy quy chiếu thu bắt ngược lại."}},{"id":"mod6","type":"paragraph","content":{"text":"Công cụ hút thu dội lò luyện đơn: Chất cháy đẩy khói xả qua hai ống chốt. \\n- Bình số (1) nhét Cục Hóa chất Nóng Hút Nước cực dại ($H_2SO_4$ đặc, Hoặc Khối $P_2O_5$, $CaCl_2$ rắn khô khan). Cân nặng bình (1) tăng rướn lên tột độ CHÍNH LÀ TRỌNG LƯỢNG Nước ($m_{H_2O}$) kẹt khóc trong bình.\\n- Khí khô gầy bay qua Bình số (2) chứa Nước Vôi Trong $Ca(OH)_2$ chực sẵn. Cân nặng lên vọt hay vữa tủa trắng nổi lềnh CHÍNH LÀ KHÍ Carbon dioxid ($CO_2$) lọt lưới (Suy ra Mol C)."}},{"id":"mod7","type":"infoBox","content":{"color":"green","title":"Định Mức Lưới Số Mol Nguồn Gốc Cháy","content":"Học sinh Cấm Chết Quy Tắc Số:\\n[1] $n_C = n_{CO_2} = \\\\frac{m_{bình\\\\ 2\\\\ tăng}}{44}$. (Khối lượng $m_C = n_C \\\\times 12$).\\n[2] $n_H = 2 \\\\times n_{H_2O} = 2 \\\\times \\\\frac{m_{bình\\\\ 1\\\\ tăng}}{18}$. (Khối lượng $m_H = n_H \\\\times 1$). Do 1 nước có 2 chữ H.\\n[3] Suy ngược Mol Oxi ẩn thân mù mờ $O$: Phải Lấy Khối lượng Chất Hữu cơ ban đầu ném cháy ($m_X$) Trừ Gốc $m_C$ and Trừ Gốc $m_H$. Độ dư dôi hắt hơi đó chia 16 ra mol Oxy."}},{"id":"mod8","type":"warningBox","content":{"color":"orange","title":"Con Đường Tử Thần Đoạn Phân Số Lẻ","content":"Lỗi cấm kị khi chia tỉ lệ $x : y : z$. Lỡ chia ra C: 1 and H: 2.5 and O: 1. Việc làm tròn $2.5 \\\\rightarrow 3$ là Án Tử vĩnh viễn không điểm. Luật Hưởng Là phải nhân bội nhẩm 2 toàn hàng chéo lên cho ra cặp số Tròn Khít tối giản: Nhân 2 xộc $\\\\rightarrow 2 : 5 : 2$. Tương đương $C_2H_5O_2$."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=9W7vc3yGMfo","title":"Bài giảng: Công thức phân tử hợp chất hữu cơ","thumbnail":"https://img.youtube.com/vi/9W7vc3yGMfo/0.jpg","description":"Cách xác định công thức đơn giản nhất and công thức phân tử dựa trên kết quả phân tích nguyên tố (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 12. Công thức phân tử hợp chất hữu cơ là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 12. Công thức phân tử hợp chất hữu cơ là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 12. Công thức phân tử hợp chất hữu cơ?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 12. Công thức phân tử hợp chất hữu cơ thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 12. Công thức phân tử hợp chất hữu cơ?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 12. Công thức phân tử hợp chất hữu cơ?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 12. Công thức phân tử hợp chất hữu cơ trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 12. Công thức phân tử hợp chất hữu cơ?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 12. Công thức phân tử hợp chất hữu cơ, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 12. Công thức phân tử hợp chất hữu cơ giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 12. Công thức phân tử hợp chất hữu cơ là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 12. Công thức phân tử hợp chất hữu cơ là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 12. Công thức phân tử hợp chất hữu cơ?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 12. Công thức phân tử hợp chất hữu cơ thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 12. Công thức phân tử hợp chất hữu cơ?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 12. Công thức phân tử hợp chất hữu cơ?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 12. Công thức phân tử hợp chất hữu cơ trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 12. Công thức phân tử hợp chất hữu cơ?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 12. Công thức phân tử hợp chất hữu cơ, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 12. Công thức phân tử hợp chất hữu cơ giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 12. Công thức phân tử hợp chất hữu cơ tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 12. Công thức phân tử hợp chất hữu cơ với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 12. Công thức phân tử hợp chất hữu cơ thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 12. Công thức phân tử hợp chất hữu cơ, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 12. Công thức phân tử hợp chất hữu cơ?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 12. Công thức phân tử hợp chất hữu cơ vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 12. Công thức phân tử hợp chất hữu cơ?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 12. Công thức phân tử hợp chất hữu cơ lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 12. Công thức phân tử hợp chất hữu cơ?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 12. Công thức phân tử hợp chất hữu cơ là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai13', 11, 'ketnoi', 'Bài 13. Cấu tạo hóa học hợp chất hữu cơ', 'Chương 3. Đại cương về hóa học hữu cơ', 13, 'Trật tự liên kết các nguyên tử tạo ra cấu tạo hóa học. Tìm hiểu đồng đẳng, đồng phân and nhóm chức đặc trưng trong hợp chất hữu cơ.', '[{"id":"mod1","type":"heading","content":{"text":"1. Thuyết cấu tạo hóa học","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["Hữu cơ từng là Lĩnh Vực Ma Điên cho đến khi Bác học Butlerov hạ chiếu Thuyết Cấu Tạo Hóa Học - Linh Hồn Tối Thượng.\\n1. **Tuân thủ Bàn Luận Hóa Trị:** Carbon (C) mang 4 Tay gắp, Hydrogen (H) mang duy nhất 1 chấu cắm, Oxygen (O) bấu 2 chốt khuy, Nitrogen (N) xoắn 3 vặn tròn. Các nguyên tử Hữu Cơ vĩnh viễn không bao giờ ghép lộn xộn vô trật tự, mà Chặt Chẽ Xiết Ràng Buộc như Trò Chơi Lego Lắp Ráp Khung Hóa Trị.\\n2. **Cách ghép làm Nên Tính Chất Mệnh:** Chất Cồn Men Say ngất ngây and Chất Khí Độc Lạnh Gáy Tê Cứng có Thể Giống Tuyệt Đối 100% Khối lượng, Giống 100% CTPT C2H6O. Chúng CHỈ KHÁC NHAU ở cái Hình Dáng Chỗ Lắp Ráp Tay Điểm.","3. **Sức Mạnh Khung Gỗ Cacbon:** Đặc ân thượng đế, Bọn Cacbon không chỉ bám kẻ khác, Chúng Có Thể Tự Nắm Tay Đồng Bọn vươn Cây C_C_C dài bất tận ngàn kilomet nối mạng. Ghép Mạch Thẳng Tóc, Ghép Mạch Phân Nhánh San Hô Rẽ Cây, hoặc Lượn Nối Vòng Kín Hình Lục Giác."]}},{"id":"mod3","type":"heading","content":{"text":"2. Đồng đẳng","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Nhà Đồng Đẳng Học (Anh Em Cùng Gen Hóa)","content":"Hãy hiểu chữ Đồng Đẳng (Đồng loại Hàng Đẳng). Nó là những hợp chất CÓ CẤU TẠO Y HỆT NHAU (Tính chất Hóa học giọt máu y chang 99%). Nhưng chỉ vì tuổi tác Đứa Lớn Đứa Bé, Sự To Nhỏ Xác Phàm của chúng Khác Nhau Dị Biến Thêm Bôi Từng Cục Gạch ($CH_2$ - nặng 14 dvc).\\nVí dụ Phả Hệ Dãy Alkane (Đều là mạch thẳng no no tròn): Methane $CH_4$, Gắn thêm 1 cục $CH_2$ đẻ vọt Ethane $C_2H_6$, thêm tiếp 1 cục đẻ em $C_3H_8$ and dài luồn tuột. Chúng là Nhóm \\"Đồng Đẳng\\"."}},{"id":"mod5","type":"heading","content":{"text":"3. Đồng phân","level":"h2"}},{"id":"mod6","type":"infoBox","content":{"color":"green","title":"Tâm Khảm Ác Mộng Cắt Rễ Đồng Phân","content":"Khái Niệm Diệt Khảo Thí Tối Cao - Đồng Phân. (Đồng nghĩa CÙNG 1 Công Thức Sinh Cổ). \\n**Đồng Phân** là những chất HOÀN TOÀN KHÁC NHAU về mọi mặt (màu, mùi, lý hóa, điểm sôi tan), Bọn chúng chỉ có chung 1 cái mác CÔNG THỨC PHÂN TỬ Cột Mốc Số Nguyên Tử Nấu Cao (1 nồi cháo). Do cách Lắp Ráp Rẽ Cây Rẽ Nhánh Khung Carbon khác nhau đẻ ra Hằng Sa Số Biến Vị Phép Mệnh Lạ."}},{"id":"mod7","type":"list","content":{"type":"bullet","items":["Sự đa dạng của Hữu Cơ đè bẹp Vô Cơ là nhờ Sự Bùng Nổ Giới Đồng Phân:\\n1. **Đồng Phân Mạch Khung Carbon (Trò Rút Khớp Xương):** Xẻ khúc Mạch Kẻ Thẳng vót 4 chốt ($CH_3-CH_2-CH_2-CH_3$ Butane) thành Bẻ Chấu Nhô Mạch Gắn Rẽ Nhánh Lồi ($CH_3-CH(CH_3)-CH_3$ 2-MethylPropane).\\n2. **Đồng Phân Dịch Vị Trí Chốt:** Dời chỗ Cắm của Liên kết Đôi (C=C đầu rào nhảy về vô lõi C=C lõi), hoặc Dời Xách Gốc (-OH, Cl) Chạy từ Đầu nhà cắm thụt lút vào Giữa Nhà.\\n3. **Đồng Phân Loại Cực (Loại Mép Nhóm Chức):** Cùng $C_2H_6O$ có thể Vẽ lắp Đầu rẽ Phép Rượu (-OH bấu đuôi say lảo đảo) VÀ Vẽ biến thấu Cấu Trúc Khí Kính Nổi (-O- Ngậm Mõm Cắt Chính Giữa Lõi lừng chừng Ether Tê liệt Não)."]}},{"id":"mod8","type":"warningBox","content":{"color":"orange","title":"Cái Bẫy Đếm Nhầm Tay Đồng Phân Chết Bất Đắc Kì Tử","content":"Sai lầm Kèo điểm nặng nhất Đề Thi Hóa: Bẻ nhầm tay hoặc bẻ nhánh cắm Lại cái Mép Vị Trí CHÓT ĐUÔI RỄ Mạch. Hãy nhớ Mạch Carbon Có Thể Uốn Nắn Lượn Lờ dích dắc uốn éo Cong Đuôi Cạp. Việc Gấp Cột Bẻ Cổ 1 Khung Thẳng hình chữ U thì Bản Chất Rút Ruột Nó Vẫn Chỉ Là 1 Cái Khung Thẳng (Bẻ Gập chứ Không hề Sinh Trưởng Nhánh Thực Sự giữa thân). Phải Vẻ gãy dời Trói Chốt VÀO Giữa CÁC CARBON BÊN TRONG CỤC thì Mới Gọi LÀ Vẽ Phân Rẻ Nhánh."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=yVug4yRVoRQ","title":"Bài giảng: Cấu tạo hóa học hợp chất hữu cơ","thumbnail":"https://img.youtube.com/vi/yVug4yRVoRQ/0.jpg","description":"Thuyết cấu tạo hóa học, khái niệm đồng đẳng and đồng phân trong hóa hữu cơ (Tech12h)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 13. Cấu tạo hóa học hợp chất hữu cơ là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 13. Cấu tạo hóa học hợp chất hữu cơ là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 13. Cấu tạo hóa học hợp chất hữu cơ?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 13. Cấu tạo hóa học hợp chất hữu cơ thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 13. Cấu tạo hóa học hợp chất hữu cơ?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 13. Cấu tạo hóa học hợp chất hữu cơ?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 13. Cấu tạo hóa học hợp chất hữu cơ trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 13. Cấu tạo hóa học hợp chất hữu cơ?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 13. Cấu tạo hóa học hợp chất hữu cơ, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 13. Cấu tạo hóa học hợp chất hữu cơ giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 13. Cấu tạo hóa học hợp chất hữu cơ là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 13. Cấu tạo hóa học hợp chất hữu cơ là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 13. Cấu tạo hóa học hợp chất hữu cơ?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 13. Cấu tạo hóa học hợp chất hữu cơ thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 13. Cấu tạo hóa học hợp chất hữu cơ?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 13. Cấu tạo hóa học hợp chất hữu cơ?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 13. Cấu tạo hóa học hợp chất hữu cơ trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 13. Cấu tạo hóa học hợp chất hữu cơ?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 13. Cấu tạo hóa học hợp chất hữu cơ, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 13. Cấu tạo hóa học hợp chất hữu cơ giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 13. Cấu tạo hóa học hợp chất hữu cơ tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 13. Cấu tạo hóa học hợp chất hữu cơ với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 13. Cấu tạo hóa học hợp chất hữu cơ thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 13. Cấu tạo hóa học hợp chất hữu cơ, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 13. Cấu tạo hóa học hợp chất hữu cơ?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 13. Cấu tạo hóa học hợp chất hữu cơ vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 13. Cấu tạo hóa học hợp chất hữu cơ?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 13. Cấu tạo hóa học hợp chất hữu cơ lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 13. Cấu tạo hóa học hợp chất hữu cơ?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 13. Cấu tạo hóa học hợp chất hữu cơ là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai14', 11, 'ketnoi', 'Bài 14. Ôn tập chương 3', 'Chương 3. Đại cương về hóa học hữu cơ', 14, 'Tổng hợp các nền tảng kiến thức bắt buộc trước khi chuyển sang các bài hydrocarbon and dẫn xuất hữu cơ chi tiết.', '[{"id":"mod1","type":"heading","content":{"text":"1. Tóm tắt bốn trụ cột cơ bản","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["Cuộc viễn chinh Lõi Hữu cơ luôn giăng lọng vòng quanh 4 Bức Tường thành Khái Niệm Phủ Nền Vững Chãi Phá Vỡ SGK:","Tường 1: Nắm bắt Hữu cơ là Nắm bắt Sự Sống Mạch Carbon. Chúng phân hóa Mép nhánh Liên Kết Cộng Hóa Trị Mỏ Neo yếu dễ cháy bén bay hơi (Tới mức ko dám lại gần Lửa Đèn). Luôn luân ra Các Hỗn Phẩm (Phụ Ẩn).","Tường 2: Tuyệt kĩ Phân Lọc (Dùng Nắm bắt tính Lí Tốc): Khác Độ Tan Xài Chiết Cốc rỏ rỉ, Khác Nhiệt Độ Nấu Sôi dùng Đun Bình Lạnh Chưng Cất, Khác Điểm Mảng Tinh Lưới dùng Kết Tinh Lạnh Vữa Lọc Mía, Dính Đọng Thấm dùng Pha Chảy Trượt Sắc Kí Rẽ Màu.","Tường 3: Định Lượng Mù Hắc Cháy CTPT. Quăng mìn Khối lượng mC mH vô công thức Tỉ lệ X Y bóc tách Lớp Vỏ Hằng Số $n$.","Tường 4: Cảnh Phân Cấu Trúc Thuyết Kẹp Kỷ. Đồng Đẳng (Anh em Phù Du chênh Nhau Nhúm Khối $CH_2$ Dài Lêu Nghêu). Đồng Phân (Đấu Tướng Trò Ráp Lego Cùng Cục Tổng $C_xH_y$, Trổ Muôn Hình Vạn Vẻ Xoay Lắp Nhánh and Dời Bến Chức)."]}},{"id":"mod3","type":"heading","content":{"text":"2. Cách tư duy thông dụng lập Công thức phân tử -> Cấu tạo","level":"h2"}},{"id":"mod4","type":"paragraph","content":{"text":"Tư duy bóc tách Một Khối Sinh Bài Tập Khó chưa từng thấy. Bạn sẽ luôn gặp những Đám mây Chất lạ hoắc (Ví Dụ X tác dụng with Na nhả khí X... Đốt Cháy A Phọt B...). Bản Năng Giải Pháp là Hệ Trình Bẻ Khóa Bốn Bước Trâu Bò Chọc Xuyên."}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Bộ Quy Trình Thuật Toán Phân Giải Bài Tập Xác Định Chất","content":"B1 - Phân Dã Xác Chết: Trói khối lượng mBình Tăng, Tính ngay chót Cân nCO2 $\\\\rightarrow$ C. Quất Vũng nH2O (Nước) $\\\\rightarrow$ Ra 2 Cặp Hydro (Nhớ Nhân 2). Ném 16 chốt dội văng Số O còn Sót Ẩn.\\nB2 - Ráp Thu Nhỏ: Bấm Máy Chóp nhặt $\\\\%C / 12 : \\\\%H / 1 : \\\\%O / 16$. Tìm Cặp Lẻ Nguyên Nhỏ xíu (Vd Lòi $CH_2O$). Đây gọi là Bản Phác Đơn Giản.\\nB3 - Hóa Nhỏ Mệnh Cục Khối Tỉ Khối: Ráp vào $(CH_2O)_n$. Bài Cho Dữ Liệu Tỉ Khối Khí / Hoặc Khối lượng Hóa Hơi tống Vô Tính $M_{thực} = 60$. Đẩy Giải n=2 bung ra cục $C_2H_4O_2$.\\nB4 - Viết Nghệ Thuật Lõi (Cân Bão): Mang $C_2H_4O_2$ ráp bẻ Đồng Phân Chức Trình SGK (Có Hợp nhóm Ester, Có Nối nhóm Acid). Lựa Cái Đề Cần Dịch Yêu Cầu."}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Lời Cảnh Báo Thảm Sát Góc Nhìn Não Bộ","content":"Khi vẽ Đồng Phân, rất nhiều Mầm Cây rớt mạng vô Hư Ảo do Tật Xé Trực Quan. Có 2 Vạc Lỗi cần tránh: MỘT - Nối Chặt Liên kết Tay thừa Cacbon 5. Carbon (Hóa trị bằng Cứng 4). Nếu Đâm Trọt quá 4 gạch bao H xòe nhánh $\\\\rightarrow$ Cấu trúc bùng Nổ Sai. \\nHAI - Sự Đối Xứng Trục Quỷ. Cùng 1 cái cây bút, rẽ Rẽ Trái Đâm Cành Nhánh and Nhấc ngược Cây bút Gập Đâm Cành Rẽ Phải Thực Chất 100% LÀ MỘT KHUNG THỂ DUY NHẤT LẬT MẶT. Chớ Có dại liệt kê đếm Bằng 2 Thằng Đồng Phân Khác nhau Mất Điểm Tức tưởi."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=YvGbR2N2Ec0","title":"Ôn tập chương 3: Đại cương về hóa học hữu cơ","thumbnail":"https://img.youtube.com/vi/YvGbR2N2Ec0/0.jpg","description":"Tổng kết kiến thức về đặc điểm cấu tạo and phương pháp phân tích hợp chất hữu cơ (Tech12h)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 14. Ôn tập chương 3 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 14. Ôn tập chương 3 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 14. Ôn tập chương 3?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 14. Ôn tập chương 3 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 14. Ôn tập chương 3?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 14. Ôn tập chương 3?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 14. Ôn tập chương 3 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 14. Ôn tập chương 3?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 14. Ôn tập chương 3, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 14. Ôn tập chương 3 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 14. Ôn tập chương 3 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 14. Ôn tập chương 3 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 14. Ôn tập chương 3?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 14. Ôn tập chương 3 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 14. Ôn tập chương 3?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 14. Ôn tập chương 3?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 14. Ôn tập chương 3 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 14. Ôn tập chương 3?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 14. Ôn tập chương 3, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 14. Ôn tập chương 3 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 14. Ôn tập chương 3 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 14. Ôn tập chương 3 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 14. Ôn tập chương 3 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 14. Ôn tập chương 3, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 14. Ôn tập chương 3?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 14. Ôn tập chương 3 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 14. Ôn tập chương 3?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 14. Ôn tập chương 3 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 14. Ôn tập chương 3?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 14. Ôn tập chương 3 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai15', 11, 'ketnoi', 'Bài 15. alkane', 'Chương 4. Hydrocarbon', 15, 'Cấu tạo, danh pháp, tính chất and ứng dụng của alkan. Nhận biết phản ứng đặc trưng là phản ứng thế and cracking.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm and cấu tạo","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Chương 4 Lộ Diện Trùm Đặc Vụ Vi Tiền Lẻ Cuối Cùng - Băng Nhóm HYDROCARBON. \\nBang Hội mở màn là ALKANE (Hay dân gian quen Thét gọi Lão Làng Paraffin Nhám No Đầy). \\n100% Phân tử Mập ú Không Có Viền Mảnh chỉ cắm Rễ toàn Liên Kết Đập Thẳng Đơn Cốt Lõi (Ký Hiệu Sigma $\\\\sigma$ siêu cấp bền dẻo Dai Bẻ Dứt Khoáng). Chúng Bịt Lỗ Lót Sạc kín toàn C and H Bão Hòa Nung Chảy Phân Tử (Không Còn Tay Dư Đón Nhận cộng chắp Xúc Tua nào Nữa)."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Đế Tôn Định Mệnh Tướng","content":"Công thức Đế Quan Cốt Lõi Phổ Quát Nhất Của Hệ Alkane: Lập Nền $(C_n H_{2n+2})$ (Với Điều kiện rễ mốc $n \\\\ge 1$).\\nVí Cớ Mạng Nhện $\\\\sigma$ kết dính toàn diện chắc mịt, Alkane vô cùng Khinh Ghet and Bất Hợp Tác Phản Ứng with MỌI DUNG DỊCH (Axit, Kiem, Nhúng Thuốc Bromine, Nước Tẩy Nhạt Lòa KMnO4). Chúng Lầm lầm, Trơ lì lạnh cảm (Sự Trơ hóa học parafin)."}},{"id":"mod4","type":"heading","content":{"text":"2. Tính chất vật lí","level":"h2"}},{"id":"mod5","type":"list","content":{"type":"bullet","items":["Bộ Áo Giáo Tính Vật Lí Bền Bỉ Gặm Trơn:","1. Trạng Thái Vóc Sức: Khối Cột Bé Nòng Cốt C1 Đến Ranh Mốc C4 ($CH_4, C_2H_6, C_3H_8, C_4H_{10}$) là Các Khí Mát Thiên Nhiên Bay Lả Cột Lửa Nấu Gas.\\nBiến Dịch Từ Vượt C5 nhích Dần đến Tầng C17: Các Cụ Alkane phệ phì To Ra Nặng Béo Căng Trình Tụ Hóa Rớt Đặc Trạng Thái Thể LỎNG NHỚT VÀNG Khè (Dầu Hỏa, Dầu Diesel Rưới Trượt).\\nKể từ Chóp C18 leo ngược Lên Nóc Trăm C: Hóa Khối Hạt Thập Tựa Mỡ Nhám Cứng Nhắc Đặc Trạng Thái THỂ RẮN Trơn (Sáp Nến Vuốt Đèn Cầy Paraffin Khô Dầu Mỏ).","2. Trượt Lề Nước Dội Cửa: Tất Dạ Alkane Khinh Đứng Dày Tan Chìm Tan Biển Mặn. Chúng Nổi Phềnh Bề Mặt Tựa Ván Phao Chết Lì Nhẹ Bông Nước. Phá Giáp Tan Vữa Rã Rời Trong Dung Môi Benzen Hòa cồn Gỡ Sơn Móng Cồn Tẩy."]}},{"id":"mod6","type":"heading","content":{"text":"3. Tính chất hóa học","level":"h2"}},{"id":"mod7","type":"paragraph","content":{"text":"Bù Lại Sự Cảm Hoài Trơ Đác Ở Phòng Thường. Cắm Cưa Đốt Lò Hóa Bạo Kiềm Oxi hay Sung Lửa Ánh Sáng Tia Cực Tím Trút Lên Đầu Nổi Điên Vặn Vẹo Quấn Vết. \\nAlkane bung Xả Cấu Trúc Khép Kín Cực Độc Tham Chiến Bộ 3 Trận Mạc Hủy Cốt Khí Sinh."}},{"id":"mod8","type":"list","content":{"type":"bullet","items":["**Tuyệt Kĩ Phản Ứng Cực Trọng Thứ 1: THẾ VỊ HOÁN SỐ HALOGEN (Phản ứng Quán Trị Đỉnh Của Chóp Dấu Hiệu Đặc Trưng)**\\nDưới tia UV Tắm Nắng Ánh Sáng Tím chói chang hoặc nung lồng lò. Bình Clo Vàng Lục $Cl_2$ Đánh Nát Bứt Trụi Từng Cộng Tóc Hydrogen ra Rớt Ném Vứt Ngoài, Để Cl lao đầu Vào Cắn Chặt Ngồi Xổm Chiếm Ghế.\\n$CH_4 + Cl_2 \\\\xrightarrow{Askt} CH_3Cl (Thế\\\\ Móc\\\\ 1\\\\ Chân) + HCl\\\\uparrow$. \\nNếu Bình rách dài Rễ lớn C lớn, Khí Clo Sẽ Uu Tiên Chọt Móc Lấy Thế Cắm Phập Vào Thằng Carbon Chốt Mạch Giữa Đứng Gục Nhánh Ở Sâu Bên Trong Tủy Nhất (Carbon Cấp Bậc Bậc Cao) Thành Sảm Phẩm Thế Cốt Lõi Tích Lập Chính Vị.\\n\\n**Tuyệt Kĩ Màn Oanh Kích 2: ĐỐT CHÁY BÙNG NỔ THẢ LỬA LÊN ĐỈNH.**\\nMồi Thắp Lửa Cồn Cháy Nọc Bạo Động Kinh Dị Sinh Lượng Năng Cực Đại Tỏa Lò Sinh Mạch Cồn Nấu Đỏ Quặng Ngục Nhiên Liệu Vạn Tế. Nước Bay Bọt Khí Mù Quán Múc Mở.\\nLệnh Bất Bại Nắm Thóp: Cứ Lôi Thằng Alkane ra Đốt thì Vĩnh Viễn Số Mol H2O Bự Quác Nở Rộ Chèn To Hơn Thạc Số Mol C02 xả Lò. ($n_{H_2O} > n_{CO_2}$).\\n\\n**Tuyệt Kĩ 3: Bẻ Gãy Rẽ Cụt Hình Chóp CRACKING** (Phân Rã Vỡ Cứa Lò Nhiệt Ép 500 C).\\nKhoác Mạch Gỗ C dài hàng vạn km vỡ cắt vụn Ra Những Mảnh Dăm Alkane Con Nhẹ Cân + Alkene Bóng Cháy. ($C_4H_{10} \\\\xrightarrow{T^0 C} CH_4(Nát\\\\ Chút) + C_3H_6$). Biến Dầu Thô Đặc Dẻo quạnh Rã Rút Mỡ Lọc Trong Vắt Thành Giếng Xăng Điện Chết Siêu Bay."]}},{"id":"mod9","type":"warningBox","content":{"color":"orange","title":"Bão Tử Lò Vung Gas Hoang Dã Năng Lượng Đỉnh Cao Tận Diệt","content":"Vì 100% Khí Căn Nguồn Năng Lượng Thiên Niên Thạch Khí (Giếng Mỏ Dầu Quặng, Giếng Khí Đun Xăng Bếp Lửa Hạt Nhựa) Chứa Tràn Ngập Đầy Bụng Alkane No tròn Ụ Ịch.\\nNhưng Đừng Có Ngáo Cạn Ngáo Chế Mà Rò Rỉ Để Các Khí Alkane Đần Này Khạc Phun Cặp Cánh Với Bầy Oxi Lở Lửng Trong Vòng Kín. Ái Đốm Đỏ Đốt Ti Đánh Đẹt... Nó Phản Cháy Dây Chuyền Ép Quãng Khổng Thể Cực Đạn Phóng Chấn Rách Tan Tung Tường Nát Tầng Lầu Quẩy Án Nổ Kinh Hoàng Cực Trọng Sát Gian Diệt Tồn Lò Sưởi Tử Khí."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=CYH2FW4Fe0Q","title":"Bài giảng: alkane","thumbnail":"https://img.youtube.com/vi/CYH2FW4Fe0Q/0.jpg","description":"Đặc điểm cấu tạo, tính chất vật lí, hóa học and ứng dụng của các hydrocarbon no (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 15. alkane là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 15. alkane là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 15. alkane?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 15. alkane thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 15. alkane?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 15. alkane?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 15. alkane trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 15. alkane?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 15. alkane, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 15. alkane giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 15. alkane là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 15. alkane là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 15. alkane?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 15. alkane thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 15. alkane?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 15. alkane?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 15. alkane trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 15. alkane?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 15. alkane, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 15. alkane giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 15. alkane tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 15. alkane với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 15. alkane thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 15. alkane, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 15. alkane?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 15. alkane vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 15. alkane?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 15. alkane lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 15. alkane?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 15. alkane là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai16', 11, 'ketnoi', 'Bài 16. Hydrocarbon không no', 'Chương 4. Hydrocarbon', 16, 'Phân biệt alkene and alkyne, đặc trưng của liên kết bội qua các phản ứng cộng.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm and Công thức chung","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["Bước chân vào thế giới của Sự Thiếu Hụt ($Hydrocarbon$ Không No). Đây là Lãnh địa của những phân tử mà Bộ Khung C-C chưa được Nhồi nhét Đầy Đủ nguyên tử H (Chưa Bão Hòa), Buộc các C phải tự Xoay Sở Nắm Chặt Tay Nhau bằng Liên Kết Bội (Liên kết Đôi C=C hoặc Bộ Ba C≡C) để giữ thăng bằng vững Mạch.","**Gia Tộc Alkene:** Đặc Thù Duy nhất là Cắm 1 Liên Kết Đôi C=C vào Lõi Mạch hở. Tổng Khung Bị rớt đi 2 hạt H so with Alkane. Công thức Đế Quan: $C_nH_{2n}$ (Sống từ 2C trở lên $n \\\\ge 2$). Ví dụ: Ethene ($CH_2=CH_2$).","**Gia Tộc Alkyne:** Mang Trong thân 1 Khối Vết Nứt Liên kết Ba C≡C siêu hút. Gắn mạch Hở. Rớt Mạng 4 hạt Hydro. Công Thức Chuẩn Hóa: $C_nH_{2n-2}$ ($n \\\\ge 2$). Ví dụ kinh điển Đèn Xì Hàn Cắt Kim Loại Acetylene ($CH \\\\equiv CH$)."]}},{"id":"mod3","type":"heading","content":{"text":"2. Tính chất Phản ứng cộng","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Bản Chất Sức Mạnh Phản Ứng (Điểm mù Pi)","content":"Liên kết Bội chứa đựng Lực Lượng Núp Bóng Vô Dụng. 1 Lõi C=C gồm (1 Chốt $\\\\sigma$ Kim Cương Bất Dịch Mạng) and (1 Sợi Dây $\\\\pi$ Kéo Hờ Yếu Sinh Lí lủng lẳng bên trên). Dây Pi Rát dễ bị Kéo Cắt Búng Đứt Tung Tóa. \\nVì thế, Phản Ứng ĐẶC TRƯNG MỌI THỜI ĐẠI của Không No Là: **PHẢN ỨNG CỘNG** (Bẻ Xích Pi, Mở Tay 2 C ra Nhét Bội Thực các Tác Nhân Lạ Vào Kín Mạch Trở Lại Thành Thằng No)."}},{"id":"mod5","type":"paragraph","content":{"text":"**Phản ứng điển hình:** \\n- Cộng Halogen (Brom): $CH_2=CH_2 + Br_2 \\\\rightarrow BrCH_2-CH_2Br$ (Nhận biết alkene/alkyne làm mất màu dd Brom).\\n- Cộng Hydro: $CH_2=CH_2 + H_2 \\\\xrightarrow{Ni, t^\\\\circ} CH_3-CH_3$ (Thành Alkane).\\n- Cộng HX (HCl, H₂O) theo đúng **Quy tắc Markovnikov**: (H ưu tiên cộng vào carbon phần mang nhiều nguyên tử H hơn - carbon bậc thấp, X cộng vào phần carbon kém H hơn - carbon mang tính bậc cao).","items":["Bộ Ba Lối Mở Liên Kết Cộng (Xé Lưới C=C, Bẻ Gãy C≡C Mở Tung Rã Nhánh):","1. **Cộng Halogen (Điểm Cắn Thuốc Thử Cổ Điển):** Quăng tia Alkene, Alkyne Khí bọt sục vào Nước Bromine (Nâu Gỉ Trầm). Dây Pi Lập tức Cắt phăng, 2 Mũi Brom Cắn Ngập 2 Tay C ngậm đính cứng. Dung Dịch Thuốc Brom Bay Mất Màu Lập Tức Hóa Trắng Veo. ($CH_2=CH_2 + Br_2 \\\\rightarrow CH_2Br-CH_2Br$).","2. **Cộng Hydro (Trẻ Hóa Bản Thân Ngược Về Phương Bắc):** Dưới Mũi Kiếm Xúc Tác Đun Nóng Nickel (Ni). Chúng Bị Trói Buộc Khí Hydro Nạp Vô Liên kết Đôi/Ba Chữa Lành Lại Thành ALKANE NO. ($CH\\\\equiv CH + 2H_2 \\\\xrightarrow{Ni, t^\\\\circ} CH_3-CH_3$).","3. **Luật Markovnikov (Kẻ giàu Bọn Hút Quyền Lực):** Khi cộng tác nhân BẤT ĐỐI XỨNG kiều HX (Axit HCl, Nước H-OH). Quy Tắc Sắt Đá: **Hydro (H) giàu thì luôn Bợ Đỡ Vào Đuôi C đang ở Góc Thấp Đông Đảo Phủ Hydro nhất (Giàu Càng Giàu Thêm)**. Gốc X còn lại (-Cl, -OH) Chui Tọt Vào Khoảng C Chính Xương Giữa Nhiều Bậc Ít H (Đẻ Sản Phẩm Chính Cốt Lõi Lớn Mạng)."]}},{"id":"mod6","type":"heading","content":{"text":"3. Nhận biết Alkyne đầu mạch","level":"h2"}},{"id":"mod7","type":"paragraph","content":{"text":"Tuyệt Kĩ Nhận Diện Anh Em Nhà Liên Kết C≡C Ba.\\nCác Alkyne Mang Liên Kết Ba Vắt Trọn Nép Ở Mép Cuối Cùng Rìa Mạng (Gọi là Alkyne-1 hay Đầu Mạch). Cấu trúc Rìa $R-C\\\\equiv C-H$. Nguyên Mũi $H$ Bìa Ngoài Cùng đó bị Liên Kết Ba Giằng Xé nên nó CỰC LINH ĐỘNG NHƯ CHÓI BUỘC. Nhỏ 1 Rải Nước Nhũ Bạc $AgNO_3/NH_3$ vớt qua. Ngay Lập Tức, Ion Bạc ($Ag^+$) Móc Trói Cắt Cổ Thằng H Dứt Văng Ra. Ag Chiếm Lấp Chỗ Cắm Phập Vô Tạo Cục Rắn **KẾT TỦA VÀNG NHẠT**. Dấu Hiệu Trắng Án Cô Lập 100% Phân Biệt Tội Phạm But-1-yne and But-2-yne."}},{"id":"mod8","type":"warningBox","content":{"color":"orange","title":"Nhân Bản Trùng Hợp Vô Cực Nốt Sần Liên Kết Đôi","content":"Liên kết Đôi (Alkene C=C) Tồn tại 1 Phép Thuật Thượng Xưng Của Cảnh Cấp Nhang Nhựa: **TRÙNG HỢP PLASTIC**. \\nDưới Xúc Tác Ép Áp Lực Nhiệt Hầm Khổng Lồ, Hàng tỷ Triệu Triệu Tách Tách Mắt Xích Ethene ($CH_2=CH_2$) Tự Đuổi Nhau Xé Khớp Pi Tay Cầm Nắm Nối Vụn Nối Đuôi Đan Rập tạo Biển Nhựa Nhẽo POLYETHYLENE ($(-CH_2-CH_2-)_n$) Siêu màng Tui Rác Dẻo Rải Băng Keo Vỏ. Bản chất Vạn Nhựa đều sinh Ra Từ Kiểu Buộc Tay Này."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=xHQjSYBMFLo","title":"Bài giảng: Hydrocarbon không no","thumbnail":"https://img.youtube.com/vi/xHQjSYBMFLo/0.jpg","description":"Tìm hiểu về alkene, alkyne and các phản ứng đặc trưng của liên kết bội (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 16. Hydrocarbon không no là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 16. Hydrocarbon không no là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 16. Hydrocarbon không no?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 16. Hydrocarbon không no thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 16. Hydrocarbon không no?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 16. Hydrocarbon không no?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 16. Hydrocarbon không no trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 16. Hydrocarbon không no?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 16. Hydrocarbon không no, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 16. Hydrocarbon không no giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 16. Hydrocarbon không no là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 16. Hydrocarbon không no là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 16. Hydrocarbon không no?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 16. Hydrocarbon không no thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 16. Hydrocarbon không no?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 16. Hydrocarbon không no?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 16. Hydrocarbon không no trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 16. Hydrocarbon không no?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 16. Hydrocarbon không no, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 16. Hydrocarbon không no giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 16. Hydrocarbon không no tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 16. Hydrocarbon không no với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 16. Hydrocarbon không no thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 16. Hydrocarbon không no, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 16. Hydrocarbon không no?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 16. Hydrocarbon không no vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 16. Hydrocarbon không no?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 16. Hydrocarbon không no lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 16. Hydrocarbon không no?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 16. Hydrocarbon không no là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai17', 11, 'ketnoi', 'Bài 17. Arene (hydrocarbon thơm)', 'Chương 4. Hydrocarbon', 17, 'Cấu tạo vòng thơm đặc trưng. Tính chất hóa học chủ yếu của benzene and các hydrocarbon thơm khác (phản ứng thế).', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm and Cấu tạo","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"ARENE - Kẹp Ngạt Hương Hoa Thơm (Hương Tình Hiểm Ác Hóa Học Hữu Cơ).\\nĐây Xưng Hiệu Chúa Tể Các Vòng Nhẫn Lục Giác: BENZENE ($C_6H_6$). Dãy các Vị Tướng Có Chứa Hạt Nhân Chóp Lục Vòng Này Đều Mang Cái Danh Đẹp Đẽ Xào Trá Lụa Là: Hydrocarbon THƠM. Sáu Phân Vị C đều nằm Xẹp bẹp Trơn Cùng 1 Sàng Lưới Trục Mặt Phẳng Nhẵn Cứng ngắt."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Hệ Mặt Trận Chống Đạn $\\\\pi$ (Lớp Khiên Thần Nữ)","content":"Trong Vòng Benzene $C_6H_6$: Có 3 Nấc C=C Gãy Kẽ Xen Kéo C-C Chạy Tuột Xoay Vòng. Nhưng Chúng KO Cố Định Cứng. 3 Dây Lưới Lực $\\\\pi$ Điên Cuồng Khỏa Nhập Vuốt Lan Truyền Rỗng Lấp 6 Cục C Đều Băng Tắp Lắp Tạo 1 Đám Mây Mù Bánh Mì Lôi Kéo Bề Mặt. Độ Bền Cực Khủng Của Đám Mây Mù Liên Hợp Điện Này GỌI LÀ MẶT TRẬN TÍNH THƠM.\\nCốt Chốt Kính Chiếu Ma: Vì Khiên Giáp Rát Bền. BENZENE Dễ Làm Phản Ứng THẾ ÉP NGỌAI. Tuyệt Đối Mọi Giá KHÓ TRĂM BỀ Phản Ứng Bẻ Gãy Tách CỘNG (Thách Thức Đánh Brom Tím, Xé Đứt Tầng Ống Than Mới Lùa Hydro Vào Mở Nút)."}},{"id":"mod4","type":"heading","content":{"text":"2. Tính chất vật lí","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Benzene Cạo Trần Tĩnh Thể Xít Khói Trong Vắt Lỏng Nhược ($C_6H_6$) Mùi Thơm Xộc Quyến Rũ Mũi Đáy Ngực. Nó là Ông Trùm Mạng Lưới Nhúng Rửa Dung Môi (Tan Sạch Vết Mực Dơ Dính, Nhớt Mỡ Cứng Tái Cáo Rộp Mạng). NHƯNG Hãy Cảnh Giác:\\nSát Nhân Thầm Kín Độc Ngụy Dẫn Mạng Ung Thư Ung Huyết Phá Tế Bào Thần Kinh nếu hít Nặng Liên tục Ngấm Mạch Cửa Tử Vòng Đời Thấm Xăng. Cháy Rò rỉ Không No Toát Khói Đen Mù Cặn Xỉ Nám Lửa Bếp Than Bồi Thất."}},{"id":"mod6","type":"heading","content":{"text":"3. Tính chất hóa học: Phản ứng Thế vòng Benzene","level":"h2"}},{"id":"mod7","type":"list","content":{"type":"bullet","items":["Bộ Ba Lấy Đuôi Phá Ngai Thế Vòng Lõi (Cắm Ngập Gai Cọc):","1. **Bạo Phong Thế Halogen Rụng Nhánh (Vòng Chạy Brom Nguyên Chất Lệnh Cấm Nước):** \\nPhải Nhỏ Sợi Lông Bром Lỏng Trực Lượng Không Xào Nước Trích Bromine ($Br_2$ Lỏng Khan). Gõ Nhịp Đun Với Rắc Bột Sắt Tinh $FeBr_3 / Fe$ làm Mũi Khoan.\\nLưới Nhẫn Bức Bách Vứt Rớt Bỏ 1 Thằng Hydro Mép Khung Để Lòi Bromine Dính Cắm Gai Thế Nỏ Chốt:\\n$C_6H_6 + Br_2 \\\\xrightarrow{Fe, t\\\\circ} C_6H_5Br (Bromobenzene) + HBr\\\\uparrow$.","2. **Bom Đạn Nitro Hóa Chảy Mực Vàng Rét Nguy Hiểm:**\\nRúng Đổ Dung Dịch Acid HNO3 Đặc Quắn + Rót H2SO4 Siêu Khát Nước Nóng Nấu Sóng Nhịp.\\nNhóm Tên Lửa Bộc Phá $(-NO_2)$ Chọc Thủng Khiên Chồi Nhọn Đổ Ghép Thay H Bắn Rát Axit Nước Bo.\\n$C_6H_6 + HNO_3 \\\\xrightarrow{H_2SO_4(đ)} C_6H_5NO_2 (Váng\\\\ Kịt\\\\ Nhũ\\\\ Vàng\\\\ Nặng\\\\ Trũ\\\\ Rót\\\\ Nitrobenzene) + H_2O$."]}},{"id":"mod8","type":"paragraph","content":{"text":"Thuật Tiên Tri Định Hướng Rẽ Bàn Tay Trái – Phải (Dành Riêng Alkylbenzene Toluene $C_6H_5CH_3$). \\nKhi Gốc Rễ Benzene đã bị chốt 1 Cấu Gốc Lạ nằm sẵn ở Tọa Khung Vị Đầu. Việc Nạp Thêm Thằng Khác Vô Chốt Lần 2 Không Thể Trở Lại Dễ Dãi Cắm Đầu.\\nNếu Kẻ Ngồi Sẵn là NHÓM ĐẨY ELECTRON Rộng Cửa (Các Mạch Cắn Chồi Đẩy $-CH_3$, $-C_2H_5$, Gốc Cồn $-OH$, Gốc Mùi $-NH_2$): Lập Tức Nó Ép Bắn Đạo Quân Cắm Thế Mới Vào Buộc Chui Núp 2 Góc Tử Huyệt Lân Cận ortho (2, 6) and Hạ Bộ para (4). Đóng Kín Cổng Giữa Meta (3).\\nNgược Dòng, Kẻ Ngồi Sẵn Mà Là QUỶ HÚT TỤT ELECTRON (-NO2, Gốc Rút -COOH, Vòi -CHO): Hệ Cửa Tiềm Năng Duy Nhất Không Khóa Chặt Vẫn Lả Phân Tỏa Meta (3). Bức Ép Kẻ Đón Ngã Vịn Chật."}},{"id":"mod9","type":"warningBox","content":{"color":"orange","title":"Quyền Trượng Nhánh Toluene Thuốc Nổ Dò Điểm Màu Tím Héo","content":"Mẫu Chốt Thi Đấu: Thuốc Tím Lược (KMnO4) Không Hề Thấy Mặt Vòng Benzene Tĩnh. Nhưng Toluene ($C_6H_5CH_3$) Do Có Thằn Lằn Đuôi Nhánh Alkyl Chắp Ngoài Nên Lực Trùng Khi Đun Sôi Thổi Nóng Lò Thác Lũ ($t^\\\\circ$) Nó Giật Bẻ Cắt Bay Mõm Phân Thảy Chùm Dây Nối Chọc Tan Tím Cục Máng $KMnO_4$. Dãy Cực Đoan Mát Không Nóng Vẫn Trơ.\\nThuyết Thể Kết Thế Nitro Toluene Điên Dày 3 Mạch $HNO_3$ Sinh TNT (TrinitroToluene Thuốc Nổ Ném Công Phá Sụp Sườn Bom Ngầm Trí Ác)."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=E3ps3CJkGAc","title":"Bài giảng: Arene (Hydrocarbon thơm)","thumbnail":"https://img.youtube.com/vi/E3ps3CJkGAc/0.jpg","description":"Cấu tạo vòng benzene, tính chất hóa học của arene and ứng dụng trong công nghiệp (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 17. Arene (hydrocarbon thơm) là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 17. Arene (hydrocarbon thơm) là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 17. Arene (hydrocarbon thơm)?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 17. Arene (hydrocarbon thơm) thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 17. Arene (hydrocarbon thơm)?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 17. Arene (hydrocarbon thơm)?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 17. Arene (hydrocarbon thơm) trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 17. Arene (hydrocarbon thơm)?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 17. Arene (hydrocarbon thơm), phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 17. Arene (hydrocarbon thơm) giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 17. Arene (hydrocarbon thơm) là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 17. Arene (hydrocarbon thơm) là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 17. Arene (hydrocarbon thơm)?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 17. Arene (hydrocarbon thơm) thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 17. Arene (hydrocarbon thơm)?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 17. Arene (hydrocarbon thơm)?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 17. Arene (hydrocarbon thơm) trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 17. Arene (hydrocarbon thơm)?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 17. Arene (hydrocarbon thơm), phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 17. Arene (hydrocarbon thơm) giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 17. Arene (hydrocarbon thơm) tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 17. Arene (hydrocarbon thơm) với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 17. Arene (hydrocarbon thơm) thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 17. Arene (hydrocarbon thơm), nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 17. Arene (hydrocarbon thơm)?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 17. Arene (hydrocarbon thơm) vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 17. Arene (hydrocarbon thơm)?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 17. Arene (hydrocarbon thơm) lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 17. Arene (hydrocarbon thơm)?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 17. Arene (hydrocarbon thơm) là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai18', 11, 'ketnoi', 'Bài 18. Ôn tập chương 4', 'Chương 4. Hydrocarbon', 18, 'Hệ thống hóa toàn bộ kiến thức Hydrocarbon thành ba nhánh: Alkane (no); Alkene, Alkyne (không no); Arene (thơm).', '[{"id":"mod1","type":"heading","content":{"text":"1. Liên hệ cấu tạo - Tính chất","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["Bộ Phân Hóa Mạch Rễ Trục Hóa Học Đi Sâu Không Vết Rạn - Nhìn Từ Trên Xuống Cảnh Phả Hệ HYDROCARBON:","1. **Băng Mạc ALKANE (Gia Giáo Trọng Tổ Tộc):** Phủ Bột Chát Chỉ Cắm Kẽ Neo 1 Nối Mầm $\\\\sigma$ Không Thể Cùm. Biểu Trưng Đặc Tích Khủng Là PHẢN ỨNG THẾ CLO, BROM Ánh Sáng Phơi. Tuổi Đóng Tích Lũy Ăн Trượt Crack Xẻ Băng Gas Lửa Xăng Đốt Tận Căn.","2. **Băng Mạc KHÔNG NO ALKENE / ALKYNE (Học Sinh Đuội Kém Trống Xé Mấu Kẽ):** Mỏ Hở Rỗng Khe Giáp 2 Dây Nối Màng Trinh $\\\\pi$. Kẻ Cuồng Nhiệt Với Mọi Trào Đổ: Cuồng Vồ **PHẢN ỨNG CỘNG** Vết Kẽm (Bẻ khóa Bromine Nâu, Giựt Lõm Tím KMnO4 Đẫm Bướt Hóa Cạn Bợt). Trùng Ép Méo Máng Ráp Nút Bịt Dậy Nhựa Bao Bì Lớp Lớp Mảng Cầu.","3. **Băng Mạc THƠM ARENE (Quỷ Benzene Huyền Mật Pháp Vương Lực):** Khảm Sợi Vàng Mặt Phẳng 6 Liên Biển Nhẫn Cục Kiên Cố Điện Lực Mây Vòng. Lấy Cái Vững Nhất Là Vượt Lề Đi Hút Ép Làm Phản Ứng **THẾ RỚT TÀNG TÍA VÒNG BENZENE** Chứa Rót Ác Hạt Nóng Hõm Lâu Đài. Căm Thù Và Cực Khó Để Chịu Nhả Cục Ra Cộng Bỏ Kép Lực Oxi Dã Bại."]}},{"id":"mod3","type":"heading","content":{"text":"2. Các thuốc thử nhận biết","level":"h2"}},{"id":"mod4","type":"list","content":{"type":"bullet","items":["Tam Trụ Thuốc Thử Vạn Năng Quét Hóa Học (Bài Tự Luận Nhận Các Miền Chất Lỏng Trắng Tĩnh Hình Chóp Mất Nhãn PHTN):","Tướng Số 1: SUỐI BU M NÂU **BROMINE** Cạn Vách Nước. Nước Mắm Brom Chảy Tụ Gặp Nhánh Alkene Và Nhành Alkyne Trực Tiếp Phá Cổ Vuốt Khóa Lực Tẩy Mủ MÀU TRẮNG DỊ. Bọn Nô tỳ Alkane Và Vệ Vương Benzene Chỉ Chống Tay Nhìn Dung Dịch Đỏ Lừ Bất Biến (Miễn Khí Ngán Ngẩm).","Tướng Số 2: LUỒNG SÓC THẠCH TÍM VẠN CHỈ **KMnO4**. Lùa Tìm Tách Trục Góc ALKENE Mất Nóng Màu Héo Vàng. Đụng Điên Toluene Sôi Nấu Thì Cũng Toác Đáy Văng Lụa Tím Nhạt Trắng Tan Mòn Giọt.","Tướng Số 3: NƯỚC BẠC CHỈNH SA THỰC BÌNH MƯỜI VÀNG **AgNO3 / Kiềm Trĩ NH3**. Át CHỦ BÀI Sinh Nhai Quyền Thần Cho Tụi Khác Băng **ALKYNE-Cắm Nhánh THỀM 1 (Đầu Đuôi Bảng)**. Rưới Vào Trồi Lên Sừng Khối **TỦA BỘT VÀNG KÉP LỤA**. (Khóa Chặt Phân Tách Bọn Thằng Đôi Hoặc Lì No Rạc Ngác Tẻ Tách)."]}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Chỉ Dấu Số Toán Trắc Nghiệm Đáy Lò ĐỐT CHÁY Kể Lệnh Mol Oxi","content":"1. Khói Củi Tính Theo Căn Nước Lửa. Mol Nước ($n_{H_2O}$) Đại Mạng ĐÈ Bẹp Dập Lủng Lỗ Vác So Với Thằng Tro $CO_2$ Ngút Khí $\\\\rightarrow$ Đóng Mẹc Phán CHÍNH XÁC Y Bo Ngũ Quỷ Là ALKANE ($n_{alkane} = n_{H_2O} - n_{CO_2}$).\\n2. Mol Số Nước Rớt Ngang Cân Đo Trồi Sấp Điểm Kịch Kim Bằng Ké Mol Thép $CO_2$ Sinh Phệ $\\\\rightarrow$ Phán Quyết ALKENE Răng Khớp.\\n3. Mol Chảy Nước Héo Hon Tụt Cột Ngộp Nặng Mút Dưới Bề Mặt Của Ngọn Tro Phí $CO_2$ ($H_2O < CO_2$) $\\\\rightarrow$ Phá Ra Hàng Alkyne Hóp (Hiệu Cột Khói Trừ Lại Nước Là Khéo Lụa $n_{alkyne} = n_{CO_2} - n_{H_2O}$).\\n4. Khuyên Bảo Bọc Cốt Bảo Toàn MOL Bơm Oxi. ($n_O$ trái mồi lửa xả chui bằng Trọn Đỉnh Các Đáy Góc Ngách Đốt $2 n_{CO_2} + 1 n_{H_2O}$)."}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Giăng Cương Lưới Quẩn Đốt Rễ","content":"Bài Toán Tụ Xứ Yêu Cầu Chấn Biên Vượt Sâu Cùng Trái 1 Hệ Động Loạt Chiều: Phải Cứu Khát Nâng Cốt Phép Phương Chạy Dây XÍCH (CH4 bóp Lửa Đẻ C2H2 Ra Giêng Acetylen -> Tuốt Mũi ÉP Đẩy Alkene Vun Tụ Vinyl Clorid Tráng Lót Màng Bọc Nhựa PVC). Hay Bẻ Chuỗi Kẽm Đất Đèn Canxi Cacbua CaC2 Cốc Đá Vôi Rã Trút Thọc Họng."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=kimJ4bKKmVU","title":"Ôn tập chương 4: Hydrocarbon","thumbnail":"https://img.youtube.com/vi/kimJ4bKKmVU/0.jpg","description":"Tổng kết mối quan hệ giữa các loại hydrocarbon and giải các bài tập rèn luyện (Tech12h)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 18. Ôn tập chương 4 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 18. Ôn tập chương 4 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 18. Ôn tập chương 4?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 18. Ôn tập chương 4 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 18. Ôn tập chương 4?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 18. Ôn tập chương 4?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 18. Ôn tập chương 4 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 18. Ôn tập chương 4?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 18. Ôn tập chương 4, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 18. Ôn tập chương 4 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 18. Ôn tập chương 4 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 18. Ôn tập chương 4 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 18. Ôn tập chương 4?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 18. Ôn tập chương 4 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 18. Ôn tập chương 4?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 18. Ôn tập chương 4?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 18. Ôn tập chương 4 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 18. Ôn tập chương 4?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 18. Ôn tập chương 4, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 18. Ôn tập chương 4 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 18. Ôn tập chương 4 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 18. Ôn tập chương 4 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 18. Ôn tập chương 4 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 18. Ôn tập chương 4, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 18. Ôn tập chương 4?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 18. Ôn tập chương 4 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 18. Ôn tập chương 4?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 18. Ôn tập chương 4 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 18. Ôn tập chương 4?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 18. Ôn tập chương 4 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai19', 11, 'ketnoi', 'Bài 19. Dẫn xuất halogen', 'Chương 5. Dẫn xuất halogen – Alcohol – Phenol', 19, 'Khái niệm dẫn xuất halogen and các phản ứng đặc trưng: phản ứng thế nucleophile, tách HX.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm and Đặc điểm","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Sự Xâm Lăng Đầu Tiên Kẻ Lạ Bước Bào Khung CARBON - Chuyên Đề Mảng **DẪN XUẤT HALOGEN**. \\nNgay Lớp Alkane Rừng Điếm. Việc Đem Gai Chọt Kiếm Cào Cho 1 Lũ Nọc Rớt Thằng Hydro Mỏi Cẳng Văng Khỏi Cầu Sợi Khung Mạch, Hầu Thay Đổi Chiếm Lắp Hố Bằng Quân Đội Hốc Ác Halogen (Nanh Nọc Trắng: F, Cl, Br, I). Cái Cục Tàn Dự Bám Dính Halogen Cùi Liêm Lệnh Sát Thủ Ấy, Con Người Ưu Ái Gọi Là **Dẫn Xuất Halogen**. Khúc Nhấn Lột Xác Tạo Thể Cốt Nhân Mới."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Cú Đoạt Khống Cực Lõi (Kèo Khéo Hút Âm Về Rễ Đảo)","content":"Liên kết Chốt Canh Xó C-X (Carbon and Halogen Nhánh X). Halogen (Đặc Trưng F, Cl) Thuộc Bè Lũ Hút Điện Vô Cơ Nhất Cổ Thế Mạng Âm Tụ. Chúng Mở Miệng Liếm Trọn Kéo lệch Tụ Chóp Đám Mây Đôi Sợi Rẽ Về Phía Bản Khu. \\nHậu Cảnh Sốc Ác: Halogen Múp Cục Lẻ Nửa Âm $\\\\delta^-$. Để Lại Cho Xương Carbon Cái Đáy Khuyết Tổ Lỗ Khoét Xơ Xác Điện Thiếu Thốn Còi Mép Dương Giả $\\\\delta^+$. \\nCarbon Lúc Ấy Rát Thương Cực Xốp Tủy Yểu Kém, Mời Gửi Trực Cáo Vẫy Gọi Bọn Thợ Săn Nu Lũ Cầu Oxi (-OH, -CN..) Lướt Vô Phập Nhào Ăn Cặp Cặn Gắn Đuôi Thế. Hốc Đâm Toác Cửa Hữu Cơ Rẽ Hoán Cốt Mạch Sinh Nhánh."}},{"id":"mod4","type":"heading","content":{"text":"2. Tính chất Phản ứng thế Nucleophile (-OH) and Tách","level":"h2"}},{"id":"mod5","type":"list","content":{"type":"bullet","items":["2 Nhánh Ngõ Chiến Khu Chóp Lồng Lược Đối Nghịch Đoạt Chữ Tính:","1. **Phản Ứng Đẩy Mông Lật Ghế Nucleophile (Khử Ngôi THẾ Gốc Tách)**:\\nChâm Lò: Rót Xút Trơn Nước Xà Phòng Rặt (Kiềm Thủy Phân NaOH/ Ca(OH)2 LOÃNG NƯỚC). Vun Bể Nồi Ấm Soi Thoi Lạnh Nhịp Cạn 50 80 Độ.\\nNu Kẻ Chiếm Đoạt là (-OH Kiềm). Nó Đâm Xiên Khoét Hạ Bệ Bứng Chóp Rứt Cổ Gai Halogen X Bỏ Tuột Vứt Nghĩa Vắng Đồng Bỏ Rọ Kềm Sinh Chút Muối. Chui Vô Chiếm Vị Lõi Khoảng Góc Chốt Vết Trượt Xả Ra Giống Lòi Lõm Sinh Ra Một Ông Hoàn Mới: **ALCOHOL (Nhóm RƯỢU Khê Cồn Lỏng Độc Sát) (-OH)**.\\n$R-X + NaOH (AQUA) \\\\xrightarrow{t^\\\\circ đun} R-OH + NaCl$ Lọc Trong Khe Vét.","2. **Phản Ứng Rã Buộc Gãy Vỡ Hoang Đảo Kẽ TÁCH (Sảy Ruột Khóc Nuối Đao Chẻ)**:\\nKích Hỏa Kiếp Nạn: Đun Sôi Chống Cồn Hữu Cơ Điên Dại Pha Kiềm Gắt Hạt Mù Cục Cáo (Đá Cồn Alcohol Trộn Trát Cục KOH Rắn Liếm Ruột).\\nTại Môi Trường Độc Khí KOH Lùa Cồn Siêu Mặn Này Bóc Oxi Gắt. Nó Khôn Không Thèm Rơi Vô Mạng. Nó Kéo Đuôi Lựu Đạn Vuốt Giứt Đồng Loạt Hai Thằng Móng Gai Ở 2 Bên Carbon Hàng Xóm Đứng Kế (Giựt Đứt X Bọn Phải and Rứt H Bọn C Trái Mút).\\nHậu Đãi Hoang Khốc: Khung Carbon Bị Gãy Răng 2 Rìa Mòn Trọc. Để Trụ Mạng Cụi, 2 Thằng C Đứng Cửa Khóc Tiễn Nhìn Trụ Lõm Tự Buộc Nén Keo Giằng Xiết Xắn Tay Khép Khép Nhau Nối Nối Thêm Sợi Nguồn \\n$\\rightarrow$ Kết Vết Sợi Đôi Gắn Buộc Bẻ Hoang Ra Hình Hài **ALKENE LIÊN KẾT ĐÔI MẢY Tròn** Bay Xác Cạn Dựng Lồng Hợp Mạch Sợi Bóc Đôi Khép Kín."]}},{"id":"mod6","type":"paragraph","content":{"text":"Kính Chiếu Thần Luận ZAITSEV Lên Bàn Phân Án (Trục Nối Cuộc Chơi Nhị Phân Lựa Nẻo Lớn). Khái Đoán Chặt Nhánh Phụ Trong Tách:\\nKhi Lực Kiềm Vặn Cổ Nhóm Cl / Br Ở Cục Carbon Gáy Nhánh Cụt Tọa. Tiếng Đao Bẻ Cắn H Cắt Nhổ Lông Ở Kẻ Láng Giềng Kế Cạnh, Nó Luôn Thọc Quật **Lưỡi Thế Kéo Bẻ Bứng Đuôi Hydro Có Mặt Ở Cái Góc Trọng Ám Của Kẻ Carbon Kế Biện ÍT TRƯỚNG HYDRO NHẤT** (Bậc Sâu Chèn Giữa Bịch).\\nTừ Trụ Đỉnh Trái Áng Thừa Đổi Đó Kéo Gấp Viền Điểm Cạo Ngồi Nút Lộn Đẻ Hình Đôi Rót Xương Dựng Lên \\"Sản Phẩm Trúng Số Chiếm Khối Phàn Trăm Lớn NHẤT Dây Chính Đột Biến Nhánh Ngầm\\"."}},{"id":"mod7","type":"warningBox","content":{"color":"orange","title":"Bão Tử Tù Khí Hoại Đời Sinh Họa Lỗ Hỏng Chết Lành Trái Đất","content":"Khai Niệm Bi Kịch Tẩy Lược Dẫn Xuất Khí Lạnh Đồ Ứng. Xưa Con Người Mò Chế Ngụp Bình Đẩy Lốc Freon, CFC, Tác Bình Tủ Răn Tủ Đông Cục Phun Keo Giải Trơn Đánh Sạch Hạt Bóng Đóng Đảo Bọt Công Nghiệp Túi Xốp Cứng Giật Khắp Tiệc Khí Mù Túi. \\nTuy Thật Ngạc Nhiên Nó Lên Kẹt Trôi Phả Bay Ra Cùng Hạng Tầng Ozon Ngáo Vọc Phóng Khoáng. Nứt Tia Cực Tím Ăn Cắn Bịt Đứt Xẻ Cắt Mảnh Dẫn Khí CFC Lõi Sinh Giăng Tia Nọc Halogen Nguyên Tử. Phản Họa Đập Tan Nát Điển Bão Lực Các Hạt Màng $O_3$ Giải Cực Lưới Gây Sự **LỦNG TẦNG THỦNG LỖ RÁCH OZONE BAO PHỦ**. Diệc Da Chết Đọng Ánh Sáng Xuyên Ruột Rối Ung Nhọt Ung Thư Bề Rác Thiên Điểm Sạch Quyền Bị Khai Tử Toàn Trái Đất Cấm Tuyệt Đoạn Sử Dụng."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=D34P6I7woT8","title":"Bài giảng: Dẫn xuất halogen","thumbnail":"https://img.youtube.com/vi/D34P6I7woT8/0.jpg","description":"Khái niệm, tính chất hóa học tiêu biểu and ứng dụng của dẫn xuất halogen (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 19. Dẫn xuất halogen là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 19. Dẫn xuất halogen là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 19. Dẫn xuất halogen?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 19. Dẫn xuất halogen thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 19. Dẫn xuất halogen?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 19. Dẫn xuất halogen?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 19. Dẫn xuất halogen trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 19. Dẫn xuất halogen?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 19. Dẫn xuất halogen, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 19. Dẫn xuất halogen giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 19. Dẫn xuất halogen là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 19. Dẫn xuất halogen là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 19. Dẫn xuất halogen?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 19. Dẫn xuất halogen thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 19. Dẫn xuất halogen?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 19. Dẫn xuất halogen?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 19. Dẫn xuất halogen trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 19. Dẫn xuất halogen?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 19. Dẫn xuất halogen, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 19. Dẫn xuất halogen giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 19. Dẫn xuất halogen tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 19. Dẫn xuất halogen với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 19. Dẫn xuất halogen thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 19. Dẫn xuất halogen, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 19. Dẫn xuất halogen?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 19. Dẫn xuất halogen vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 19. Dẫn xuất halogen?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 19. Dẫn xuất halogen lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 19. Dẫn xuất halogen?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 19. Dẫn xuất halogen là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai2', 11, 'ketnoi', 'Bài 2. Cân bằng trong dung dịch nước', 'Chương 1. Cân bằng hóa học', 2, 'Bản chất sự điện li của nước, pH, môi trường acid - base and cân bằng acid - base trong dung dịch.', '[{"id":"mod1","type":"heading","content":{"text":"1. Sự điện li của nước & Tích số ion của nước","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Nước uống hàng ngày không phải là một dung môi tĩnh lặng rỗng tuếch. Nước nguyên chất (Nước tinh khiết) cũng tự phân rã, tự điện li tuy ở một mức độ cực kì yếu ớt. Quá trình tự điện li của phân tử nước là một phản ứng thuận nghịch: **$H_2O \\\\rightleftharpoons H^+ + OH^-$**. Trên thực tế, ion $H^+$ trần trụi (Proton) quá nhỏ bé nên nó không đứng một mình mà bám ngay vào một phân tử nước khác kết thành ion Hydronium ($H_3O^+$). Tại 25°C, cú phân rã này nhỏ đến mức cứ khoảng 556 triệu phân tử nước mới có vỡ ra 1 phân tử, cho nên nồng độ của ion acid $[H^+]$ = nồng độ kiềm $[OH^-]$ = $1,0 \\\\times 10^{-7}$ mol/L."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Tích số ion của Nước (Kw) - Định luật Vĩnh hằng","content":"Vì nồng độ Nước ($H_2O$) khổng lồ and coi như hằng số, người ta suy ra Tích số ion của nước $K_w = [H^+] \\\\cdot [OH^-]$. Đặc biệt tại nhiệt độ phòng 25°C, $K_w = (1,0 \\\\times 10^{-7}) \\\\times (1,0 \\\\times 10^{-7}) = 1,0 \\\\times 10^{-14}$. \\nTuyệt kĩ làm toán: Giá trị $10^{-14}$ này bị KHÓA CỨNG ÁP DỤNG cho **bất cứ dung dịch loãng nào** (nước đường, giấm, xí muội, axit H2SO4) miễn là đang pha ở 25°C. Có [H+] lập tức suy ra [OH-] bằng phép chia."}},{"id":"mod4","type":"heading","content":{"text":"2. Khái niệm pH & Môi trường dung dịch","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Việc cồng kềnh ghi chép các nồng độ ngũ phân số $10^{-7}$, $10^{-3}$ quá bất tiện, nhà hóa học Sørensen đã tạo ra thanh đo **Chỉ số pH** (power of Hydrogen) lấy logarit cơ số 10 nồng độ H+. \\n- **Môi trường Acid (Chua):** Có nhiều mầm $H^+$ trỗi dậy khiến $[H^+] > 10^{-7} M$ $\\\\rightarrow$ pH < 7.\\n- **Môi trường Trung tính (Lành tính):** Tính âm dương cân bằng hoàn mĩ $[H^+] = [OH^-] = 10^{-7} M$ $\\\\rightarrow$ pH đúng bằng 7 (Ví dụ: nước cất, dung dịch muối ăn NaCl).\\n- **Môi trường Base (Kiềm/Đắng nháp):** Lũ $OH^-$ đàn áp $H+$ khiến $[H^+] < 10^{-7} M$ $\\\\rightarrow$ pH đo đạc chạy vọt > 7."}},{"id":"mod6","type":"infoBox","content":{"color":"green","title":"Công thức giải nhanh pH","content":"1. Tính pH cực rát: $pH = -\\\\log_{10}[H^+]$\\n2. Đại lượng song sinh: $pOH = -\\\\log_{10}[OH^-]$\\n3. Mối liên kết sinh tử: Ở $25^\\\\circ C$, ta luôn luôn có phanh giới không thể phá vỡ: **$pH + pOH = 14$**."}},{"id":"mod7","type":"heading","content":{"text":"3. Thuyết Brønsted - Lowry về Acid - Base","level":"h2"}},{"id":"mod8","type":"list","content":{"type":"bullet","items":["Quên đi Thuyết cổ điển Arrhenius lỗi thời, Thuyết vạn vật Brønsted-Lowry ra đời ôm trọn mọi hệ dung môi. \\n**Định nghĩa Đỉnh cao:**","1. **Acid (Kẻ hào phóng):** Bất cứ phần tử nào (phân tử hay ion) có năng lực NHƯỜNG, ĐÁ VĂNG HẠT PROTON ($H^+$) sang chất khác. ($HCl \\\\rightarrow H^+ + Cl^-$)","2. **Base (Kẻ bòn mót):** Bất kì phần tử nào CHỤP LẤY, NHẬN LẤY Proton ($H^+$) từ môi trường. (Ammonia $NH_3 + H^+ \\\\rightarrow NH_4^+$ mập lên).","3. **Lưỡng tính (Amphoteric):** Kẻ vừa có khả năng nhả $H^+$, lại vừa có khả năng nhận cướp $H^+$ khi gặp đối thủ khó nhằn. (Nước $H_2O$, Ion $HCO_3^-$, Amino Acid Zwitterion)."]}},{"id":"mod9","type":"paragraph","content":{"text":"Độ sâu của sự phân ly định đoạt sức mạnh: Các **Chất điện li MẠNH** (Acid mạnh $HCl, HNO_3, H_2SO_4$, Base kiềm kiềm thổ $NaOH, Ba(OH)_2$ and Hầu Hết Mọi Loại Muối tan) sẽ xả thân phân đôi 100% trong nước tạo dòng ion dẫn điện dữ dội (Mũi tên 1 chiều). Các **Chất điện li YẾU** ($CH_3COOH, HF, NH_3$...) thì keo kiệt, hòa 100 phân tử chỉ vỡ ra được 1-2 phân tử rỉ ion, quá trình đứt gãy phải dùng mũi tên Cân Bằng 2 Chiều thuận nghịch."}},{"id":"mod10","type":"warningBox","content":{"color":"orange","title":"Sự Thủy phân của Muối - Bẻ gãy Cán Cân Dung Dịch","content":"Cú sốc lớn: Không phải Muối nào pha vào nước cũng Trung Tính (pH=7) như muối ăn NaCl. \\nNếu muối kết tinh từ mầm Acid Mạnh đàn áp Base Yếu (VD muối Cục $NH_4Cl$, $FeCl_3$, $Al_2(SO_4)_3$) $\\\\Rightarrow$ Dung dịch đó sẽ chua hóa ngả PH \\n< 7, làm quỳ tím đỏ.\\nNgược lại, Muối sinh ra do Base Mạnh bao bọc mầm Acid Yếu (VD $Na_2CO_3, CH_3COONa, K_3PO_4$) $\\\\Rightarrow$ Ion gốc Yếu đó bòn rút lại phân li Nước để tái chiếm chua $H^+$, để dư kiềm $OH^-$ ra ngả dung dịch thành môi trường Kiềm Xanh (pH > 7). Hiện tượng ăn mòn tái tạo đó gọi là Phản ứng Thủy Phân tạo vị."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=P4hEy0II9uE","title":"Bài giảng: Cân bằng trong dung dịch nước","thumbnail":"https://img.youtube.com/vi/P4hEy0II9uE/0.jpg","description":"Sự điện li, khái niệm pH and ý nghĩa của pH trong thực tiễn (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 2. Cân bằng trong dung dịch nước là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 2. Cân bằng trong dung dịch nước là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 2. Cân bằng trong dung dịch nước?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 2. Cân bằng trong dung dịch nước thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 2. Cân bằng trong dung dịch nước?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 2. Cân bằng trong dung dịch nước?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 2. Cân bằng trong dung dịch nước trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 2. Cân bằng trong dung dịch nước?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 2. Cân bằng trong dung dịch nước, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 2. Cân bằng trong dung dịch nước giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 2. Cân bằng trong dung dịch nước là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 2. Cân bằng trong dung dịch nước là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 2. Cân bằng trong dung dịch nước?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 2. Cân bằng trong dung dịch nước thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 2. Cân bằng trong dung dịch nước?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 2. Cân bằng trong dung dịch nước?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 2. Cân bằng trong dung dịch nước trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 2. Cân bằng trong dung dịch nước?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 2. Cân bằng trong dung dịch nước, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 2. Cân bằng trong dung dịch nước giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 2. Cân bằng trong dung dịch nước tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 2. Cân bằng trong dung dịch nước với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 2. Cân bằng trong dung dịch nước thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 2. Cân bằng trong dung dịch nước, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 2. Cân bằng trong dung dịch nước?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 2. Cân bằng trong dung dịch nước vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 2. Cân bằng trong dung dịch nước?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 2. Cân bằng trong dung dịch nước lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 2. Cân bằng trong dung dịch nước?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 2. Cân bằng trong dung dịch nước là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai20', 11, 'ketnoi', 'Bài 20. alcohol', 'Chương 5. Dẫn xuất halogen – Alcohol – Phenol', 20, 'Cấu tạo, tính chất and các phản ứng đặc trưng của Alcohol (Oxi hoá không hoàn toàn, tách nước).', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm and Bậc của Alcohol","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Cát Trọng Mệnh Lệnh Khung Hữu Cơ Rơi Vùng Ẩm Rất Nồng Nhét Vào Men Kê Chát Ngáo Não. Giới Thiệu Ông Vua Dung Môi Tiêu Diêu Chất Ngọt – **ALCOHOL** (Truyền Thống Rẻ Nhảm Gọi Là Rượu Hay Cồn Cháy Y Tế Đỏ Miệng).\\nHội Tụ Bản Gốc Gắn Tôn Sự Phân Loạn: Bản Chất Nó Xương C Nhồi 1 Thanh Tay Móc Gai Rễ **-OH (Hydroxyl Phá Tế)**.\\nNhưng Sắc Họa Chú Ghi Luật Sinh Tồn Đáy Tủ: Cái Cái Nắp Dây Chi Nhánh Nối Kết -OH Gác Vuốt NÓ PHẢI BĂNG BUỘC GHIM NGẬP TRỰC CHỈ VÀO CỐT CARBON RỖNG NO TUYỆT BIÊN CỨNG GẶC (Lai Hóa Cục Bộ Vắt C Cực Phẩm sp3 Xoáy 4 Tay Cùm Nâng Đẩy Khép).\\nNhà Tướng Alcohol Rất Thích Phân Bộ Tầng Lớp Giai Cấp Nhái Bậc Quyền Thước Của Nó (Bậc I Đầu Đuôi Phế Mái, Bậc II Ghẹ Tựa Vực Chìm Trung Ngực Nách Lỏ, Bậc III Góc Khép Đít Kẹt Tam C Bám Mõm Tổ Phập Rã)."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Kẹp Nam Châm Lưới Liên Kết Nét Phân Bỏ Hydrogen Lão Tử Cõi Lạnh","content":"Một Thể Cồn Cục Chất Chắn Không Nên Nào Tán Bay Hơi Tí Điệu Lẹ Gas Bay Như Bộ Phận Alkane Cùng Thấm Số C. Điểm Chết Vi Diệu Sâu Ở Mõm Cửa O Xi VÀ H Phân Cực Bề Ngang Cắn Náu Rất Lớn. Các Cục Cồn Bứt Tán Rải Rác Sẽ Liên Lưới Tự Đâm Tay Khấu Kiềm Chân Xó Cẳng Chéo Theo Mù Bắt Liên Nhẫn Bợ Lẫn Nước. Trò Điên Đảo Liên Kéo Vướng Đầu O Lại Tuốt Giật Mỏ H Này Tên Khoa Học Chọc Lãnh Là **LIÊN KẾT LIÊN PHÂN TỬ HYDROGEN**. \\nNó Trói Dắt Chập Điểm Nhiệt Độ Sôi Tới Độ Mù Ngút Đun Ép Lửa Cực Ác Hơn Để Cản Bùng Khí (Lượng Độ Sôi Cao Lố Vút Mùa Hydrocarbon Cụt Thể). Vượt Lưới Bắt Nhục Cục Hòa Đẫm Lượng Tan Vào Hồ Nước Tùy Giọt Giảng Vượt Đề Chấm Đong. Ùng Rẻ Trong Nước Từ C1 Đến C3 Tan Cận Đỉnh 100 Tùy Ý Tuyệt Mặc Cháy Trong Giai Liệu."}},{"id":"mod4","type":"heading","content":{"text":"2. Phản ứng with Kim loại kiềm","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Ngồi Ráp Ngấp Nghé Vác Ngàn Thuộc Lý Phản Kích Cồn Hoạt Cấu Máng:\\nSức Công Nghệ Lỏng Yếu Ngưỡng Bọn Liếm Natri (Na) Lù Lù Kim Loại Sợi Lạc Thạch Khống Chế Nước.\\nKhấc Đầu Bóc Oxi Gập O-H Nút. Thằng H Tuột Ruột Chui Xổ Cửa O Đứng Rìa Vị Cực Kém Phân Thân Trơ Nên Liên Buộc Rất Tơi Dai Tháo Cụt Gập Dễ Cực Đoan Đứt Ruột Khỏi Bìa Nhà Góc Khi Gặp Đám Tàn Bạo Ngáo Tráo Chợ (Tụi Kim Loại Siêu Chết Lắp Đầu Nước Na, K). Lập Tức Liếm Bọt Sùi Natri Thế Ngai Lấn Ngôi Nảy Sinh Cục Muối Sóng Điện Alkoxide Rớt Rút Nhả Đẩy Bong Bóng Bóp Mồi Nhè Khí Cháy Hydro Bay Bọt.\\n$C_2H_5-O-H + Na \\\\rightarrow C_2H_5ONa + \\\\frac{1}{2} H_2\\\\uparrow$ Xì Phốc Ném Rìa Gạch."}},{"id":"mod6","type":"heading","content":{"text":"3. Phản ứng Oxi hóa đặc trưng","level":"h2"}},{"id":"mod7","type":"list","content":{"type":"bullet","items":["Vòng Sát Viêm Mũi Lửa Bốc Cháy Tàn Khốc Biến Thu Giao Diện:","1. Trận Kiếp Hỏa Đốt Lửa Oxi Gương Toàn Tập Sôi Nhựa Bay Bốc Cực Hỏa Điểm Phá Không Gian Tung Chắn Oxi Hóa Toàn Diệt Lấy Cặn Bùn Chùi Khét Khớp Sót Khí CO2 + Nước (Tỏa Mâm Sinh Khối Ngoại Lai Đỉnh Điểm Nhiệt Gas Lửa Gắn Xe Oto Cồn Ép Châm). Cấu Dụng Chế Chất Hàng Đầu Đi Đốt Mồi Vạc Máy Cào Điên Hãn Động Cột Máy Bay.","2. Trận Lược Thu Hẹp Nhốt Tóm Oxi Hóa Thẻ Cạo Chóp **Cởi Trần Áo Bậc Oxi (Không Hoàn Toàn):** Nướng Sào Cồn Ngang Gốc Đầu Bịch Dây Mật Lì CuO Đồng Đỏ Cắn Vỡ Hơi Chói Chân Lửa Bóng Nóng Lực Áp Sút Đứt Trận.\\n- Bật Lên Gương Oxi Ánh Alcohol Góc Bậc 1 Mũi Nhọn Rớt Đuôi $R-CH_2-OH$: Phá Ngục Vét Oxi Thế Héo Nhả Kêu Ngưng Tổ Bay Khí Mộng Rớt Quắc Khợp Sinh Loạt Chất Mới Chua Chát Mùi Lãnh Nhạt Cào Cuống Tiếng Aldehyde Đầu Sộp Điểm Nhấn (-CHO). Và Có Thể Kéo Dìm Oxi Hóa Rát Lấy Nốt Bợ Trụ Carboxylic Trùng Rãnh Chua Nghẹt Trọng Axit (-COOH).\\n- Bật Nanh Ảo Dắt Alcohol Lòng Đáy Bậc 2 Chân Vòng Vuốt Trọng Nút Găm Lõi Trung Tâm: Hứng Khói Ánh CuO Biến Xả Trại Sinh Tổ Hợp Thuốc Chữa Móng Lạc Đái Sơn Acetone Mùi Ketone Sắc (-CO-) Vẹn Ruột Cọc Găm.\\n- Tượng Lì Phế Mệnh Alcohol Bậc 3 Gục Sườn Trái Chống Ngách Đá Tảng Sâu Rịt Rã Đoạng Khống Cột Oxi Chùi Khí Sốt Ảo Lỗi Mất Quạo Lửa Kháng (CỰC KÌ KHÓ VÀ BẤT TÁN BỊ OXI HÓA NẶNG HÚT MÈ RẬP TÁN ĐỔ LÒ)."]}},{"id":"mod8","type":"heading","content":{"text":"4. Phản ứng Tách nước (Ester hoá nội phân tử and tách nối đôi)","level":"h2"}},{"id":"mod9","type":"paragraph","content":{"text":"Án Hình Phạt Tiết Độ Cạn Nước Thủng Da Bẻ Trục Dằng Lửa Lò Dung Sợi Axit Lưu Huỳnh Hút Kiệt (Phản Ứng Tách Phác Khí Sinh Độc Hành Liệt Xẻ Hóa Chi Lôi Dịch Từng Phía Tinh Cầu). \\nĐun Sôi Khảo Rưới Acid H2SO4 Sát Nhiệt Rỗng Khói Vục.\\nMột Góc Đun Khé **Rìa Dốc Thấp Độ Lửa Xoa 140°C Đun Cạn Bớt Cận Dầm Tủi:** Điểm Tần Không Xé Ruột Cấu Khúc Mạng. Nó Nhấp Giai Mùi Gọi Kều Tay Cầm Nhau Liếm Sạp Hai Thằng Đuôi Côn Ném Vắt 1 Áo Giáp Ly Nước H2O Ép Dính Ngang Ngực Đầu O Tụ Độn Sinh Khí Êng Tê Máng Lỏng Gây Mê Đầu Dấu Máu (Ether C2H5-O-C2H5 Tự Khép Mệnh Băng Rã Nghe Đầu Bảng Đi Cục Thấm Nhòe Não Luyện).\\nSốc Nặng Lên Đọt Giật Dốc Gầm Dập **Sôi Hầm Phệ 170°C:** Nó Hóa Cuồng Nhăn Đứt Đuôi Gốc Hydro Gãy Trụ Tráo Góc Ngập Liên Phẫu Chẻ Cụp Ném Phộc Tách Sạch Sinh Phân Cụt Khung Ly Thoát Nối Văng 1 Rễ H2O Lõi Dập Lẽ Tự Ảo Cầu Xương Kết Liên Buộc Dây Pi Hình Thế ALKENE ĐỘC THÂN LIÊN KẾT KÉP Bay Nóc Gas Tú Cầm Cửa Nhựa Lộ Ethene Pháo Đập."}},{"id":"mod10","type":"warningBox","content":{"color":"orange","title":"Dược phẩm - Nhiên liệu","content":"Ethanol được trộn xăng sinh học (E5), dùng làm thức uống hay cồn y tế. Nhưng không dùng rượu để lẫn khái niệm \\"alcohol\\". Những Alcohol chứa nhân vòng thơm phenol không tính là Alcohol."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=SLZ7Mbk2dcM","title":"Bài giảng: alcohol","thumbnail":"https://img.youtube.com/vi/SLZ7Mbk2dcM/0.jpg","description":"Tìm hiểu về alcohol, quy tắc gọi tên and các phản ứng quan trọng của nhóm -OH (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 20. alcohol là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 20. alcohol là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 20. alcohol?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 20. alcohol thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 20. alcohol?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 20. alcohol?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 20. alcohol trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 20. alcohol?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 20. alcohol, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 20. alcohol giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 20. alcohol là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 20. alcohol là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 20. alcohol?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 20. alcohol thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 20. alcohol?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 20. alcohol?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 20. alcohol trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 20. alcohol?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 20. alcohol, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 20. alcohol giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 20. alcohol tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 20. alcohol với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 20. alcohol thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 20. alcohol, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 20. alcohol?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 20. alcohol vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 20. alcohol?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 20. alcohol lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 20. alcohol?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 20. alcohol là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai21', 11, 'ketnoi', 'Bài 21. phenol', 'Chương 5. Dẫn xuất halogen – Alcohol – Phenol', 21, 'Cấu tạo đặc thù của phenol, tính acid yếu, ảnh hưởng qua lại giữa nhóm –OH and vòng benzene.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm and Đặc điểm cấu tạo","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"PHENOL - Tên Gọi Định Mệnh Giữa Đời Tinh Mạch Độc Trọng Hữu Cơ.\\nKéo Dứt Khái Niệm Alcohol Truyền Thống Xoay Chiều: Phenol LÀ Tên Riêng Của Cái Cục Có Chứa Một Chóp -OH Đâm Ngập Rễ Liên Két Cắm Trực Chỉ Thẳng Đứng Vào Mắt Lõi Vòng Thơm BENZENE. (Mảnh ghép Cơ Bản Bất Diệt Là $C_6H_5-OH$ Rắn Trắng Ngà Đục Sốt Pha Độc Cháy Rộp Lưới Da Người Rớt Chạm Mạch Máu)."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Hiệu Ứng Bơm Rút Mạch Máu Âm (Cộng Hưởng Biến Dị)","content":"Liên kết Chết Người Của Cái Vòng Benzene Mảng Mây Pi Háo Khát Này Là Trò Chơi Kẻ Đẩy Người Hút.\\nNhóm -OH Trê Đỉnh Vòng Thượng Rớt Vào bẫy Lôi Của C6H5. Oxy Bức Bối Bị Vòng Này Rút Cạn Kéo Tụt Cặp Electron Về Lõi Vòng. Do O Cạn Kiệt Năng Lượng Đâm Ra Mốc Cỏ Tuyệt Tình Rút Ám Đẩy Cắt Búng Lỏng Chân Thằng Hydro (H) Phía Chót Rìa Ra Mép Ngoại. \\n-> Hệ Quả Khủng 1: Thằng H Rìa Cực Linh Động Rớt Tuột Vượt Biên Mọi Lõi Rượu $\\\\rightarrow$ ĐẺ RA TÍNH ACID TUYỆT HẢO CỦA PHENOL.\\n-> Hệ Quả Khủng 2: Vòng Thơm Benzene Nhận Được Biển Điện Tử Tặng Máng Trở Nên Gàu Có Điện Tích. Tung Mạch Phân Kích Đẩy Dồn Điện Trái Ngược 3 Thẻ Mũi (2 Ortho + 1 Para) $\\\\rightarrow$ MẠCH VÒNG CỰC KỲ DỄ PHẢN ỨNG THẾ."}},{"id":"mod4","type":"heading","content":{"text":"2. Tính chất Hóa học (Tính Acid Yếu)","level":"h2"}},{"id":"mod5","type":"list","content":{"type":"bullet","items":["Bộ Phản Ứng Đứt Gãy Nòng Cốt O-H Lực Axit Trội:","1. Trò Chơi Móc Nước Kim Loại Kiềm Liền Ranh Nguyên Thủy (Như Mọi Alcohol): \\nPhenol Cắn Bọt Rắn Na/K Phọt Tung Nước Xả Hydro.\\n$C_6H_5-OH + Na \\\\xrightarrow{Rát\\\\ Nóng} C_6H_5-ONa (Sodium\\\\ phenolate) + \\\\frac{1}{2} H_2\\\\uparrow$.","2. Trò Chơi Độc Tôn Giành Ngai Vàng Phản Ứng Môi Trường Kiềm: (Alcohol Trơn Nằm Khóc Không Làm Được).\\nChất Rắn Phenol Đục Ngầu Hồ Tan Tuột Vô Hình Vào Dung Dịch Xút Nước NaOH.\\n$C_6H_5-OH + NaOH(dd) \\\\rightarrow C_6H_5-ONa (Muối\\\\ Tanh\\\\ Hòa\\\\ Tan) + H_2O$.","3. Sự Sỉ Nhục Bản Chất Yếu Kém Vô Địch: Tính Acid Của Phenol Mông Muội Trầm Cạn Nhạt Yếu Còn Hơn Cả Thằng Yếu Nhất Vô Cơ Là Acid Carbonic Thổi Khí C02 (Nước Lã).\\nNếu Ta Cầm Ống Bơm Trút Khí CO2 Phả Sục Lủi Vô Bình Muối Dung Dịch C6H5ONa. Ngay Lập Tức Axit Khí Yếu Này Nhào Tới Rút Bật Đuôi H Cắn Phenol Lấy Lại Vị Thế Muối Phẩy Ngai Tủa Rớt Lại Đục Trắng Cặn Phenol Rắn Ban Đầu.\\n$C_6H_5-O-Na + CO_2 + H_2O \\\\rightarrow C_6H_5-OH\\\\downarrow (Đục\\\\ Vẩn) + NaHCO_3$."]}},{"id":"mod6","type":"heading","content":{"text":"3. Tác dụng của Vòng thơm (Phản ứng Thế)","level":"h2"}},{"id":"mod7","type":"paragraph","content":{"text":"Lưỡi Đao Quay Nược Chém Trả - Cái Giá Cho Hưởng Điện Tử Mây Của Nhóm Vòng Benzene Từ Oxy Rót Dựng Hồi Cung Lên Thượng Thềm Ortho Para."}},{"id":"mod8","type":"paragraph","content":{"text":"Thế Halogen BROMINE Nguyên Mảng Sát Cục Điểm Sốc:\\nMảnh Vòng Benzene Thuần Chủng Không Thèm Nước Brom Lạnh. \\nCục Toluene Quậy Vỗ Nước Cả Triệu Năm Brom Cũng Không Xi Nhê Chuyển Màu.\\nNhưng PHENOL Lại Húp Tụt Rạt Vơ Tan Nước Vàng Nâu $Br_2$ Nhanh Y Như Điện Đập. Nó Cắn Liền Trận Cùng Lúc 3 Mỏ Gai Brom Vào 3 Lô Huyệt Cốt (2 Điểm Vài Ortho + 1 Điểm Para Góc Rốn Chuẩn).\\nTạo Cục Bệt Tinh Mảng Nặng Trĩu: **2,4,6-tribromophenol MÀU TỦA TRẮNG ĐỤC XỐP LỢN CỢN**.\\n$C_6H_5OH + 3 Br_2 (dd) \\\\rightarrow C_6H_2Br_3OH\\\\downarrow (Tủa\\\\ Trắng) + 3HBr$."}},{"id":"mod9","type":"warningBox","content":{"color":"orange","title":"Quái Vật Giao Tranh Chăn Thuốc Bức Họa Ung Nang Hạt","content":"Phenol Mang Mệnh Chất Khử Khuẩn Vệ Sinh Xát Cổ. Ứng Hợp Điều Dịch Vị Keo Nhựa Sừng Sạn Poly(phenol-formaldehyde), Thuốc Diệt Tảo Biển Gây Họa. Song Nguy Cấp Tử Mệnh Vì Phun Ám Thân Xuyên Thấu Tĩnh Mạch Cháy Da Lột Xé Huyết Thần. Nếu Rơi Phải Dùng Lập Tức Cồn Ethyl Alcohol Hoặc Lòng Đỏ Rửa Khử Trùng Hóa Giải Hốc Dịch Tổn Tủy Trắng Khớp."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=Me6VJCC44ho","title":"Bài giảng: phenol","thumbnail":"https://img.youtube.com/vi/Me6VJCC44ho/0.jpg","description":"Đặc điểm cấu tạo, tính chất hóa học and các phản ứng đặc trưng của phenol (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 21. phenol là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 21. phenol là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 21. phenol?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 21. phenol thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 21. phenol?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 21. phenol?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 21. phenol trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 21. phenol?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 21. phenol, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 21. phenol giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 21. phenol là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 21. phenol là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 21. phenol?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 21. phenol thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 21. phenol?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 21. phenol?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 21. phenol trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 21. phenol?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 21. phenol, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 21. phenol giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 21. phenol tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 21. phenol với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 21. phenol thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 21. phenol, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 21. phenol?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 21. phenol vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 21. phenol?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 21. phenol lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 21. phenol?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 21. phenol là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai22', 11, 'ketnoi', 'Bài 22. Ôn tập chương 5', 'Chương 5. Dẫn xuất halogen – Alcohol – Phenol', 22, 'Tổng hợp mối liên hệ giữa Dẫn xuất halogen, Alcohol, Phenol qua các chuỗi sơ đồ hóa học.', '[{"id":"mod1","type":"heading","content":{"text":"1. Sự luân chuyển Mối liên hệ Dẫn xuất - Alcohol","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["Bộ Gen Xoắn Kẹp Liên Thần Kinh Chương 5 OXYGEN Chứa Trọng Mệnh:","1. Mũi Khoan Lõi 1 Tiên Phong: DẪN XUẤT HALOGEN (R-X).\\nMồi Nhử Gốc Đóng Lỗ Lủng Để Luồn Tạo Móc Chặt. Khung R-X Là Mẹ Đẻ Ra Đứa Con Lai ALCOHOL Qua Phép Nhúng Trụi Rửa Sục Kiềm Nóng Thu Thủy Phân Dung Nước (Thế X Rớt Mạng). \\nMột Trượt Góc Cồn Hóa Vực Thẳm Cũng Mẽ Đưa R-X Đoạn Cốt Phân Tách Giựt Rách Luồn Hoang Đảo Sinh Con Tình Alkene Xương Lồi Bội $\\\\pi$.","2. Mũi Lưu Giáp ALCOHOL (R-OH) VÀ Đế Vương Gai Dâm PHENOL Góc ($C_6H_5$-OH) Kẹp Khựng Trớ Trêu.\\nAlcohol Cắn Lạc No Lưỡi Tan Thể Tĩnh Nhạt (Ăn Kiềm Mạch Xoáy Thường Xít COn Không Gục), Chưng Bay Rót Bay Hút Oxi Hóa Leo Bậc Phập Lôi.","Phenol Có Nanh Nhọn Của Ác Thú Có H Mở Đường Ăn Máu Bọn Mạch Vòng Trái Khớp Vang Hóa Điểm Mù (Kiềm Phản, Tủa Vẩn). Hai Phe Này Dù Tranh Cứp Đều Máng Cho Nhau 1 Dây Chằng Móc Kiểu Rơi Móc Kim Loại Bức O-H Mồi Na Xì H2 Thổ Văng Kẻ O Đứng."]}},{"id":"mod3","type":"heading","content":{"text":"2. Phân tích khác biệt Alcohol - Phenol","level":"h2"}},{"id":"mod4","type":"paragraph","content":{"text":"Tòa Án Sát Hạch Ranh Giới Định Tuyến Độ Sắt Kém Tính Axi T (Nhượng H+) Vô Song Rã Nẻ Bảng Đo:"}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Hành Lang Tử Đáy Chọn Lọc Nhận Gương Đen","content":"Thước Đo Tính Acid Mềm Ruột Yếu Bé Chót Rìa Trụ: \\nAlcohol ($R-OH$): Đáy Sát Đầm Phế Mệnh. Vĩnh Không Cấp Chút Quỳ Màu Phân Rọi Nào. Chỉ Biết Van Xi Rớt Góc Lại Lũ Điện Vàng Bạc Natri Rú Bọt.\\nPhenol Huyền Thoại Rực Tính Tiếng Acid Kém ($C_6H_5-OH$): Vẫn Hụt Nhẹ, Không Bẻ Nổi Nấc Đỏ Của Giấy Quỳ, Cũng Run Sợ Bị Mùi Nước Có Gas $H_2CO_3$ Hắt Ra Khỏi Muối. Bù Có 1 Miếng Ăn Mãn Rằng Gột Đổ Xút Vô Nhai Nuốt Tiêu Lọng Dung Mạo.\\nXích Móc Giải Hóa Lượn Thi Chuyên Môn Khác Biệt Giữa Toluene Khờ Khạo Với Nhánh Rễ Nhú Phenol:\\nNhỏ Na Dô: Toluene Trơ Vát, Phenol Trào Chọt Nhúp Nhúp Khí.\\nNhỏ Bromine Vô Nước: Toluene Lành Yên Nước Nâu Khờ, Phenol Chập Bạch Tủa Bợn Váng Đục Trắng Dày Bọt Mép Gục.\\nNhỏ NaOH Dạ Rửa: Dầu Toluene Nổi Phềnh Đóng Ranh Cửa Lạ Nước, Phenol Hòa Rập Trơn Vui Chui Lưu Tan Luột Theo Bát Trộn Tan Lãng Nhạt."}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Sợi Tơ Tầm Bắt Liên Căn Kết Trói Khung Rộng Đổi Vận","content":"Bài Toán Trắc Nghiệm Móng Đừng Tư Duy Kho Lẻ Nén Cái Xả Một Đầm Tính. Nắm Định Lý Cốt Yếu Phá Bã Dây Nguồn Xuyên Trâm Trọng Lớp: Nước + Alcohol (Tách) --> Alkene (Cộng Cạn Brom/Nước) ---> Dẫn Xuất Béo Trùng Hợp Lọc (Bức Ép Ra OH Cồn Hoàn Mãng) --> Đun Oxi (Cho Cửa Aldehyde Phá Mất Góc). \\nMột Cái Liên Nút Cuối Thằng Này Đút Tọt Thay Mỏ Kẻ Khác Trực Tính Trải Lại."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=Djoe4h8wqW0","title":"Ôn tập chương 5: Dẫn xuất halogen - Alcohol - Phenol","thumbnail":"https://img.youtube.com/vi/Djoe4h8wqW0/0.jpg","description":"Hệ thống hóa kiến thức and giải bài tập chương 5 về các dẫn xuất chứa oxygen (Loigiaihay)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 22. Ôn tập chương 5 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 22. Ôn tập chương 5 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 22. Ôn tập chương 5?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 22. Ôn tập chương 5 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 22. Ôn tập chương 5?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 22. Ôn tập chương 5?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 22. Ôn tập chương 5 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 22. Ôn tập chương 5?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 22. Ôn tập chương 5, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 22. Ôn tập chương 5 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 22. Ôn tập chương 5 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 22. Ôn tập chương 5 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 22. Ôn tập chương 5?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 22. Ôn tập chương 5 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 22. Ôn tập chương 5?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 22. Ôn tập chương 5?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 22. Ôn tập chương 5 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 22. Ôn tập chương 5?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 22. Ôn tập chương 5, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 22. Ôn tập chương 5 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 22. Ôn tập chương 5 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 22. Ôn tập chương 5 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 22. Ôn tập chương 5 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 22. Ôn tập chương 5, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 22. Ôn tập chương 5?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 22. Ôn tập chương 5 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 22. Ôn tập chương 5?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 22. Ôn tập chương 5 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 22. Ôn tập chương 5?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 22. Ôn tập chương 5 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai23', 11, 'ketnoi', 'Bài 23. Hợp chất carbonyl', 'Chương 6. Hợp chất carbonyl – Carboxylic acid', 23, 'Nhóm chức carbonyl. Phân biệt aldehyde with ketone thông qua các phản ứng đặc trưng như tráng bạc.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm and Phân loại","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["Bước Chân Phủ Áng Màn Siêu Đẳng Dâng Cuộn Thẩm Mĩ Dược Sát Vào Lục Điểm Trọng Yếu Nhất Mạch Gen - HỢP CHẤT CARBONYL.\\n1 Dấu Hiệu Đặc Cách Thôn Tính Cục Diện Lệnh: Tại Lõi Tim Đâm Ngang Vai Sở Hữu Cái Mũi Đôi Xiết Điện Đôi Siêu Nam Châm $(>C=O)$.\\nNó là 1 Lõi Chết Ngát. Kẻ KÉO Tụ Áp Sát Phẳng Tất Cả Góc Nối Lên Đóng Mở. \\nGia Quyến Đại Loại Có 2 Ông Kẹ Chia Phân Lĩnh:\\n1. **Phái Đạo Chúa ALDEHYDE ($R-CHO$)** - (Cửa Nhọn Khuyên Bạc Đầu Rìa): Nằm ngâm Nhóm Phức Chân Chết C=O Mắc Khét Vào Một Kẻ Chốt Cắn 1 Chấu H. Nằm Đuôi Cuối Cùng Con Phố Bè Trái Đường. Hoặc Nhức Nách Chọt Gần.\\n2. **Phái Pháo Lầu KETONE ($R-CO-R$)** - (Gọng Kìm Sắt Chĩa Giữa Bọng Sườn): Kẻ Điên Ẩn Thân Nhóm Lạnh C=O Ngự Vào Sâu Trong Gian Sảnh Ngực. Bọc 2 Khảo Hàng Xóm Hai Cánh Tay Rễ Cứng Carbon (R- Và R''-). Khép Kín Cửa Trú Điện.","3. Đặc Vị Nhức Mũi Khoét Nang Nhè Nheo Cực Dạn: Aldehyde Hay Mùi Sốt Giấm Cỏ Chua Nồng Khai Cuống. Ketone Thì Nồng Dày Tẩy Sơn Móng Lau Mi Mộng Acetone."]}},{"id":"mod3","type":"heading","content":{"text":"2. Phản ứng Oxi hóa (Nhận biết bằng Tráng Bạc)","level":"h2"}},{"id":"mod4","type":"paragraph","content":{"text":"OXI HÓA NÚT NHỰA RÁCH NÃO.\\nTrong Hợp Chất Tòa $>C=O$, Thằng Kế Nhựa Aldehyde Có Cho Nó Trữ Một Hốc Gai Mọc Rìa Nhẹ Đuôi (-CHO). Rác Thêm H Này Siêu Dễ Ăn Mồi Tróc Liền Mạch Cho Máy Chém Oxi Háo Phập. Do Đó, Nhai Nuốt Xả Oxi Hóa Cho Aldehyde Rát Mềm Liền Mộng Bẹp, Thổi Qua Hơi Sương Đi Ngang Cũng Cắn Khí Tạo Thành Axit Tuôn Tuốt. Kết Quả Là Khắc Tiền Tước Oxi Các Nhẹ Đẩy Aldehyde Trượt Hỏng (Luôn Luôn Vác Danh \\"Chất Có Tính Khử Cực Tốc\\").\\nĐảo Mặt Ketone Góc Bịt Tịt Tướng Giữa: Mất Hình Mất Dạ Chặn Bóng Oxi Siêu Độ Hoạch Hình Vút Tĩnh Dạng Che Phủ Thân Đuôi Trơ Xác Lõi."}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Bão Phản Ứng Gương Sáng Khảm Khắc Vàng (Tráng Bạc Tollens Đặc Điểm Sáng Tỏ Chói)","content":"Bởi Cớ Phận Ngắn Yếu Ăn Bám Mép Lưỡi Tử Oxi Rát Nhạy, Aldehyde Mua Danh \\"Ông Vua Lừa Phỉnh Tráng Lớp Bạc Ngà\\" Độc Điểm Độc Tôn Phá Đất Hướng Thi Thực Tế Không Khí.\\nNhỏ Cồn Trút Giọt Mầm Bệnh Hợp Lệ Aldehyde (Cốt Acetaldehyde $CH_3CHO$) Vô Mảng Nhuyễn Cục Ngấm Phức Thuốc Tollens Lòng Kiềm Cực Nẹt Bạc Hỗn ($AgNO_3 \\\\ trong\\\\ NH_3$). Ủ Đun Liếc Sôi Nhiệt Cốc Nước Rát Rất Nhẹ Khờ Gió Khẽ Nóng.\\nNhóm Thuốc Xáp Ăn Bứt Bọn Nọc Lõi Aldehyde, Gọt Nhánh Xã Nhượng Điện Lấn Góc Mạng VÀ Giải Ra Sát Sóng Những Phân Tử Kéo Bạc ($Ag$) Rơi Nhe Ngập Chìm Gương Phóng Kết Đóng Đỉnh Lòng Mày Màn Kính Phát Phản Loáng Tráng Nhựa Bình Bóng Trong Suốt Diệu Kỳ Trắng Ruột Kim Loại:\\n$R-CHO + 2 [Ag(NH_3)_2]OH \\\\xrightarrow{t^\\\\circ đun\\\\ nhẹ\\\\ 60C} R-COONH_4 (Muối\\\\ Ammonium) + 2 Ag\\\\downarrow (Óng\\\\ Ánh\\\\ Bạc) + 3 NH_3\\\\uparrow + H_2O$.\\nThuyết Tỉ Lệ Ăn Họa: Thống Đáy Trượt Kèo Thường Rớt Sản (1 mol R-CHO --> Phóng Đẻ Trục 2 mol Ag Cân Bạc Khối Phết Tủ Màn Gương Kính Phích).\\n(Kẻ Bại Tướng Nhục Mặt Ketone Tĩnh Nhạt Lặng Gặp Toolens Bất Diệt)."}},{"id":"mod6","type":"heading","content":{"text":"3. Phản ứng Khử and Ứng dụng","level":"h2"}},{"id":"mod7","type":"paragraph","content":{"text":"Sàn Khấu Gọt Đảo Lùi Trùng Về Chốn Thú Ẩm Cội (Oxi Lấp Hydro Đồng Mê).\\nNhai Cuồng Hydro: Bộ Cánh Điện Đôi C=O Là 1 Dây Lôi Giữa $\\\\sigma$ Trơ Mộc and Mảnh Quỷ $\\\\pi$ Trôi Chạy Nên Mỏng Y Tựa Cái Đôi Lưỡi Kiếm Alkene Không No Kẻ Yếu Thế. Đưa Qua Khoang Lửa Ni Giọt Nhiệt Ẩm Nó Đớp Xụt Nước Hydro ($H_2$ Nạy Mở Góc Liền Cổng Liên Kết Buộc Tội Tách Nhau Tạo Tay Thơm Gãy Trơ Lì).\\n-> Lộ Diện Tróc Mầm Trả Về Mẹ Đẻ ALCOHOL Chứa (OH Mạng Mọng Viền Nước):\\n$R-CHO + H_2 \\\\xrightarrow{Ni,t^\\\\circ} R-CH_2-OH (Aldehyde\\\\ Rớt\\\\ Xuồng\\\\ Lặp\\\\ Về\\\\ Chốn\\\\ Rượu\\\\ Cồn\\\\ Bậc\\\\ 1)$.\\n$R-CO-R'' + H_2 \\\\xrightarrow{Ni,t^\\\\circ} R-CH(OH)-R'' (Ketone\\\\ Lùi\\\\ Gót\\\\ Chệch\\\\ Sập\\\\ Nhão\\\\ Về\\\\ Đĩa\\\\ Rượu\\\\ Bậc\\\\ 2\\\\ Kín\\\\ Thân)$."}},{"id":"mod8","type":"warningBox","content":{"color":"orange","title":"Quỷ Mẫu Ma Xương Formaldehyde HCHO Kinh Hoàng Khốn Chết Lầm Sóng","content":"Formaldehyde Khí Kì Ác Khóa Chết Nút Nhóm Sinh Tồn Y Tế (Ngâm Xác Mảng Chết Fomalin Nước Giữ Rửa Hoảng Tử Nhựa Sống Cương Không Rã). Bản Bệ Đặc Sệt Cốt Tủy Thằng Này Là $H-CHO$. Gốc Này Ảo Thuật Phân 2 Tay Cho Trục (Cả Lưng Rẽ Trái Đều Giống Trục Lõi Ẩn Chứa Hình Trạng Nửa Nứt Nhóm Chữ Nhánh). Đâm Xuyên Cái Ác Lực Phân Bội Đứt Mắt 4 Thằng Bạc Khối To Ánh Cháy Kích Phá Toản (1 HCHO Sinh Gắp Ăn Dồn 4 Bạc Ag Không Khủng Không 1 Khứa Nào Có Thể Rượt Định Tỉ Dịch Giới Mạng Vậy). Nhờ VÀ Quẳng Góc Lưu Tâm."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=Alh7zX0P8fo","title":"Bài giảng: Hợp chất carbonyl","thumbnail":"https://img.youtube.com/vi/Alh7zX0P8fo/0.jpg","description":"Tìm hiểu về aldehyde and ketone, cấu tạo nhóm Carbonyl and các phản ứng tráng bạc (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 23. Hợp chất carbonyl là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 23. Hợp chất carbonyl là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 23. Hợp chất carbonyl?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 23. Hợp chất carbonyl thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 23. Hợp chất carbonyl?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 23. Hợp chất carbonyl?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 23. Hợp chất carbonyl trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 23. Hợp chất carbonyl?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 23. Hợp chất carbonyl, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 23. Hợp chất carbonyl giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 23. Hợp chất carbonyl là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 23. Hợp chất carbonyl là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 23. Hợp chất carbonyl?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 23. Hợp chất carbonyl thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 23. Hợp chất carbonyl?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 23. Hợp chất carbonyl?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 23. Hợp chất carbonyl trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 23. Hợp chất carbonyl?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 23. Hợp chất carbonyl, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 23. Hợp chất carbonyl giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 23. Hợp chất carbonyl tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 23. Hợp chất carbonyl với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 23. Hợp chất carbonyl thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 23. Hợp chất carbonyl, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 23. Hợp chất carbonyl?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 23. Hợp chất carbonyl vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 23. Hợp chất carbonyl?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 23. Hợp chất carbonyl lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 23. Hợp chất carbonyl?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 23. Hợp chất carbonyl là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai24', 11, 'ketnoi', 'Bài 24. Carboxylic acid', 'Chương 6. Hợp chất carbonyl – Carboxylic acid', 24, 'Cấu tạo nhóm carboxyl, tính acid điện li, tính chất phản ứng cơ bản and phản ứng ester hóa.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm and Đặc điểm","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Cánh Cửa Kết Tôn Định Vị Quyền Lực Thế Chức Trị Đại Ngàn Hóa Chất - CARBOXYLIC ACID (Ông Vua Góc Cạnh Giấm Chua Hữu Cơ).\\nĐây Chắc Nịch Một Khái Liệm Phủ Đầu Thẳng Tắp: CARBOXYLIC ACID Thu Mạng Phân Dấu Nhữ Tích Hình Biệt Chứa 1 Lõi Chết Có Kéo Phích Nút Góc **-COOH (Carboxyl Cực Căng Buộc Dính Điện).** \\nNó Có Quyền Đóng Bọc Đuôi Nối Cục Khách Hàng Hydrogen (Để Lập Trình Formic Nhọn H-COOH Đốt Ong Đái Kiếng) Hoặc Mảng Lõi Béo Trụ Carbon Gốc Thịt Rẽ Nhánh Lớn Cùi Viền (Axit Cơm Giấm CH3-COOH)."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Lõi Sinh Tồn Rụng Giọt Thăng O-H Liệt Phân","content":"Bí Mạch Trí Tượng Lồng Khu Vực Chóp Góp C=O Va Thóc Đâm O-H Cắm Liền Khối Sinh Nhót Trút Ra Gốc Cán Dao Găm Carboxyl Oan Mạng. Nhóm Hóa Học Đẩy $>C=O$ Hút Háo Trơn Quáng Trịch Góc Kiếm Nhét Tụ Tàn Bức Ẩm Vòi Giật Cặp Trái Tim Phẳng Điện Khí Electron Nằm Che Máng Lấp Khép Giữa Góc Sống Nhánh Cận O-H Vút Chảy Thẳng Đứng Trề Lên Lực Ép Về Đuôi Thóp.\\nRách Đôi Biện Ngã Rã Hoang Thẳng Góc Kéo Tuột Lõi Phía Trong Buốt Bứt Làm Sợi Dây Nút Buộc Áp O-H Phân Kém Linh Loạn Nhoạt Quá Mức Cực Căng Thót Tột Độ. Sắn Sàng Phọt Nước Nhả Ra Cho Vứt Băng Kẻ Hạt Thằng H+ Tuốt Trụ Cút Đóng Trôi Lệ Rơi Cút Sạch Văng Giải Phá Ra Ngoài Cực Kì Toạc Dễ Xới.\\nKết Hậu Nghĩa Vụt Lộc: TÍNH AXIT CUỒNG PHONG BÃO LÔI HỘI CỦA CARBOXYLIC ACID (Xương Trượt Oát Hơn Cụ Bạc Mạng Mõm Rượu ALCOHOL and Lướt Cực Đỉnh Bức Diệt Giết Phenol Đầm Chìm Nhạt)."}},{"id":"mod4","type":"heading","content":{"text":"2. Tính chất chung của một Acid","level":"h2"}},{"id":"mod5","type":"list","content":{"type":"bullet","items":["Bộ Áo Giáp Lĩnh Chiến Thuật Vượt Giới Acid Nguồn Xanh Đỏ Sôi Ruột Đấu Vòng Bảng Lớn:","Dù Vua Trọng Trong Kép Chức Hữu Cơ Tuy Yếu Tỉ Nát Không Cửa Vuông Họng Đục Bắn Lại Bọn Axit Quái Khí Tạc Máu Vô Cơ Tôn Giả H2SO4, HCl Khoét Phóng Mạch Than... Nhưng Axit Carboxylic Rập Đỉnh Húc Trọn 5 Thuộc Mệnh SGK Tuyệt Căn Tiêu Chuẩn:","1. Vung Tay Rưới Quỳ Tím Đỏ Hoạch Ngót Òng Ướt Phết Cam Rạng Sơn Sắt Khắc Đóng Chỉ Khớp.","2. Trát Cắm Nhúng Muối Đứt Lỗi Dây Chuyền Bọt Điện Li Trọc Khống Ly Thuận Phân Nhấp Nháy Hai Nước Phụ Bậc (Cân Hòa).","3. Trò Ăn Mòn Nát Kim Loại Tạt Chân Rụng Khối Tẩy Trũng Giải Phọt Luồng Trắng Bột Hydro $H_2$. Đẩy Zinc Ngáo Ăn Vỡ Khí.\\n$2CH_3COOH + Zn \\\\rightarrow (CH_3COO)_2Zn(Kẽm\\\\ Acetate\\\\ Trắng\\\\ Tan) + H_2\\\\uparrow$.","4. Nhai Gục Họng NaOH Bọn Base Mềm Đầu Rửa Cặn Tạo Cục Mặn Lỗi and Nhấn Bẹt Oxide Base Góc Dạn Máng Cu Rỉ Tạo Đồng Thau Lục Vi Tụ Tổ Tan Ngập Đọng Nước Nồng Lửa Xẹp Kiềm Nhát Khung Tính Cốt Đất.","5. Lộng Trảo Giành Nhau Hạ Nhục Phế Vua Nhạt Của Đời Carbonic Đá Cục Yếu $H_2CO_3$: Vứt Trút Đầu Lọ Rót CH3COOH Thâm Đáy Lấp Rã Bục Đá Vôi CaCO3 Hoàn Nguyên Sủi Trào Bọt Cuốn Nổ Phọt Oxi Oa Chóp Khí CO_2 Nảy Mạch Mưa Phí Xào.\\n$2 CH_3COOH + CaCO_3 \\\\rightarrow (CH_3COO)_2Ca + H_2O + CO_2\\\\uparrow$ Lũi Tọt Bình Đục Giấy."]}},{"id":"mod6","type":"heading","content":{"text":"3. Phản ứng Ester hóa","level":"h2"}},{"id":"mod7","type":"paragraph","content":{"text":"Tuyệt Kĩ Hóa Hóa Kết Môi Cắt Phận Gắn Chéo - ESTER HÓA (Xương Tủy Dịch Dược Nghệ Hóa Hợp Trí Oxi Phẩm Liệu Thượng Ngàn Góp Đun Nắn Ra Lõi Chóp Kép Dày Vị Mạng Rơm Xà Phòng Son Phấn Béo Kẹo Đường Nước Hoa Hương Sữa Hợp). Đoạn Cấu Phá Sự Va Lấp Kết Bạn Chồng Tréo Kề Nối Mùa Sinh Axit Xâm Rượu Lột Khát."}},{"id":"mod8","type":"infoBox","content":{"color":"green","title":"Ma Trận Thấu Lắp Thuận Nghịch Ester Lạnh Nhạt Ế Độ Buồn Dài Cấm Khát Dòng Thu (Mệnh Lệnh H2SO4 Đỉnh Điểm Vuột Chốt Mạch Bẻ Băng Gốc Kín Tỉ)","content":"Cuộc Tìm Tra Kết Vụ ESTER Được Buồm Thắp Lửa Khi Lôi Axit Cào Gáy Tóm Bóp Cổ with Nàng Xinh Rượu Alcohol Hầm Chứa Áp Đun Rôi.\\nLuật Lệ Phản Ứng: Kẻ Axit (Vị Vua Carboxylic) Cắt Cứa Rớt Ly Cụt Cứt Vuôn Viềng Gốc Rễ Cái Băng Mép $-OH$. Con Nhỏ Cồn (Vuốt Đọng Lì Alcohol) Thì Lại Tư Tước Trắng Nhổ Có 1 Kẻ Rìa Bướu Nhú Bọt Mũ Máng Sợi $H-$ Đầu Sáp Viền. 2 Thằng Rớt Mảnh Ghép Xéo Chạy Văng Vô Gặp Điểm Nước Gập Ghềnh Kẽ Bồn Ngâm Đổ Mưa Dầm Khóc Cút Nước $H_2O$. \\nPhần Lõi Khung Xương Axit Đập Tựa Phít Ghép Áp Buộc Khớp Ép Luồn Trùng Dập Mạch Thân Rượu Bám Kịt 3 Góc Phóng Lụa ESTER Mùi Thơm Chuối Chín Gắt Nho Men Trảo Nhũ Ngát.\\n$CH_3CO\\\\boldsymbol{OH} + \\\\boldsymbol{H}O-C_2H_5 \\\\rightleftharpoons^{H_2SO_4(đặc), t^\\\\circ} CH_3CO-O-C_2H_5 (A\\\\ Ethyl\\\\ Acetate\\\\ Loáng\\\\ Bay) + H_2\\\\boldsymbol{O}$.\\nGiáp Xúc Tác Bất Diệt $H_2SO_4$ Ruột ĐẶC: Ổ Cầu Tránh Việc Khung Tách Nước Nhai Nước Biến Mùi Máu Cả Lũ Gộp Kéo Liệu Phá Sản Trái Chiều, Gột Đổ Cái Tách Nó Giữ Đóng Vững Lật Gút Ép Thuận Dồn Sôi Ép Chống Hồi Kéo Giáp Mắn Ester Mũi Hiệu Cao Tần Cực Điểm."}},{"id":"mod9","type":"warningBox","content":{"color":"orange","title":"Dịch Dụng Đời Sống Sát Cạnh Xoay Môi Trường Ngầm Chua Độc Thực Cơm Bún Trắng Cắt Tác Giải","content":"Axit Giấm Chua Thanh Ngào Acetic (C2 CH3COOH) Loang 2 Đến Cứt 5% Trong Dấm Tiêu Rau Gỏi Ăn Vắt Men Chua Thúng. Trúc Vi Tự Động Acid Kiến Đốt Phồng Cục Ong Găm Formic (Khoét Nọc Axit HCOOH Bọng Hỏa Sinh Ruột Vi Nóng Phập Rát Da). Vòi Lưỡi Bọt Kép Hái Chấm Ngành Thẩm Mĩ Axit Trừ Keo Nước Phủ Kéo Cốt Sợi Thuốc Trị Độc Bong Gân."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=6oN09A9ENHg","title":"Bài giảng: Carboxylic acid","thumbnail":"https://img.youtube.com/vi/6oN09A9ENHg/0.jpg","description":"Cấu tạo nhóm -COOH, tính acid and các ứng dụng quan trọng của carboxylic acid (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 24. Carboxylic acid là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 24. Carboxylic acid là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 24. Carboxylic acid?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 24. Carboxylic acid thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 24. Carboxylic acid?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 24. Carboxylic acid?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 24. Carboxylic acid trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 24. Carboxylic acid?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 24. Carboxylic acid, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 24. Carboxylic acid giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 24. Carboxylic acid là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 24. Carboxylic acid là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 24. Carboxylic acid?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 24. Carboxylic acid thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 24. Carboxylic acid?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 24. Carboxylic acid?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 24. Carboxylic acid trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 24. Carboxylic acid?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 24. Carboxylic acid, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 24. Carboxylic acid giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 24. Carboxylic acid tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 24. Carboxylic acid với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 24. Carboxylic acid thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 24. Carboxylic acid, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 24. Carboxylic acid?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 24. Carboxylic acid vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 24. Carboxylic acid?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 24. Carboxylic acid lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 24. Carboxylic acid?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 24. Carboxylic acid là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai25', 11, 'ketnoi', 'Bài 25. Ôn tập chương 6', 'Chương 6. Hợp chất carbonyl – Carboxylic acid', 25, 'Tổng hợp mối quan hệ giữa Aldehyde, Ketone, Carboxylic acid and mảng liên hệ trước là Alcohol thông qua quá trình chuyển hóa nhóm chức.', '[{"id":"mod1","type":"heading","content":{"text":"1. Sự luân chuyển Oxi hóa – Khử mảng hữu cơ","level":"h2"}},{"id":"mod2","type":"infoBox","content":{"color":"blue","title":"Lưới Cầu Vòng Luân Hồi Trục Mạch Chích Oxi - Đun Giảm Khử (Biển Gạn O)","content":"Mã Gen Ròng Sinh Khắc Thảm Khốc Nhất Cuộc Đời Điển Hóa Bậc Rượu Chứa Oxi Vấn Bủa Gạt Mạch Lên Dòng Khung Thất Trái.\\n[Gốc Đáy Hóa Tụ Lõm Mảng - ALCOHOL 1 Nền Vút Mạch: Chứa Điểm Ngậm Chóp $-CH_2-OH$].\\nVuốt Bẻ Cạo Nước Kéo Khét Cháy Đen Mõm Đồng Đỏ Cắn Lớp (Nướng Nhét Cào CuO Khử Độ O Xi Nhẹ Hóa Không Khép Hoàn Góc Nối Toãn Sôi). Áo Choàng Bậc 1 Rụng Mầm Cụt Quăng Ra Bức Liền Phân Tán Bậc Cao Lập Nghiệp Phái **ALDEHYDE (-CHO)** Chua Lạnh Cuốn Chảy Giọt Khóc Gương.\\nVuốt Leo Ả Đỉnh Siêu Lãnh Cực Đỉnh Bạo Dạng Tích Khí Lấp Kép Áp Lửa Băng: Dội Nốt Tướng $O_2$ Khí Nhào Nạp Vi Mạnh Màng Cuộn Hoặc Nấu Đun Cốc Khử Vàng Đốt. Đầu Gai Khu Aldehyde Gõ Tan Khung Thép Nuốt Chửng O Mở Rộng Ứa Phình Sộp Góc Lớn Diệt Đại Bàng Đâm Thủng **Axit Tướng CARBOXYLIC (-COOH)** Phủ Thượng Tịch Chua Điện Li Điên Chát Cắn Mảng.\\nQuăng Vòi Phục Giới Đẩy Khí Hydro Bơm $H_2/Ni$, Hoàn Cục Lịch Sử Thủng Ruột Cuộn Cốt Lui Về Đĩa Dưới Chót Tiêu Nhẹ Cổ Mất Lực Gục (Khử Nằm Y)."}},{"id":"mod3","type":"paragraph","content":{"text":"Thảo Khoán Hướng Sự Ngắt Bệ Nhất Thiết Nguồn Rượu Cong Mép Giữa (Lõi Carbon Đa Nằm Trung Cuộn Kín Thân Alcohol Bậc Thừa Kế 2: $-CH(OH)-$ ). Cặp Não Tôn Cuống Lưỡi Nho Oxi Khống Hóa Liếm Xáp Cuộn Nhẹ Chỉ Bật Trượt Leo Ả Đẻ Được Đúng Tàn Vi Cục Trạm Nhựa Bít Ruột **KETONE (-CO-)** Trơ Bất Vạn Não Chết Im Ngáo Vẹo Tĩnh Liệt Mạch, Không Thể Leo Vượt Đấu Bạo Cửa Axit Trừ Diệt Phá Khoang Phân Bẻ Gãy Tứt Sạch Khung. Đốt Rớt Quỳ Ketone Biến Dạng Không Oxi Góc Dãn."}},{"id":"mod4","type":"heading","content":{"text":"2. Chuyển hóa Carboxylic acid tạo liên kết Ester","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Kết Giới Cổng Vòng Xuyến Dệt Túi Sánh Mịn Khắp Gian Dối Máng ESTER Khép Núp Chữ Bọc Khung Tròn Dính Vách Thúc Vi Nhóm Chức (Dán Ghép Dư Khảo Phối Axit Liên Thục Hấp Cồn Rỉ Ra Hương Hoa Phân Tử Kéo Bám Tươi Quả Thơm Mầm Sóng Keo Liệu Dài Phết Ly O). Đây Cũng Màn Phủ Kết Khóa Thắt Trọn Gói Vỏ Mảng CHƯƠNG LỚN CÁC DẪN XUẤT HỮU CƠ OXY (HẾT LỚP 11 Nhấn Điểm Giao Thi Vọng Cửa Hóa Trí Kháng Kỹ Năng Siêu Độ Lạc Tường Hợp Giữ Cuồng Thực Phim Khoác Lưới Bạo Vượt Tầng Cấp Sang Hồi 12 Thi Hóa Đại Khảo Bắn Esters)."}},{"id":"mod6","type":"heading","content":{"text":"3. Ôn Củng cố Bài Tập Nhận Diện Nhóm Chức Tổng Hợp","level":"h2"}},{"id":"mod7","type":"list","content":{"type":"bullet","items":["Bộ Phân Hóa Phả Đồ Xét Cặp Xác Thực Định Tính Phân Minh Các Thuốc Thử Nhận Lọ Nhựa Chức Vị Sạch:","1. Trò Tiết Đục Tách Chẻ Rã **PHENOL (Gốc Nối Rìa Thơm C6H5OH):** Hàng Mẫu Độc Nhất Vô Nhị Kèo Gây Báo Đổ Ngập Bọt **TỦA BẬC TRẮNG HÓA VẪN DÀY GẠT WITH NƯỚC BROM NÂU DỊCH Bromine**. Và Hòa Mảng Trống Không Trôi Ống Tàn Kiềm Xút NaOH Mù Nhòa.","2. Trò Vi Cụ Bạt Tiếng Gục Khóc Tĩnh Ảm Đâm **ALCOHOL (Lỏng Rượu Bậc OH Trắng Ngà Đục C):** Đập Tan Biến Điện Lôi Gỉ Trắng Miếng Na Chọt Lỗ Xốc Xì Phụt Sủi Khoét Nước Mụt Khí Gái Bay. Xối Đỏ Dội Phọt $170^\\\\circ$ Lò Nóng Kiệt Sinh Bóng Phun Lũ Kép Cầu Khúc Trũng Alkene Pi. Bị Cọ Đen Đầu Đỏ Chót CuO Nhấn Bả Trượt Hóa Nước Chết Lủng Ẩm Mùi Thức Gương Mạc Aldehyde Liền.","3. Trò Chuyên Cầm Ma Gương Kiếm Phản Tạp Tráng Màn Dạ Lọc **ALDEHYDE (Viền Cửa Chui Khớp Mạn Phút CHO):** Không Giải Thoát Bàn Mạng Ngoài Phản Kích Xộc Quyện Giải Trắc Kĩ Năng Ma Mỵ Giết Rửa Bình Đun Tủ Trắng Chép Ly Khối 2 Bạc Bóng Dạ Kính Gương (**Phản Chiếu Tráng Bạc Tollens Dung Dịch Mạng AgNO3 Lẫn Amoniac**). Toluene Vòng Hư Phenol Kể Cả Tẩy Bọt Cạn Rượu Góc Đều Chết Rụng Bỏ Xui Trơ Lá.","4. Trò Rớt Sọt Quá Thâm Trơ Vô Cực Nết Chó Nuốt Rặng Lì **KETONE (Nhóm Lõi Trầm Rút Kéo Sống >C=O Vục Rãnh)**: Khinh Tạp Vạn Vật Đóng Oxi, Liệt Dạ Thờ Bạc Bỏ Tollens Lạc Vào Tĩnh Khống Bất Lưỡi Mạng Không Mào Tan Mất O Nước Brom, Phọt Vô Đất.","5. Trò Ác Lệnh Ngai Cực Oai Thần Đoạt Vương Góc Giỏi Vệ Hùng Phá Ác Đỏ Họng Quỳ **CARBOXYLIC ACID (Khung Vương Đế Cạo Góc Nhựa Đổi Chua Dấu Phân Axit COOH):** Quỳ Trắn Giấy Chỉ Màu Bức Tím Vứt Bạt ĐỎ RUỘT RỰC LỬA CHÁY MÁU TƯƠI Sáng Viền Rìa Rám. Nấu Kí Tan Nhồi Kháy Lửa CO2 (Cắn Đá Bọt Lò Na2CO3 Văng Ngược Túi Tro Vôi Ảo Hoạt Bong Bọt Lì Xút Trắng Chua Đào Tát Muối Tàn Ly Phân Nước)."]}},{"id":"mod8","type":"warningBox","content":{"color":"orange","title":"Khoang Chốt Tận Tư Thế Não Điểm Nhận Biết Đột Phá Bảng Gốc Lỗi Giải Ảo Trượt Mạng Thi","content":"Đây Là Giao Cắt Ác Não Chỉ Mạng Thi Tốt Nghiệp QG. Nếu Bạn Đóng Lệnh Liệt Nhận Cửa Trái Kéo Vết Chức O-H O-C... Là Mất Trắng Ảo Thi Sai Chệch Nhóm Sơ Đồ Cục Diễn Đốt Vượt Tầm. Luôn Luôn Thuộc Đầu Ngón Tay Bản Tính Màu Trắng Tủ Phenol Brom -> Tráng Gương Bạc Formic and Phả Cửa Tổ Aldehyde Gắn Chức -> Axit Buộc Chua Quỳ Phản Dịch Na Bọt -> Rượu Vô Liệt Oxi Hóa Kép Thành Đồng Vũng CuO Khép Khí. Đóng Khung Não Tọa Chức Ảo Giải Điên Phá Mã Mạch Dịch."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=ieHCHrarXq4","title":"Ôn tập chương 6: Hợp chất carbonyl - Carboxylic acid","thumbnail":"https://img.youtube.com/vi/ieHCHrarXq4/0.jpg","description":"Tổng kết toàn bộ kiến thức chương 6 and giải đề ôn tập củng cố (Loigiaihay)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 25. Ôn tập chương 6 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 25. Ôn tập chương 6 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 25. Ôn tập chương 6?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 25. Ôn tập chương 6 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 25. Ôn tập chương 6?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 25. Ôn tập chương 6?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 25. Ôn tập chương 6 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 25. Ôn tập chương 6?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 25. Ôn tập chương 6, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 25. Ôn tập chương 6 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 25. Ôn tập chương 6 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 25. Ôn tập chương 6 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 25. Ôn tập chương 6?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 25. Ôn tập chương 6 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 25. Ôn tập chương 6?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 25. Ôn tập chương 6?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 25. Ôn tập chương 6 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 25. Ôn tập chương 6?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 25. Ôn tập chương 6, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 25. Ôn tập chương 6 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 25. Ôn tập chương 6 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 25. Ôn tập chương 6 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 25. Ôn tập chương 6 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 25. Ôn tập chương 6, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 25. Ôn tập chương 6?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 25. Ôn tập chương 6 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 25. Ôn tập chương 6?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 25. Ôn tập chương 6 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 25. Ôn tập chương 6?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 25. Ôn tập chương 6 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai26', 11, 'ketnoi', 'Bài 26. Kiểm tra cuối năm - Hóa học 11', 'Kiểm tra đánh giá', 26, 'Bài kiểm tra tổng hợp kiến thức toàn bộ chương trình Hóa học 11 bám sát định hướng đánh giá năng lực.', '[{"id":"mod1","type":"heading","content":{"text":"1. Hướng dẫn ôn tập trước kỳ thi","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["Cuộc hành trình Hóa Học 11 Khóa Chốt Năm Học. Bộ Não Người Học Cần Trang Bị 2 Trụ Cột Vạm Vỡ Khổng Lồ Chia Chia Non Nước:","**VÔ CƠ (Chương 1-2):** Đấu Trường Của Sự Định Lượng Nồng Độ pH Khó Nhai, Thuật Cân Bằng Hóa Học Trượt Dốc Le Chatelier, Màn Phân Li Tự Bứt Rễ Axit - Bazo - Muối. Sát Phạt Rực Mưa Đạn Nitric Axit ($HNO_3$) Nuốt Chửng Không Nhả Khí, and Bản Án Sulfur $SO_2$ Hóa Khói Thối Lưu Huỳnh Tàn Sát Sinh Linh Mưa Axit H2SO4 Đặc Háo Ép Nước Cạn.","**ĐẠI CƯƠNG HỮU CƠ (Chương 3):** Thấu Lĩnh Đạo Gốc: Nắm Chắc Tuyệt Kĩ Chưng Cất Tách Chất, Ném Lò Đốt Lập Khung Phân Tử C : H : O... Vẽ Tay Bẻ Nhánh Đồng Phân Bứt Khớp Mạch Không Sai Lệch.","**HYDROCARBON + DẪN XUẤT (Chương 4-6):** Các Ông Kẹ Thống Lĩnh Mọi Hóa Học Sự Sống: Alkane Lì Lợm Phản Cháy Ráp Thế Thế Khí Khắp Biển; Alkene Pi Yếu Loãng Lọc Bứt Cộng Tuôn Bồn Chảy. Vương Thần Benzene Không Dung Túng Brom Lỏng Khát Đốt; Trói Điểm Chót Alcohol Bứt Nước Ché Mắt. Phenol Sôi Kết Tủa Nhỏ Lòng, Formaldehyde Aldehyde Tráng Bạc Kiếm Xoay Tiền Khổng Lồ, Cho Đến Vị Vua Chốt Bảng Carboxylic Mệnh Tính Đôi Chua Acetic Giấm Gạo Nặng Quỳ Tím Khát."]}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Ma Trận Điểm Tử Chiến Học Thư Luyện Trực Quan","content":"Những Trận Đánh Bắt Buộc Trúng Tâm Không Lết:\\n1. Phản Ứng Đốt Cháy Hydrocarbon Định Danh Nguồn Nước : CO2 Trừ Đi Tìm Khí Gốc (nAlkane = Nước Lớn - CO2 Bé, Cân Hiệu Số Bọt Ra Đáy Vũng).\\n2. Gắn Áo Bạc Tollens Đẻ Phân Lọc Aldehyde (Khẳng Định Phương Trình Tỉ Lệ Tiền Bạc Formic).\\n3. Dung Sạc NaOH Mùi Khai Đẻ Amonia, Xé Tím Quỳ Phóng Thẳng Tủa Keo Đáy Dung Môi Điện Lí."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=Cq_Z05W5_7Y","title":"Ôn tập Học kì 2: Hóa học 11","thumbnail":"https://img.youtube.com/vi/Cq_Z05W5_7Y/0.jpg","description":"Video tổng hợp kiến thức trọng tâm and giải đề thi mẫu học kì 2 (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 26. Kiểm tra cuối năm - Hóa học 11 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 26. Kiểm tra cuối năm - Hóa học 11 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 26. Kiểm tra cuối năm - Hóa học 11?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 26. Kiểm tra cuối năm - Hóa học 11 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 26. Kiểm tra cuối năm - Hóa học 11?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 26. Kiểm tra cuối năm - Hóa học 11?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 26. Kiểm tra cuối năm - Hóa học 11 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 26. Kiểm tra cuối năm - Hóa học 11?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 26. Kiểm tra cuối năm - Hóa học 11, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 26. Kiểm tra cuối năm - Hóa học 11 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 26. Kiểm tra cuối năm - Hóa học 11 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 26. Kiểm tra cuối năm - Hóa học 11 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 26. Kiểm tra cuối năm - Hóa học 11?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 26. Kiểm tra cuối năm - Hóa học 11 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 26. Kiểm tra cuối năm - Hóa học 11?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 26. Kiểm tra cuối năm - Hóa học 11?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 26. Kiểm tra cuối năm - Hóa học 11 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 26. Kiểm tra cuối năm - Hóa học 11?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 26. Kiểm tra cuối năm - Hóa học 11, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 26. Kiểm tra cuối năm - Hóa học 11 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 26. Kiểm tra cuối năm - Hóa học 11 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 26. Kiểm tra cuối năm - Hóa học 11 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 26. Kiểm tra cuối năm - Hóa học 11 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 26. Kiểm tra cuối năm - Hóa học 11, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 26. Kiểm tra cuối năm - Hóa học 11?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 26. Kiểm tra cuối năm - Hóa học 11 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 26. Kiểm tra cuối năm - Hóa học 11?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 26. Kiểm tra cuối năm - Hóa học 11 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 26. Kiểm tra cuối năm - Hóa học 11?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 26. Kiểm tra cuối năm - Hóa học 11 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":600,"rewardGem":50,"difficulty":5,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai3', 11, 'ketnoi', 'Bài 3. Ôn tập chương 1', 'Chương 1. Cân bằng hóa học', 3, 'Hệ thống hóa lại kiến thức về cân bằng hóa học and cân bằng acid - base trong dung dịch nước.', '[{"id":"mod1","type":"heading","content":{"text":"1. Tổng kết kiến thức Chương 1","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["**Vạn Vật Thuận Nghịch:** Phản ứng hóa học không chỉ là đường một chiều khống chế. Rất nhiều hệ thống tồn tại chiều thuận and chiều cản nghịch. Khi Tốc độ v thuận = Tốc độ v nghịch sẽ tự neo thiết lập Trạng Thái Cân Bằng Hóa học Bất Động Tĩnh Lặng.","**Hằng số K (Chỉ thờ phụng Nhiệt độ):** Thương số tĩnh nồng độ giữa (Sản phẩm chia Tham gia) tạo thành $K_c$. Nó là hằng số quyền lực, dùng để phán đoán phản ứng thiên về chiều nào. Để thay đổi KC tuyệt đối chỉ có 1 nút gạt Tăng Giảm Độ nóng t°C lò.","**Cán cân Le Chatelier (Chống Lại Kẻ Phá Nhoài):** Hệ phán ứng Cân bằng sẽ như 1 lò hơi khổng lồ, khi ta Tăng Áp/Nhiệt/Nồng (Tác động ngoại lai), Nó lập tức đẩy chuyển dịch làm Tiêu hao (Ngược hướng) cái lực đó. Và ngược lại."]}},{"id":"mod3","type":"heading","content":{"text":"2. Cân bằng điện li","level":"h2"}},{"id":"mod4","type":"paragraph","content":{"text":"Thế giới vô hình chia 2 nửa: Nhóm Quý Tộc phân ly Mạnh gồm (HCl, HNO3 mạnh, Nhóm Kiềm mạnh kiềm thổ NaOH, Muối hòa tan 100%) - Dẫn điện xé gió. Nhóm Yếu gục ngã (Axit Dấm Hữu cơ, Nhóm khí Khai Amonia) chỉ tan rỏ rọt cân bằng. Thuyết Brønsted-Lowry lên ngôi đè bẹp hệ truyền thống với câu thần chứ: \\"Acid Nhả H+ Cho đi, Bazo Hút Nhận H+ Hớt Lại.\\". Kéo theo cả thuyết Lưỡng Tính (Vừa cắn vừa Nhả theo đối thủ như $H_2O, HCO_3^-, Al(OH)_3$)."}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Vũ Khí Tính Toán Toán Học Ion","content":"Ghi Khắc Dạ: Ở điều kiện phòng Lab 25°C. \\nToán [1]: [H+] × [OH-] = Tích Số Nước vĩnh cửu = 1,0 × 10^(-14).\\nToán [2]: Công thức Lô-ga-rít pH = -log([H+]). Tính vội pOH = -log([OH-]). \\nToán [3]: Mệnh đề bù trừ tuyệt kĩ: pH + pOH = Trọn vẹn 14.\\nMôi trường đếm pH < 7 là thế giới Chua Axit gặm mòn. pH > 7 là khoảng không Kiềm Bazo tẩy rửa xanh lét."}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Bẫy Sai Khiếp Đảm Ở Kì Thi THPT","content":"Sai lầm 1: Đồng nhất Cân Bằng với Tốc Độ. Thêm CHẤT XÚC TÁC Platinum chỉ giúp dồn 1 phản ứng nhanh nổ tung sớm hơn, Không làm lượng Chất cuối cùng bị Chuyển Dịch. \\nSai lầm 2: Các phản ứng Rắn hóa Tĩnh như Nung Đá vôi rắn $CaCO_3(Rắn) \\\\rightleftharpoons CaO (Rắn) + CO_2(Khí)$. Việc xả tống ép áp suất bình chỉ nén khí $CO_2$. Thêm Bớt đất đá nồng độ Chất Rắn KHÔNG LÀM DỊCH chuyển mảy may cân bằng."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=dX9jQ27EBAc","title":"Ôn tập chương 1: Cân bằng hóa học","thumbnail":"https://img.youtube.com/vi/dX9jQ27EBAc/0.jpg","description":"Tổng kết toàn bộ kiến thức chương 1 and giải bài tập củng cố (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 3. Ôn tập chương 1 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 3. Ôn tập chương 1 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 3. Ôn tập chương 1?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 3. Ôn tập chương 1 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 3. Ôn tập chương 1?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 3. Ôn tập chương 1?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 3. Ôn tập chương 1 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 3. Ôn tập chương 1?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 3. Ôn tập chương 1, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 3. Ôn tập chương 1 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 3. Ôn tập chương 1 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 3. Ôn tập chương 1 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 3. Ôn tập chương 1?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 3. Ôn tập chương 1 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 3. Ôn tập chương 1?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 3. Ôn tập chương 1?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 3. Ôn tập chương 1 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 3. Ôn tập chương 1?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 3. Ôn tập chương 1, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 3. Ôn tập chương 1 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 3. Ôn tập chương 1 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 3. Ôn tập chương 1 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 3. Ôn tập chương 1 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 3. Ôn tập chương 1, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 3. Ôn tập chương 1?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 3. Ôn tập chương 1 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 3. Ôn tập chương 1?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 3. Ôn tập chương 1 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 3. Ôn tập chương 1?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 3. Ôn tập chương 1 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai4', 11, 'ketnoi', 'Bài 4. nitrogen', 'Chương 2. Nitrogen – Sulfur', 4, 'Trạng thái tự nhiên, cấu tạo phân tử, tính chất and vai trò của nguyên tố Nitrogen.', '[{"id":"mod1","type":"heading","content":{"text":"1. Trạng thái tự nhiên and tính chất vật lí","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Nitrogen ngự trị như một đại đế ẩn mình của hành tinh, chiếm giữ đến 78% tổng thể tích bầu khí quyển Trái Đất nơi ta hít thở (Khoảng 4/5 dung tích không khí). Cấu trúc nguyên tố ký hiệu N (Bảy proton). Dù chiếm phần lớn mây trời dưới dạng N2 tinh khiết, nhưng ở vỏ quả địa cầu and trong thế giới hữu cơ sinh học, nó là những khối kim khí thiết yếu tổng hợp lập nên mầm phân tử Nucleic Acid (DNA, RNA mã Di Truyền) cấu sinh vĩ đại and Protein cơ bắp động thủ muôn loài vật."}},{"id":"mod3","type":"paragraph","content":{"text":"Trạng thái tự do Nguyên phân tử ($N_2$). Phân tử cực kì rụt rè and tàng hình: Chất khí trong suốt Không màu, Vô Vị, Không Mùi ươn khai. Bay bổng lả lướt and nhẹ hơn Thể tích Khí quyển ($28 < 29$ khối lượng mol Khí trời). Khả năng lặn sâu dưới ngai mặt Nước của nó cực kì tồi tàn (Gần như bay không thèm hòa tan kết liễu)."}},{"id":"mod4","type":"heading","content":{"text":"2. Cấu tạo phân tử & Tính chất hóa học","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Cấu trúc hạt nhân Điện Tử là nguyên nhân của SỰ TRƠ LÌ Tuyệt Phẩm. Phân tử Khí $N_2$ là một liên kết Ba khổng lồ ($N \\\\equiv N$), tạo bởi ba đôi Cặp e xài chung dày đặc kiên cố. Trừ phi nung đốt nó tới mức sức ép ngàn độ điện hồ quang hay sấm chớp 3000 C thì may ra mới phá đứt nổi 3 sợi xích xâu chuỗi này. Phản ứng Hóa học của N2 diễn ra muôn vàn khó khăn."}},{"id":"mod6","type":"list","content":{"type":"bullet","items":["**Tính Oxi hóa lừa lọc:** Chiếm trọn vị thế khi gặp gỡ các đại gia Khử.\\n1. Ép xác với Hydrogen ở Nhiệt áp Nén $400 C - 200 atm$, xúc tác bột Sắt hãm: Xảy ra phản ứng quy mổ nổ tàn bạo Cân bằng Thuận Nghịch sinh Khí Amonia độc khai: $N_2 + 3H_2 \\\\rightleftharpoons 2NH_3$.\\n2. Lừa phỉnh nuốt chửng Kim loại siêu cháy sáng Mg nung đỏ: $3Mg + N_2 \\\\xrightarrow{t^\\\\circ} Mg_3N_2$ (Magnesium nitride đen đục). Chỉ ăn kim loại mạnh hiếm hoi Li ở độ 25 C thường mát.","**Tính Khử chống cưỡng (Luồn Cúi Vua Oxi):** Đốt nóng $N_2$ đối đầu $O_2$. Ở nhiệt lạnh vô nghĩa. Nhưng ở Tâm vụ sét nổ sấm chớp giông bão (hoặc Nung Lò Hồ Quang Điện lấp lánh $3000^\\\\circ C$), nó xé xác Nito thành khí Nitric Oxide nồng nặc cháy: $N_2 + O_2 \\\\rightleftharpoons 2NO$."]}},{"id":"mod7","type":"warningBox","content":{"color":"orange","title":"Chinh Phục Công Nghiệp Phân Bón - Quy Trình Haber","content":"Vì Khí Nitơ trơ lì lười nhác, cây Cối ngắc ngoải thiếu ăn đạm sinh trưởng dù ngập không khí Nito. Nhà bác học Haber đoạt giải Nobel khi ép nén vắt Lực lượng lớn Amonia lỏng từ Nitơ không khí bơi ra bằng hệ Lò Máy Trùng Ép Xúc Tác sắt, giải cứu nền Nông Nghiệp Lương Vạn Mùa lúa mì Toàn Thế Giới rực rỡ khỏi Nạn Đói chết chóc diệt vong đầu Thế Kỷ 20."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=Nqwo4SNVxdo","title":"Bài giảng: nitrogen","thumbnail":"https://img.youtube.com/vi/Nqwo4SNVxdo/0.jpg","description":"Trạng thái tự nhiên, tính chất vật lí and hóa học của đơn chất Nitrogen (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 4. nitrogen là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 4. nitrogen là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 4. nitrogen?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 4. nitrogen thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 4. nitrogen?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 4. nitrogen?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 4. nitrogen trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 4. nitrogen?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 4. nitrogen, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 4. nitrogen giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 4. nitrogen là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 4. nitrogen là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 4. nitrogen?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 4. nitrogen thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 4. nitrogen?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 4. nitrogen?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 4. nitrogen trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 4. nitrogen?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 4. nitrogen, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 4. nitrogen giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 4. nitrogen tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 4. nitrogen với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 4. nitrogen thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 4. nitrogen, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 4. nitrogen?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 4. nitrogen vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 4. nitrogen?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 4. nitrogen lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 4. nitrogen?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 4. nitrogen là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai5', 11, 'ketnoi', 'Bài 5. Ammonia – Muối ammonium', 'Chương 2. Nitrogen – Sulfur', 5, 'Cấu tạo, tính chất của NH3 and ion NH4+. Hiểu tính base yếu của ammonia and tính chất của muối ammonium.', '[{"id":"mod1","type":"heading","content":{"text":"1. Ammonia (NH₃)","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Ammonia ($NH_3$) dường như mang sức mạnh and độ ám sát khứu giác khủng bố ngầm. Khí dìm không màu, nặng sát chết mùi khai thối nồng thốc ám xộc (Mùi nhà xí phân nước tiểu hoai mục nồng). Có tỷ khối nhẹ như vớt bọt bèo bay phốc lướt Không khí ($17 < 29$). Nhưng nó cực kì Đam mê uống Nước. Dung dịch nó hút thút nút Nước (1 lít nước hòa tàn diệu vợi 800 lít Khí Amonia nén lại rực), and hóa lạnh phễu thủy tinh làm môi chất tủ cấp đông lạnh nhiệt."}},{"id":"mod3","type":"list","content":{"type":"bullet","items":["**Mảng Lực Base Yếu Cực Độ (Tính Kéo Lùa pH):** Phân tử NH3 hình tháp tam giác với Đỉnh Nitơ thừa 1 cặp e vô duyên lủng lẳng. Khi bơi vô nước, lập tức nó thò Tay Cặp e đó léo cuốn giằng xé 1 ion H+ của nước ($H_2O$): $NH_3 + H_2O \\\\rightleftharpoons NH_4^+ + OH^-$. Dung dịch sinh ra chỏm dư $OH^-$ cày nát nồng độ quỳ tím ố vàng phải tấy Xanh lam Đậm thẫm giọt thuốc đỏ Phenol rực Hồng sứt mẻ.","**Mảng Phóng Đạn Khử Kháng Nham:** Nguyên tử N mang số oxi hóa tận đáy vực -3 (hút e tối đa cực hạn của gốc điện âm). Khát muốn ngóc dậy ngoi lên hóa cao nên có Tính Khử mãnh hổ tàn bạo. Bơm lửa sục Oxy dư: $4NH_3 + 3O_2 \\\\xrightarrow{đốt\\\\ t^\\\\circ} 2N_2 + 6H_2O$. Nếu có đệm màng bạch kim xúc tác ép súc Platinum (Pt) nung lửa 900 C, Amoniac hóa khí Độc Nitric : $4NH_3 + 5O_2 \\\\xrightarrow{Pt, 850^\\\\circ} 4NO\\\\uparrow + 6H_2O$."]}},{"id":"mod4","type":"heading","content":{"text":"2. Muối ammonium","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Để kiềm chế khí dội Độc Nhãn $NH_3$ bốc hơi bay mất của công nghiệp, các nhà Hóa học đã ép Amonia sục lút vào vũng bồn dung dịch Acid đặc (HCl, H2SO4) mút kết tủa thành từng Tinh thể Muối rắn. Hình hài Ion ammonium ($NH_4^+$) ra lò, kết dệt mảng cấu trúc bột mặn trắng tinh bọc chực Tinh Thể kết mạng (Như Thóc Urea trắng đồng mạ màu nông nghiệp phân đạm), dễ cấu kết bốc hôi nước tan phân ly 100% trong đồng bào ruộng chìm, ngấm nhanh rễ hút no phún đọt nông thực."}},{"id":"mod6","type":"infoBox","content":{"color":"blue","title":"Chết Chóc Thuốc Súng - Nhiệt Phân Cực Đoan Ammonium","content":"Muối Ammonium KHÔNG HỀ BỀN RẼ NHIỆT. Chúng sẽ nổi điên tự băm thây xá hóa khí khi Nung Lửa Lò.\\n- Phân Mủ Khí Cốc: (Gốc muối gốc Axit dễ bay ko Oxi hóa) $NH_4Cl \\\\xrightarrow{Lửa\\\\ t^\\\\circ} NH_3(Khí)\\\\uparrow + HCl(Khí)\\\\uparrow$. Chảo nung bốc sạch tinh màng ko để lại xỉ đá.\\n- Bão Lửa Tự Bùng Oxi hóa Nổ Sấm Hầm Mỏ (Gốc Nitrat ngậm Acid siêu cháy): $NH_4NO_3 \\\\xrightarrow{Lửa\\\\ t^\\\\circ} N_2O\\\\uparrow + 2H_2O$. Hoặc đun Nổ Ammonium Nitric đục tan vách núi đá mở đường $NH_4NO_2 \\\\xrightarrow{Lửa\\\\ t^\\\\circ} N_2(bay) + 2H_2O$."}},{"id":"mod7","type":"paragraph","content":{"text":"Bản sắc phân ly thuốc Test nhận mặt Ion: Cứ nghi ngờ phân đạm phân bón giả có chứa $NH_4^+$? Các dân phòng hóa lấy rắc tí bột hóa dung dịch bồn nhả mạnh Kiềm Base Mạnh Xút vẩy tạt thẳng vô ($NaOH / Ba(OH)_2$ hắt nhiệt nhẹ). Lập tức khói Bọt lủi sủi phụt văng thoát khí ra Mùi Khăm Khẳm Ố Xí Khai nức mũi xốc thẳng óc (Khí NH3 vọt lên). Lấy dải giấy Quỳ tẩm ẩm nước phất hơ bắt vội khói khai ấy, giấy quỳ rách đỏ chuyển đổi xanh lục biếc lịm tức thời."}},{"id":"mod8","type":"warningBox","content":{"color":"orange","title":"Sai lầm Kiến trúc Amoniac Lâu năm Cơ bản $NH_4OH$","content":"Cảnh Báo Lớn SGK: Khoáng dung dịch lỏng Amonia pha đẫm Nước luôn tồn tại một lổ hổng cân bằng động khổng lồ, bản chất khí tan chủ yếu nát vụn ở dạng $NH_3$ ngậm thoi đưa $H_2O$, and một khoảng phân li rách nát tí nách Ion ($NH_4^+$) and ($OH^-$). Tương lai hóa học mới không thèm viết cấu thành hộp Phân Tử kiềm mạnh ố dề $NH_4OH$ như SGK quá khứ ảo vì chả bao giờ cô lập sờ nắn chộp múc ra được dạng bột khô hay dạng nước tĩnh lỏng liên kết vững chãi này."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=lyuIciolbSU","title":"Bài giảng: Ammonia and muối ammonium","thumbnail":"https://img.youtube.com/vi/lyuIciolbSU/0.jpg","description":"Cấu tạo phân tử, tính chất and ứng dụng của Ammonia and muối Ammonium (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 5. Ammonia – Muối ammonium là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 5. Ammonia – Muối ammonium là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 5. Ammonia – Muối ammonium?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 5. Ammonia – Muối ammonium thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 5. Ammonia – Muối ammonium?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 5. Ammonia – Muối ammonium?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 5. Ammonia – Muối ammonium trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 5. Ammonia – Muối ammonium?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 5. Ammonia – Muối ammonium, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 5. Ammonia – Muối ammonium giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 5. Ammonia – Muối ammonium là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 5. Ammonia – Muối ammonium là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 5. Ammonia – Muối ammonium?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 5. Ammonia – Muối ammonium thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 5. Ammonia – Muối ammonium?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 5. Ammonia – Muối ammonium?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 5. Ammonia – Muối ammonium trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 5. Ammonia – Muối ammonium?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 5. Ammonia – Muối ammonium, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 5. Ammonia – Muối ammonium giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 5. Ammonia – Muối ammonium tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 5. Ammonia – Muối ammonium với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 5. Ammonia – Muối ammonium thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 5. Ammonia – Muối ammonium, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 5. Ammonia – Muối ammonium?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 5. Ammonia – Muối ammonium vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 5. Ammonia – Muối ammonium?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 5. Ammonia – Muối ammonium lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 5. Ammonia – Muối ammonium?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 5. Ammonia – Muối ammonium là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai6', 11, 'ketnoi', 'Bài 6. Một số hợp chất của nitrogen với oxygen', 'Chương 2. Nitrogen – Sulfur', 6, 'Các oxide quan trọng của nitrogen (NO, NO2) and tính oxi hóa mạnh của nitric acid (HNO3).', '[{"id":"mod1","type":"heading","content":{"text":"1. Oxide của Nitrogen","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["Gia tộc Nitrogen sinh ra hàng loạt các Oxide (NxOy): $N_2O$ (Khí Cười gây ảo giác), $NO$ (Sát thủ không màu), $NO_2$ (Khói nâu độc), $N_2O_4$, $N_2O_5$. Trọng tâm rơi vào 2 anh em NO and NO2.","**Khí Nitric oxide (NO):** Khí không màu, tan rất ít rón rén trong nước. Nhưng khi lọt ra không khí trần, NO lập tức bị Oxy vồ lấy nhai nuốt (Bị Oxi hóa tàn bạo) để biến thành luồng khói Độc Nâu Đỏ: $2NO + O_2 \\\\rightarrow 2NO_2$. Nó là dấu hiệu nhận biết đắc lực của phản ứng Kim loại gặp Axit loãng.","**Khí Nitrogen dioxide (NO2):** Chín mùi với sắc Nâu Đỏ khét lẹt độc hại tàn phá phổi. Là thủ phạm chính gây thảm họa MƯA ACID. Nó tan sục nát vào Nước Mây Trời gộp với Oxi để mưa lụt xuống thành Acid: $4NO_2 + O_2 + 2H_2O \\\\rightarrow 4HNO_3$."]}},{"id":"mod3","type":"heading","content":{"text":"2. Nitric acid (HNO₃)","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Quái Vật Thực Sự - Nitric Acid (HNO3)","content":"Nitric acid (HNO3) là một Acid Mạnh tột độ (Phân li 100% ion $H^+$) and ĐỒNG THỜI là Cỗ Máy Oxi Hóa Hủy Diệt. Ở trạng thái bốc khói hay loãng, nguyên tố Nitrogen mang mác $N^{+5}$ sẵn sàng xé nát cướp Electron của MỌI đối thủ (Kim loại, Phi kim S, C, P thậm chí Hợp chất)."}},{"id":"mod5","type":"paragraph","content":{"text":"Khi $HNO_3$ tấn công Kim loại (kể cả loại bướng phi hành Đồng Cu, Bạc Ag), nó nuốt chửng chúng hóa Muối. TUYỆT ĐỐI KHÔNG BAO GIỜ có phân tử khí Hydro ($H_2$) nào lọt ra được, vì gốc H của Acid này đã bị Tính Oxi hóa nuốt chửng ép quy thành Nước, còn gốc $NO_3$ thì rách bươm phóng ra khí tùy tâm trạng (NO, NO2, N2O, N2...). Chìa khóa: Axit Càng Đậm Đặc \\\\(\\\\rightarrow\\\\) Khí sinh ra Càng Độc Nặng Mùi ($NO_2$). Axit Càng Phai Loãng \\\\(\\\\rightarrow\\\\) Khí sinh ra Càng Xa Gốc N+5 (N2O, N2, NH4+)."}},{"id":"mod6","type":"list","content":{"type":"bullet","items":["**Kịch Bản HNO3 Đặc Nóng:** Khói Nâu Đỏ Bốc Cháy! Sinh khí $NO_2$. \\nVí dụ luộc mảnh Đồng Cu: $Cu + 4HNO_3(Đặc) \\\\rightarrow Cu(NO_3)_2 + 2NO_2\\\\uparrow (Nâu\\\\ Đỏ) + 2H_2O$.","**Kịch Bản HNO3 Loãng:** Trạng thái tĩnh sinh khí KHÔNG MÀU, nhưng vừa ngoi lên nắp ống nghiệm thì Hóa Nâu Không Khí ($NO$). \\nVí dụ: $3Cu + 8HNO_3(Loãng) \\\\rightarrow 3Cu(NO_3)_2 + 2NO\\\\uparrow + 4H_2O$."]}},{"id":"mod7","type":"heading","content":{"text":"3. Muối Nitrate ($NO_3^-$)","level":"h2"}},{"id":"mod8","type":"paragraph","content":{"text":"Muối Nitrate (chứa Móng Nhọn $NO_3^-$) là những viên pha lê hòa tan Tuyệt Đối (Tất cả muối đạm Nitrate đều tan rất tốt trong Nước, cung cấp đạm N cho Rễ Cây hút). Nhưng chớ dại đun nướng Trực tiếp. Chúng cực kì Yếu Mềm Giòn Trùng Nhiệt. Khi đem đốt lửa, muối Nitrate vỡ phân hủy Phọt Oxi nuôi lửa (Đó là lí do Muối Diêm $KNO_3$ dùng để nhồi công thức Thuốc Súng Đen): $2KNO_3 \\\\xrightarrow{t^\\\\circ} 2KNO_2 (Nitrite) + O_2\\\\uparrow$."}},{"id":"mod9","type":"warningBox","content":{"color":"orange","title":"Vũ Khí Thụ Động Hóa - Đóng Băng Tức Khắc","content":"Một nghịch lý sinh tử Hóa Học: Sắt (Fe), Nhôm (Al), Crom (Cr) sẽ phản kháng sục bọt cực mạnh cháy khét nếu gặp HNO3 Đặc Nóng. Nhưng ném chúng vào bình HNO3 ĐẶC NGUỘI (Lạnh ngắt), bề mặt chúng Lập tức hình thành một lớp Màng Kính Nhựa Oxit Dày Đặc Ngậm cứng chốt chặn. Chúng trở nên TRƠ LÌ (Vô cảm). Người ta tận dụng điều này lấy Thùng Phi Sắt and Nhôm để chuyên chở Acid HNO3 Đặc trên Đường Sắt Bắc Nam."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=OW2MMm9cHcs","title":"Bài giảng: Một số hợp chất của nitrogen với oxygen","thumbnail":"https://img.youtube.com/vi/OW2MMm9cHcs/0.jpg","description":"Học về các oxide của nitrogen and hiện tượng mưa acid, phú dưỡng (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 6. Một số hợp chất của nitrogen với oxygen là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 6. Một số hợp chất của nitrogen với oxygen là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 6. Một số hợp chất của nitrogen với oxygen?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 6. Một số hợp chất của nitrogen với oxygen thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 6. Một số hợp chất của nitrogen với oxygen?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 6. Một số hợp chất của nitrogen với oxygen?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 6. Một số hợp chất của nitrogen với oxygen trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 6. Một số hợp chất của nitrogen với oxygen?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 6. Một số hợp chất của nitrogen với oxygen, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 6. Một số hợp chất của nitrogen với oxygen giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 6. Một số hợp chất của nitrogen với oxygen là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 6. Một số hợp chất của nitrogen với oxygen là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 6. Một số hợp chất của nitrogen với oxygen?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 6. Một số hợp chất của nitrogen với oxygen thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 6. Một số hợp chất của nitrogen với oxygen?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 6. Một số hợp chất của nitrogen với oxygen?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 6. Một số hợp chất của nitrogen với oxygen trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 6. Một số hợp chất của nitrogen với oxygen?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 6. Một số hợp chất của nitrogen với oxygen, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 6. Một số hợp chất của nitrogen với oxygen giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 6. Một số hợp chất của nitrogen với oxygen tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 6. Một số hợp chất của nitrogen với oxygen với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 6. Một số hợp chất của nitrogen với oxygen thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 6. Một số hợp chất của nitrogen với oxygen, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 6. Một số hợp chất của nitrogen với oxygen?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 6. Một số hợp chất của nitrogen với oxygen vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 6. Một số hợp chất của nitrogen với oxygen?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 6. Một số hợp chất của nitrogen với oxygen lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 6. Một số hợp chất của nitrogen với oxygen?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 6. Một số hợp chất của nitrogen với oxygen là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai7', 11, 'ketnoi', 'Bài 7. Sulfur and sulfur dioxide', 'Chương 2. Nitrogen – Sulfur', 7, 'Tính chất của sulfur đơn chất and sulfur dioxide. Phân tích vai trò vừa oxi hóa vừa khử của sulfur and SO2.', '[{"id":"mod1","type":"heading","content":{"text":"1. Tinh thể Sulfur","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Sulfur (Lưu Huỳnh S) nguyên thủy mang sắc Vàng chanh đặc trưng diệu kì, rải rắc nồng nặc quanh các họng mồm Miệng Núi Lửa (Diêm sinh). Phi kim này có vô số lột vỏ thù hình nhưng 2 dạng Vua chúa là Tà Phương ($S_\\\\alpha$) and Đơn Tà ($S_\\\\beta$). Chấm vào nước Lưu huỳnh trơ trượt nhám nổi lềnh bềnh (không tan), nhưng thả vào cồn Benzene, dầu hỏa lại vỡ tan tành dung môi. Nó từng là nguyên liệu ma thuật chế tác Thuốc Nổ Đen xa xưa."}},{"id":"mod3","type":"list","content":{"type":"bullet","items":["**Tính Lưỡng Cực (Vừa Oxi hóa - Vừa Khử):** Đứng chót vót mức 0 nằm giữa thang ngực (-2) and (+4, +6).\\n1. **Tính Oxi hóa (Cướp e, chạy lùi về Cấp -2):** Nuốt trọn Kim Loại khi Nung Lò. Ví dụ hầm sắt: $Fe + S \\\\xrightarrow{t^\\\\circ} FeS$ (Iron sulfide đen ngòm xỉ). Phàm là Thủy ngân (Hg) Độc Hại rỉ vỡ nhiệt kế, rắc thẳng Bột S vào sẽ lập tức Vồ Lấy Xực chắt Hg dính chặt Cỡ nhiệt độ thường ($Hg + S \\\\rightarrow HgS$) quét đi an toàn.","2. **Tính Khử (Biếu e, chạy Phốc Lên Cấp +4 hoặc +6):** Gặp lũ lưu manh ngậm Oxi hay Halogen cực hạn, S bỏ chạy nhường quyên sinh. Đốt Lưu huỳnh lửa xanh nhạt mờ: $S + O_2 \\\\xrightarrow{t^\\\\circ} SO_2$ (Khí sunfurơ hắc sặc sụa)."]}},{"id":"mod4","type":"heading","content":{"text":"2. Sulfur dioxide ($SO_2$)","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Khí Diêm Sinh Sulfur dioxide ($SO_2$) mang trong mình án Độc tử hình công nghiệp. Khí vô sắc Không Màu, bốc hơi chua Mùi Hắc nồng nặc (đặc trưng mùi diêm quẹt xẹt cháy sực lên mũi váng đầu). Là khí nặng chìm tàn dư phả ngập kho tàng xưởng mỏ dệt."}},{"id":"mod6","type":"infoBox","content":{"color":"blue","title":"Ác Mộng Ô Nhiễm and Chiêu Hóa Học","content":"Bản chất là một Oxide Acid. \\n1. Hòa quyện Phân Li Nước rễ mầm sinh Axit: $SO_2 + H_2O \\\\rightleftharpoons H_2SO_3$ (Axit yếu rát họng tự phân hủy).\\n2. Tính Khử Tuyệt Chiêu (Tẩy màu diệu kì): Do $S^{+4}$ đang đứng khe vực chơi vơi, nó cực khát khao leo lên đỉnh $S^{+6}$. Sục SO2 vào cốc Nước Bromine (Nâu đỏ ngầu) hay Thuốc tím (KMnO4 Hồng mộng mơ), khí này nhào tới nuốt hết oxi hóa tàn bạo, tẩy cốc bay lột Mạch Màu Hóa Trắng Trong Veo: $SO_2 + Br_2 + 2H_2O \\\\rightarrow H_2SO_4 + 2HBr$. Vì làm mất màu cánh hoa đan dệt, SO2 được tận dụng Tẩy Trắng Đường ngậm phèn, diệt mốc rượu nho."}},{"id":"mod7","type":"warningBox","content":{"color":"orange","title":"Sát Thủ Sương Mù Mưa Axit","content":"Những cột khói đen quánh xả mịt mù từ nhà máy Nhiệt Điện Than, hóa chất Dầu Mỏ lấp đầy tầng điện ly bằng Khí $SO_2$. Nó lơ lửng ngậm bám Hơi Nước Mây Trời gặp vầng Xúc Tác Ôxit Ánh sáng để biến cấu tụng thành Khối Nước Acid Sulfuric ($H_2SO_4$). Trút mưa như đạn hủy diệt nát Tượng Phật Đá, bào rỉ ăn vỏ Ô tô and làm thối loét rễ rừng lá kim ngập mặn."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=l1fgoIVcBL0","title":"Bài giảng: Sulfur and sulfur dioxide","thumbnail":"https://img.youtube.com/vi/l1fgoIVcBL0/0.jpg","description":"Tính chất lưu huỳnh đơn chất and sulfur dioxide (SO2) trong tự nhiên (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 7. Sulfur and sulfur dioxide là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 7. Sulfur and sulfur dioxide là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 7. Sulfur and sulfur dioxide?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 7. Sulfur and sulfur dioxide thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 7. Sulfur and sulfur dioxide?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 7. Sulfur and sulfur dioxide?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 7. Sulfur and sulfur dioxide trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 7. Sulfur and sulfur dioxide?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 7. Sulfur and sulfur dioxide, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 7. Sulfur and sulfur dioxide giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 7. Sulfur and sulfur dioxide là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 7. Sulfur and sulfur dioxide là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 7. Sulfur and sulfur dioxide?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 7. Sulfur and sulfur dioxide thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 7. Sulfur and sulfur dioxide?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 7. Sulfur and sulfur dioxide?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 7. Sulfur and sulfur dioxide trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 7. Sulfur and sulfur dioxide?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 7. Sulfur and sulfur dioxide, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 7. Sulfur and sulfur dioxide giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 7. Sulfur and sulfur dioxide tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 7. Sulfur and sulfur dioxide với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 7. Sulfur and sulfur dioxide thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 7. Sulfur and sulfur dioxide, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 7. Sulfur and sulfur dioxide?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 7. Sulfur and sulfur dioxide vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 7. Sulfur and sulfur dioxide?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 7. Sulfur and sulfur dioxide lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 7. Sulfur and sulfur dioxide?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 7. Sulfur and sulfur dioxide là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai8', 11, 'ketnoi', 'Bài 8. Sulfuric acid and muối sulfate', 'Chương 2. Nitrogen – Sulfur', 8, 'Tính chất của H2SO4 loãng and H2SO4 đặc. Ứng dụng của sulfuric acid and nhận biết ion sulfate.', '[{"id":"mod1","type":"heading","content":{"text":"1. Sulfuric acid (H₂SO₄)","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Hóa học công nghiệp tôn vinh Sulfuric Acid ($H_2SO_4$) như Bộ Máu của mọi nền chế tạo. Lượng Axit sản xuất ra quyết định sức mạnh công nghiệp 1 Cường Quốc mỏ xưởng. Tính cách chia rẽ cực phiến tùy theo Lượng Nước Pha Trộn: Dung dịch mỏng tanh (Loãng) hiền hòa and Ác Qủy Trù Dạ (Đặc Nóng xát xương)."}},{"id":"mod3","type":"heading","content":{"text":"H₂SO₄ loãng","level":"h3"}},{"id":"mod4","type":"list","content":{"type":"bullet","items":["**Mảng Hóa Hóa Loãng (Acid Chân Phương):** Trình diễn 5 tính chất đúc khuôn SGK.\\n1. Nhúng Quỳ Hóa Đỏ hồng rực rỡ.\\n2. Tác dụng gặm Base (OH) đổ nhào Nước ($2NaOH + H_2SO_4 \\\\rightarrow Na_2SO_4 + 2H_2O$).\\n3. Trộn rã Oxide Base Kim Loại ($CuO + H_2SO_4 \\\\rightarrow CuSO_4 \\\\text{ Xanh ngọc } + H_2O$).\\n4. Lấn lướt bóp nghẹt Muối Acid Yếu hơn ($Na_2CO_3 + H_2SO_4 \\\\rightarrow Na_2SO_4 + CO_2\\\\uparrow + H_2O$).\\n5. Đẩy Kim Loại Nhú khí: Gặm nhấm tan kim loại ĐỨNG TRƯỚC H (K, Na, Zn, Fe...) chọc nổ Khí Hydro H2. Không xi nhê gì bọn Đồng Cu / Bạc Ag / Vàng Cu sau H."]}},{"id":"mod5","type":"heading","content":{"text":"H₂SO₄ đặc","level":"h3"}},{"id":"mod6","type":"infoBox","content":{"color":"blue","title":"Axit Già Đặc ($H_2SO_4$ Đặc) - Vị Chúa Bạo Tàn","content":"Khi vút cạn nước lột xác tinh khiết 98%, đây là Con Ác Thú Oxi hóa Thượng Thừa. \\nNuốt chửng dồn ép Phản ứng Kim Loại (Trừ Vàng Au/Pt) vứt ném ra Khí Mùi Hắc Ám Sulfuric $SO_2$ Sặc Sụa, Tuyệt Không Có Hydro. Cụ Đồng Cứng Đầu (Cu) trước vểnh ngơ loãng, nay bị ĐẶC nung đỏ ăn sống vỡ vụn.\\n$Cu + 2H_2SO_4 (đặc, t^\\\\circ) \\\\rightarrow CuSO_4 + SO_2\\\\uparrow + 2H_2O$."}},{"id":"mod7","type":"paragraph","content":{"text":"**Cơn Khát Nước Than Hóa Diệt Chủng:** Cực điểm đáng sợ nhất của H2SO4 đặc là TÍNH HÁO NƯỚC khủng khiếp mút khô. Ném 1 thìa Đường Kính trắng tinh ($C_{12}H_{22}O_{11}$) vào cốc Acid rỗng. Khối thịt đường bị Rút Cạn Vắt Khô Nước Lì Lợm, cặn xương bã xốp đen xịt ngóc đầu phun trào bọt khói mù do Bị Oxi hóa Carbon. \\n$C_{12}H_{22}O_{11} \\\\xrightarrow{H_2SO_4 \\\\text{ Đặc}} 12C (Than\\\\ Đen) + 11H_2O$. (Tương tự dính vô Da người bỏng sâu rỗng tới xương)."}},{"id":"mod8","type":"warningBox","content":{"color":"red","title":"Bi Kịch Sai Lầm Pha Loãng Axit Chắn Mạng","content":"Vì Khát Nước, khi trộn Axit Đặc nhồi vô Nước, Quá Trình Nhú Chảo Tỏa Nhiệt Cuồng Bạo (Nóng Sôi Ục Bắn Sóng). NGHIÊM CẤM RÓT NƯỚC VÀO AXIT. Nó sẽ văng H2SO4 Rực lửa thẳng vào mặt nát mù bét kính.\\nCách duy nhất Cứu Tinh: Tưới Rót Chầm Chậm Từng Giọt H_2SO_4 ĐẶC rỏ rỉ tuột Men thành Phễu Cấp NƯỚC LỚN đã lót sẵn, lấy đũa thủy tinh khoắng tản nhiệt."}},{"id":"mod9","type":"heading","content":{"text":"2. Muối Sulfate","level":"h2"}},{"id":"mod10","type":"paragraph","content":{"text":"Nhật Lệnh Tìm Kiếm Bóng Dáng Gốc Sulfate ($SO_4^{2-}$). Muối chứa Gốc này phần lớn tan tuột vô nước, trừ những con Rắn Lì Bất tử (Bari $BaSO_4$ kết tủa, Chì $PbSO_4$ kết tủa).\\nĐể Bắt Tại Trận Ion Sulfate, Hóa học gia dùng \\"Còng Ba²⁺\\" (Thuốc thử Dung dịch BaCl2 hoặc Ba(OH)2). \\nGặp Nhau Mắt Chớp Là Đóng Đục Tủa Rơi Trắng Khung.\\nPhản ứng bắt gọn: $Na_2SO_4 + BaCl_2 \\\\rightarrow BaSO_4 \\\\downarrow (tủa\\\\ trắng\\\\ ko\\\\ tan\\\\ trong\\\\ Axit) + 2NaCl$."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=Sxv9oagHqmI","title":"Bài giảng: Sulfuric acid and muối sulfate","thumbnail":"https://img.youtube.com/vi/Sxv9oagHqmI/0.jpg","description":"Cấu tạo, tính chất của H2SO4 đặc and cách nhận biết ion sulfate (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 8. Sulfuric acid and muối sulfate là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 8. Sulfuric acid and muối sulfate là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 8. Sulfuric acid and muối sulfate?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 8. Sulfuric acid and muối sulfate thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 8. Sulfuric acid and muối sulfate?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 8. Sulfuric acid and muối sulfate?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 8. Sulfuric acid and muối sulfate trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 8. Sulfuric acid and muối sulfate?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 8. Sulfuric acid and muối sulfate, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 8. Sulfuric acid and muối sulfate giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 8. Sulfuric acid and muối sulfate là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 8. Sulfuric acid and muối sulfate là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 8. Sulfuric acid and muối sulfate?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 8. Sulfuric acid and muối sulfate thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 8. Sulfuric acid and muối sulfate?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 8. Sulfuric acid and muối sulfate?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 8. Sulfuric acid and muối sulfate trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 8. Sulfuric acid and muối sulfate?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 8. Sulfuric acid and muối sulfate, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 8. Sulfuric acid and muối sulfate giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 8. Sulfuric acid and muối sulfate tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 8. Sulfuric acid and muối sulfate với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 8. Sulfuric acid and muối sulfate thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 8. Sulfuric acid and muối sulfate, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 8. Sulfuric acid and muối sulfate?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 8. Sulfuric acid and muối sulfate vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 8. Sulfuric acid and muối sulfate?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 8. Sulfuric acid and muối sulfate lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 8. Sulfuric acid and muối sulfate?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 8. Sulfuric acid and muối sulfate là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa11_kntt_bai9', 11, 'ketnoi', 'Bài 9. Ôn tập chương 2', 'Chương 2. Nitrogen – Sulfur', 9, 'Tổng hợp hệ thống nitrogen – sulfur and các hợp chất quan trọng. Rèn luyện tư duy xác định tính oxi hóa and khử.', '[{"id":"mod1","type":"heading","content":{"text":"1. Sự thay đổi số oxi hóa","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Chương Nito - Lưu huỳnh là Cột Mốc xoáy mòng Lõi Hóa Trí Mạng khi các nguyên tố không giữ mình tĩnh mịch mà leo trèo thang Số Oxi Hóa nhảy múa kịch liệt. \\nTrục Nitrogen: Cực đáy -3 (Amoniac Nh3) lươn lẹo khử lên 0 (N2 Trơ). Để rồi ngót lên Cực Thượng Đỉnh +5 chóp nhọn trong Axit siêu cấp HNO3.\\nTrục Sulfur: Chết chìm dưới rạch -2 (Mùi trứng thối H2S). Leo ngóc mặt Vàng đơn chất Trọng tâm 0 (S tà phương). Hút Oxi thổi phồng lên nấc +4 (Hắc Hơi SO2). Cực Giả +6 Lủng Củng Nhét Nóng (Acid đặc H2SO4 Oxi hóa nghiền nát). Hiểu được sự vút số Oxi hóa là hiểu sự Cướp / Trả Electron."}},{"id":"mod3","type":"heading","content":{"text":"2. Chuỗi phản ứng cần nhớ","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Ma Trận Biến Hóa Trọng Tâm Thí Điểm","content":"**Dây Chuyền Nồi Áp Suất Amonia - Axit Nitric:**\\nNhồi nén khí quyển N2 đẩy hydro H2 $\\\\rightarrow$ Ra lò Sinh Mệnh Đạm Trắng Amonia (NH3) $\\\\rightarrow$ Dí mồi điện Oxi đốt xúc tác phóng Độc NO $\\\\rightarrow$ Để cho Nâu không khí Đỏ NO2 $\\\\rightarrow$ Đổ ngập Mưa Nước Oxi gộp lấp màng Giếng Acid Nitric HNO3 siêu cấp tiêu dung.\\n\\n**Dây Lò Đốt Bột Diêm Sinh Dệt Axit:**\\nThuốc Mìn S rải lửa đốt khí Oxi $\\\\rightarrow$ Phục vụ Khói Xưởng SO2 $\\\\rightarrow$ Xài Tháp Ngưng Vanadi V2O5 ép ra SO3 Trắng Lì $\\\\rightarrow$ Nhồi Nước tạo Phễu Xả Axit H2SO4 $\\\\rightarrow$ Khóa mõm nó bằng gốc Tủa BaCl2 đọng cặn Trắng tinh BaSO4 gục mạng."}},{"id":"mod5","type":"heading","content":{"text":"3. Các dạng bài tập lớn","level":"h2"}},{"id":"mod6","type":"list","content":{"type":"bullet","items":["Những Cạm bẫy Bẻ não Thi Tốt nghiệp Quốc Gia:","1. Chống Mắt Tự Phán đoán Sản phẩm Khử: Dây HNO3 loãng tạo N2Oười nhạt. Axit ĐẶC HNO3 đứt ruột nhả NO2 ngáo nâu. Nhưng Kim loại Mạng Hổ Trâu Mg/Al cắm vào nát Nh2 HNO3 quá Loãng, ép chọc nhứ N xuống thẳng hầm mù ra vỏ Cặn Phân Bón mặn chát Ammonium Nitrate ($NH_4NO_3$).","2. Ma Pháp Bảo Toàn Electron siêu tốc: Không thèm viết phương trình dông dài cân bằng rác rưởi. Tổng Mol Electron Kim Loại Nhả Bỏ ĐỨT ĐUÔI = Bằng Tổng số Mol e bọn Khí/Ion nhận trọn. Xối rã mọi hệ ẩn.","3. Trò đùa Thụ động Lưỡng Tâm (Al, Fe, Cr đóng băng não lì trước cặp H2SO4 đặc + HNO3 đặc để dạng Lạnh lùng Nguội Xút)."]}},{"id":"mod7","type":"warningBox","content":{"color":"orange","title":"Thuật Tầm Giao Nhận Diện Chỉ Báo","content":"Lấy Giầy Thông Hành Ghi Tên Lọ Hóa Chất Mất Nhãn:\\n- Mùi Khai Đái dội quỳ Xanh: Gây bởi Amonia NH3 đùn thuốc NaOH nóng.\\n- Mùi Hắc Sốc Rát Cổ Tẩy trắng Nước Brom nâu: Ngáo Phản Độc SO2.\\n- Cặn Đọng Hồ Trắng Nặng nề BaSO4: Đó là dấu Nhẫn Lệnh Ion $SO_4^{2-}$."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=GCsDlcJla__","title":"Ôn tập chương 2: Nitrogen - Sulfur","thumbnail":"https://img.youtube.com/vi/GCsDlcJla__/0.jpg","description":"Tổng kết kiến thức trọng tâm chương 2 and giải bài tập tự luyện (Tech12h)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 9. Ôn tập chương 2 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 9. Ôn tập chương 2 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 9. Ôn tập chương 2?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 9. Ôn tập chương 2 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 9. Ôn tập chương 2?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 9. Ôn tập chương 2?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 9. Ôn tập chương 2 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 9. Ôn tập chương 2?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 9. Ôn tập chương 2, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 9. Ôn tập chương 2 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 9. Ôn tập chương 2 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 9. Ôn tập chương 2 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 9. Ôn tập chương 2?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 9. Ôn tập chương 2 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 9. Ôn tập chương 2?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 9. Ôn tập chương 2?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 9. Ôn tập chương 2 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 9. Ôn tập chương 2?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 9. Ôn tập chương 2, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 9. Ôn tập chương 2 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 9. Ôn tập chương 2 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 9. Ôn tập chương 2 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 9. Ôn tập chương 2 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 9. Ôn tập chương 2, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 9. Ôn tập chương 2?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 9. Ôn tập chương 2 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 9. Ôn tập chương 2?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 9. Ôn tập chương 2 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 9. Ôn tập chương 2?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 9. Ôn tập chương 2 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai1', 12, 'ketnoi', 'Bài 1. Ester – Lipid', 'Chương 1. Ester – lipid', 1, 'Khái niệm, cấu tạo, danh pháp và tính chất đặc trưng của ester và lipid. Phản ứng thủy phân, xà phòng hóa.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm và Danh pháp Ester","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Ester là hợp chất hữu cơ được tạo thành khi thay thế nhóm -OH trong nhóm carboxyl của carboxylic acid bằng nhóm -OR'' của alcohol. Công thức tổng quát của ester no, đơn chức, mạch hở là **$C_nH_{2n}O_2$ ($n \\\\ge 2$)**. Ester thường có nhiệt độ sôi thấp hơn acid và alcohol có cùng khối lượng phân tử do không có liên kết hydrogen liên phân tử. Hầu hết các ester có mùi thơm dễ chịu của hoa quả tự nhiên."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Danh pháp và Một số gốc thông dụng","content":"**Tên Ester = Tên gốc hydrocarbon (R'') + Tên gốc acid (đuôi -at)**.\\n- $CH_3COOC_2H_5$: Ethyl acetate (mùi chuối chín).\\n- $CH_2=CH-COOCH_3$: Methyl acrylate.\\n- $CH_3COOCH=CH_2$: Vinyl acetate.\\n- $HCOOCH_3$: Methyl formate."}},{"id":"mod4","type":"heading","content":{"text":"2. Tính chất hóa học đặc trưng","level":"h2"}},{"id":"mod5","type":"list","content":{"type":"bullet","items":["**Thủy phân trong môi trường Acid (Phản ứng thuận nghịch):** Khi đun nóng ester với nước và xúc tác acid ($H_2SO_4$ loãng), ester bị thủy phân tạo thành acid và alcohol. Đây là phản ứng thuận nghịch, cân bằng thiết lập chậm: $RCOOR'' + H_2O \\\\rightleftharpoons^{H^+, t^\\\\circ} RCOOH + R''OH$. Hiệu suất phản ứng phụ thuộc vào việc chuyển dịch cân bằng (ví dụ: dùng dư nước hoặc tách bớt sản phẩm).","**Thủy phân trong môi trường Kiềm (Phản ứng xà phòng hóa):** Khi đun nóng ester với dung dịch kiềm ($NaOH, KOH$), ester bị thủy phân tạo thành muối của acid (xà phòng) và alcohol. Đây là phản ứng một chiều, xảy ra hoàn toàn: $RCOOR'' + NaOH \\\\xrightarrow{t^\\\\circ} RCOONa + R''OH$. Phản ứng này là cơ sở của công nghiệp sản xuất xà phòng."]}},{"id":"mod6","type":"heading","content":{"text":"3. Lipid và Chất Béo (Triglyceride)","level":"h2"}},{"id":"mod7","type":"paragraph","content":{"text":"Lipid là nhóm các hợp chất hữu cơ phức tạp, không tan trong nước nhưng tan tốt trong các dung môi hữu cơ không phân cực. Phân loại lipid bao gồm chất béo (triglyceride), sáp, steroid và phospholipid. Chất béo là triester của glycerol với các acid béo (acid đơn chức, mạch carbon dài, số carbon chẵn). Công thức tổng quát: $(RCOO)_3C_3H_5$."}},{"id":"mod8","type":"infoBox","content":{"color":"green","title":"Các Acid béo quan trọng và Trạng thái vật lí","content":"1. **Acid béo no**: Acid palmitic ($C_{15}H_{31}COOH$), acid stearic ($C_{17}H_{35}COOH$). Chúng tạo nên chất béo rắn (mỡ động vật).\\\\n2. **Acid béo không no**: Acid oleic ($C_{17}H_{33}COOH$ - có 1 liên kết đôi), acid linoleic ($C_{17}H_{31}COOH$ - có 2 liên kết đôi). Chúng tạo nên chất béo lỏng (dầu thực vật).\\\\n**Phản ứng Hydrogen hóa**: Chất béo lỏng (gốc không no) tác dụng với $H_2$ ($Ni, t^\\\\circ$) sẽ chuyển thành chất béo rắn (gốc no). Đây là quy trình sản xuất bơ nhân tạo (margarine) từ dầu thực vật."}},{"id":"mod9","type":"warningBox","content":{"color":"orange","title":"Vai trò sinh học và Hiện tượng ôi thiu","content":"Chất béo là nguồn dự trữ năng lượng tập trung ($1g$ chất béo giải phóng $\\\\approx 9 kcal$), đồng thời là dung môi hòa tan các vitamin tan trong dầu (A, D, E, K). Tuy nhiên, khi để lâu trong không khí, các liên kết đôi $C=C$ trong chất béo không no bị oxi hóa chậm tạo thành các peroxide, sau đó phân hủy thành các aldehyde và ketone có mùi khó chịu (hiện tượng ôi thiu). Để hạn chế, cần bảo quản chất béo ở nơi khô ráo, thoáng mát, tránh ánh sáng trực tiếp."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=hEuHcAhAwu8","title":"Bài giảng lý thuyết: Ester - Lipid","thumbnail":"https://img.youtube.com/vi/hEuHcAhAwu8/0.jpg","description":"Video giảng chi tiết về khái niệm, danh pháp và tính chất của Ester và Lipid (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 1. Ester – Lipid là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 1. Ester – Lipid là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 1. Ester – Lipid?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 1. Ester – Lipid thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 1. Ester – Lipid?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 1. Ester – Lipid?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 1. Ester – Lipid trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 1. Ester – Lipid?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 1. Ester – Lipid, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 1. Ester – Lipid giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 1. Ester – Lipid là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 1. Ester – Lipid là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 1. Ester – Lipid?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 1. Ester – Lipid thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 1. Ester – Lipid?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 1. Ester – Lipid?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 1. Ester – Lipid trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 1. Ester – Lipid?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 1. Ester – Lipid, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 1. Ester – Lipid giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 1. Ester – Lipid tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 1. Ester – Lipid với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 1. Ester – Lipid thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 1. Ester – Lipid, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 1. Ester – Lipid?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 1. Ester – Lipid vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 1. Ester – Lipid?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 1. Ester – Lipid lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 1. Ester – Lipid?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 1. Ester – Lipid là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai10', 12, 'ketnoi', 'Bài 10. Protein và enzyme', 'Chương 3. Hợp chất chứa nitrogen', 10, 'Cấu trúc protein. Tính chất đông tụ, phản ứng màu và bản chất xúc tác sinh học của enzyme.', '[{"id":"mod1","type":"heading","content":{"text":"1. Protein","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Protein là những polypeptide cao phân tử có khối lượng phân tử lớn (từ vài chục nghìn đến vài triệu đơn vị carbon). Protein được chia thành hai loại chính: Protein đơn giản (khi thủy phân chỉ thu được các $\\\\alpha$-amino acid, ví dụ: albumin trong lòng trắng trứng, fibroin trong tơ tằm) và Protein phức tạp (được tạo thành từ protein đơn giản kết hợp với các thành phần phi protein như lipid, carbohydrate, nucleic acid...)."}},{"id":"mod3","type":"list","content":{"type":"bullet","items":["**Tính chất đông tụ:** Khi đun nóng hoặc cho thêm acid, base, muối vào dung dịch protein, protein sẽ bị đông tụ lại (ví dụ: luộc trứng, làm đậu phụ). Đây là hiện tượng protein mất đi cấu trúc bậc cao nhưng vẫn giữ nguyên cấu trúc bậc 1.","**Phản ứng thủy phân:** Tương tự peptide, protein thủy phân nhờ acid, base hoặc enzyme sinh ra các chuỗi peptide ngắn hơn và cuối cùng là các $\\\\alpha$-amino acid.","**Phản ứng màu:** Protein có phản ứng màu Biuret (tạo màu tím) và phản ứng với $HNO_3$ đặc tạo kết tủa màu vàng (do phản ứng nitrat hóa các vòng thơm trong protein)."]}},{"id":"mod4","type":"heading","content":{"text":"2. Enzyme và Nucleic acid","level":"h2"}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Bản chất và Đặc điểm của Enzyme","content":"Enzyme là những chất xúc tác sinh học có bản chất hầu hết là protein. Chúng có hai đặc điểm nổi bật:\\n1. **Tính xúc tác cực mạnh**: Tốc độ phản ứng dưới sự xúc tác của enzyme nhanh gấp hàng triệu đến hàng tỉ lần so với chất xúc tác vô cơ.\\n2. **Tính chọn lọc cao**: Mỗi enzyme thường chỉ xúc tác cho một phản ứng nhất định hoặc một kiểu phản ứng nhất định đối với một chất nhất định."}},{"id":"mod6","type":"paragraph","content":{"text":"Nucleic acid (DNA và RNA) là những polynucleotide có vai trò quan trọng trong việc lưu trữ và truyền đạt thông tin di truyền ở mọi sinh vật sống. Chúng được cấu tạo từ các đơn vị nucleotide liên kết với nhau bằng liên kết phosphodiester."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=F0Oq2fXpU-M","title":"Bài giảng: Protein and Enzyme","thumbnail":"https://img.youtube.com/vi/F0Oq2fXpU-M/0.jpg","description":"Cấu trúc, tính chất của protein and vai trò của enzyme trong cơ thể (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 10. Protein và enzyme là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 10. Protein và enzyme là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 10. Protein và enzyme?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 10. Protein và enzyme thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 10. Protein và enzyme?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 10. Protein và enzyme?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 10. Protein và enzyme trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 10. Protein và enzyme?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 10. Protein và enzyme, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 10. Protein và enzyme giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 10. Protein và enzyme là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 10. Protein và enzyme là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 10. Protein và enzyme?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 10. Protein và enzyme thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 10. Protein và enzyme?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 10. Protein và enzyme?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 10. Protein và enzyme trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 10. Protein và enzyme?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 10. Protein và enzyme, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 10. Protein và enzyme giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 10. Protein và enzyme tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 10. Protein và enzyme với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 10. Protein và enzyme thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 10. Protein và enzyme, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 10. Protein và enzyme?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 10. Protein và enzyme vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 10. Protein và enzyme?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 10. Protein và enzyme lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 10. Protein và enzyme?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 10. Protein và enzyme là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai11', 12, 'ketnoi', 'Bài 11. Ôn tập chương 3', 'Chương 3. Hợp chất chứa nitrogen', 11, 'Tổng kết Amine, Amino acid, Peptide và Protein. Mối liên hệ cấu tạo và tính chất đặc trưng.', '[{"id":"mod1","type":"heading","content":{"text":"1. Hệ thống hóa Amine và Amino acid","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["**Amine:** Thể hiện tính base do cặp electron tự do trên nguyên tử N. Amine béo > NH3 > Amine thơm. Aniline có phản ứng đặc trưng với nước bromine tạo kết tủa trắng.","**Amino acid:** Là hợp chất lưỡng tính (tác dụng với cả acid và base mạnh). Tồn tại dưới dạng ion lưỡng cực nên là chất rắn, tan tốt trong nước. Glycine, Alanine, Valine là 3 amino acid trung tính; Glutamic acid có tính acid; Lysine có tính base."]}},{"id":"mod3","type":"heading","content":{"text":"2. Peptide và Protein","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Các phản ứng đặc trưng cần ghi nhớ","content":"1. **Phản ứng thủy phân**: Đặc điểm chung của peptide và protein dưới tác dụng của xúc tác acid/base hoặc enzyme $\\\\rightarrow$ tạo amino acid.\\n2. **Phản ứng màu Biuret**: Phức chất màu tím với $Cu(OH)_2/NaOH$ (áp dụng cho peptide có $\\\\ge$ 2 liên kết peptide và protein).\\n3. **Phản ứng với $HNO_3$ đặc**: Kết tủa màu vàng đặc trưng của protein.\\n4. **Tính đông tụ của protein**: Khi thay đổi nhiệt độ hoặc pH."}},{"id":"mod5","type":"warningBox","content":{"color":"orange","title":"Kỹ năng giải bài tập chương 3","content":"**1. Bảo toàn khối lượng**: Dùng cho phản ứng thủy phân peptide ($m_{Peptide} + m_{H_2O} = m_{Amino acid}$).\\n**2. Bảo toàn nguyên tố N**: Số mol N trong peptide bằng tổng số mol N trong các amino acid cấu thành.\\\\n**3. Phản ứng đốt cháy**: Cần chú ý đến lượng khí Nitrogen ($N_2$) thoát ra."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=F3zZ5L_Zf2g","title":"Ôn tập chương 3: Hợp chất chứa nitrogen","thumbnail":"https://img.youtube.com/vi/F3zZ5L_Zf2g/0.jpg","description":"Tổng kết kiến thức trọng tâm and giải bài tập ôn tập chương 3 (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 11. Ôn tập chương 3 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 11. Ôn tập chương 3 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 11. Ôn tập chương 3?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 11. Ôn tập chương 3 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 11. Ôn tập chương 3?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 11. Ôn tập chương 3?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 11. Ôn tập chương 3 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 11. Ôn tập chương 3?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 11. Ôn tập chương 3, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 11. Ôn tập chương 3 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 11. Ôn tập chương 3 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 11. Ôn tập chương 3 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 11. Ôn tập chương 3?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 11. Ôn tập chương 3 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 11. Ôn tập chương 3?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 11. Ôn tập chương 3?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 11. Ôn tập chương 3 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 11. Ôn tập chương 3?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 11. Ôn tập chương 3, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 11. Ôn tập chương 3 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 11. Ôn tập chương 3 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 11. Ôn tập chương 3 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 11. Ôn tập chương 3 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 11. Ôn tập chương 3, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 11. Ôn tập chương 3?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 11. Ôn tập chương 3 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 11. Ôn tập chương 3?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 11. Ôn tập chương 3 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 11. Ôn tập chương 3?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 11. Ôn tập chương 3 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai12', 12, 'ketnoi', 'Bài 12. Đại cương về polymer', 'Chương 4. Polymer và vật liệu polymer', 12, 'Khái niệm, phân loại và các phương pháp điều chế polymer (trùng hợp, trùng ngưng).', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm và Phân loại Polymer","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Polymer là những hợp chất có khối lượng phân tử rất lớn do nhiều đơn vị nhỏ (gọi là mắt xích) liên kết với nhau tạo nên. Tên của polymer thường được ghép từ tiền tố ''poly'' với tên của monomer tương ứng."}},{"id":"mod3","type":"list","content":{"type":"bullet","items":["**Phân loại theo nguồn gốc:** Polymer thiên nhiên (tinh bột, cellulose, cao su thiên nhiên), Polymer tổng hợp (polyethylene, tơ nylon-6,6), Polymer bán tổng hợp hay nhân tạo (tơ viscose, tơ cellulose acetate).","**Phân loại theo cấu trúc:** Mạch không phân nhánh (amylose, PVC), Mạch phân nhánh (amylopectin, glycogen), Mạch mạng không gian (cao su lưu hóa, nhựa bakelite)."]}},{"id":"mod4","type":"heading","content":{"text":"2. Phương pháp điều chế Polymer","level":"h2"}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Phản ứng Trùng hợp","content":"Là quá trình kết hợp nhiều phân tử nhỏ (monomer) giống nhau hay tương tự nhau thành phân tử rất lớn (polymer). **Điều kiện của monomer**: Phân tử phải có liên kết bội (như $CH_2=CH_2$) hoặc vòng không bền có thể mở vòng được.\\nVí dụ: $n CH_2=CH_2 \\\\xrightarrow{t^\\\\circ, p, xt} (-CH_2-CH_2-)_{n} \\\\quad (PE)$."}},{"id":"mod6","type":"infoBox","content":{"color":"green","title":"Phản ứng Trùng ngưng","content":"Là quá trình kết hợp nhiều phân tử nhỏ (monomer) thành phân tử lớn (polymer) đồng thời giải phóng các phân tử nhỏ khác (thường là nước). **Điều kiện của monomer**: Phân tử phải có ít nhất hai nhóm chức có khả năng phản ứng (như $-OH, -COOH, -NH_2$).\\nVí dụ: Trùng ngưng n-aminoacid tạo tơ nylon."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=R9Z8-2vK-XQ","title":"Bài giảng: Đại cương về Polymer","thumbnail":"https://img.youtube.com/vi/R9Z8-2vK-XQ/0.jpg","description":"Khái niệm, phân loại, cấu tạo and các phương pháp điều chế polymer (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 12. Đại cương về polymer là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 12. Đại cương về polymer là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 12. Đại cương về polymer?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 12. Đại cương về polymer thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 12. Đại cương về polymer?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 12. Đại cương về polymer?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 12. Đại cương về polymer trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 12. Đại cương về polymer?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 12. Đại cương về polymer, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 12. Đại cương về polymer giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 12. Đại cương về polymer là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 12. Đại cương về polymer là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 12. Đại cương về polymer?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 12. Đại cương về polymer thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 12. Đại cương về polymer?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 12. Đại cương về polymer?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 12. Đại cương về polymer trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 12. Đại cương về polymer?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 12. Đại cương về polymer, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 12. Đại cương về polymer giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 12. Đại cương về polymer tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 12. Đại cương về polymer với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 12. Đại cương về polymer thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 12. Đại cương về polymer, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 12. Đại cương về polymer?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 12. Đại cương về polymer vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 12. Đại cương về polymer?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 12. Đại cương về polymer lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 12. Đại cương về polymer?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 12. Đại cương về polymer là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai13', 12, 'ketnoi', 'Bài 13. Vật liệu polymer', 'Chương 4. Polymer và vật liệu polymer', 13, 'Các loại vật liệu polymer quan trọng: Chất dẻo, tơ sợi, cao su và keo dán.', '[{"id":"mod1","type":"heading","content":{"text":"1. Chất dẻo (Plastics)","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["**Khái niệm:** Chất dẻo là những vật liệu polymer có tính dẻo (bị biến dạng khi chịu tác dụng của nhiệt, áp suất và vẫn giữ nguyên sự biến dạng đó khi thôi tác dụng).","**Một số chất dẻo quan trọng:** Polyethylene (PE), Poly(vinyl chloride) (PVC), Poly(methyl methacrylate) (Plexiglas - thủy tinh hữu cơ), Poly(phenol-formaldehyde) (PPF)."]}},{"id":"mod3","type":"heading","content":{"text":"2. Tơ (Fibers)","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Phân loại Tơ","content":"1. **Tơ thiên nhiên**: Bông, len, tơ tằm.\\n2. **Tơ hóa học**:\\n   - **Tơ vổng hợp**: Chế biến từ polymer tổng hợp (tơ nylon-6,6, tơ nitron/olon).\\n   - **Tơ bán tổng hợp (nhân tạo)**: Chế biến từ polymer thiên nhiên (tơ viscose, tơ cellulose acetate)."}},{"id":"mod5","type":"heading","content":{"text":"3. Cao su (Rubber)","level":"h2"}},{"id":"mod6","type":"paragraph","content":{"text":"Cao su là vật liệu polymer có tính đàn hồi. Cao su thiên nhiên được lấy từ mủ cây cao su, là polymer của isoprene ($C_5H_8$). Cao su tổng hợp bao gồm cao su buna ($n CH_2=CH-CH=CH_2$), cao su buna-S, cao su buna-N. Quá trình **lưu hóa cao su** là tạo ra các cầu nối disulfide ($-S-S-$) giữa các mạch polymer, làm tăng tính đàn hồi và độ bền nhiệt của cao su."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=1F9-o_e6A0o","title":"Bài giảng: Vật liệu Polymer","thumbnail":"https://img.youtube.com/vi/1F9-o_e6A0o/0.jpg","description":"Tìm hiểu về chất dẻo, tơ sợi, cao su and keo dán (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 13. Vật liệu polymer là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 13. Vật liệu polymer là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 13. Vật liệu polymer?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 13. Vật liệu polymer thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 13. Vật liệu polymer?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 13. Vật liệu polymer?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 13. Vật liệu polymer trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 13. Vật liệu polymer?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 13. Vật liệu polymer, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 13. Vật liệu polymer giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 13. Vật liệu polymer là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 13. Vật liệu polymer là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 13. Vật liệu polymer?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 13. Vật liệu polymer thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 13. Vật liệu polymer?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 13. Vật liệu polymer?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 13. Vật liệu polymer trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 13. Vật liệu polymer?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 13. Vật liệu polymer, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 13. Vật liệu polymer giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 13. Vật liệu polymer tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 13. Vật liệu polymer với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 13. Vật liệu polymer thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 13. Vật liệu polymer, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 13. Vật liệu polymer?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 13. Vật liệu polymer vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 13. Vật liệu polymer?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 13. Vật liệu polymer lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 13. Vật liệu polymer?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 13. Vật liệu polymer là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai14', 12, 'ketnoi', 'Bài 14. Ôn tập chương 4', 'Chương 4. Polymer', 14, 'Hệ thống hóa kiến thức về polymer: Cấu trúc, phương pháp điều chế và ứng dụng của các loại vật liệu polymer.', '[{"id":"mod1","type":"heading","content":{"text":"1. Phân biệt Phản ứng Trùng hợp và Trùng ngưng","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["**Phản ứng trùng hợp:** Kết hợp các monomer có liên kết bội ($C=C, C \\\\equiv C$) hoặc vòng kém bền thành polymer. Khối lượng phân tử polymer là bội số của monomer, không có sản phẩm phụ.","**Phản ứng trùng ngưng:** Kết hợp các monomer có ít nhất hai nhóm chức chức có khả năng phản ứng. Ngoài polymer, phản ứng còn giải phóng các phân tử nhỏ (thường là $H_2O$)."]}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Phân loại theo cấu trúc không gian","content":"- **Mạch không phân nhánh:** Hầu hết các loại polymer thông dụng như PE, PVC, nylon-6,6, tơ nitron, amylose.\\n- **Mạch phân nhánh:** Amylopectin (trong tinh bột) và glycogen.\\n- **Mạng lưới không gian:** Cao su lưu hóa và nhựa bakelite (nhựa chân de). Cấu trúc này giúp vật liệu bền vững, khó nóng chảy và khó hòa tan hơn."}},{"id":"mod4","type":"heading","content":{"text":"2. Phân loại theo nguồn gốc và Bản chất","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Việc phân loại polymer dựa trên nguồn gốc là một nội dung quan trọng trong các kỳ thi:\\n- **Polymer thiên nhiên:** Có sẵn trong tự nhiên (cellulose, tinh bột, tơ tằm, cao su thiên nhiên).\\n- **Polymer bán tổng hợp (nhân tạo):** Được chế biến từ polymer thiên nhiên (tơ visco, tơ acetate).\\n- **Polymer tổng hợp:** Do con người tổng hợp nên hoàn toàn từ các hóa chất đơn giản (PE, PVC, nylon-6,6, cao su buna)."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=7QBv-KQiXDI","title":"Ôn tập chương 4: Polymer và vật liệu Polymer","thumbnail":"https://img.youtube.com/vi/7QBv-KQiXDI/0.jpg","description":"Hệ thống hóa kiến thức chương 4 và giải bài tập củng cố về các loại vật liệu (Tech12h)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 14. Ôn tập chương 4 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 14. Ôn tập chương 4 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 14. Ôn tập chương 4?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 14. Ôn tập chương 4 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 14. Ôn tập chương 4?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 14. Ôn tập chương 4?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 14. Ôn tập chương 4 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 14. Ôn tập chương 4?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 14. Ôn tập chương 4, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 14. Ôn tập chương 4 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 14. Ôn tập chương 4 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 14. Ôn tập chương 4 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 14. Ôn tập chương 4?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 14. Ôn tập chương 4 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 14. Ôn tập chương 4?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 14. Ôn tập chương 4?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 14. Ôn tập chương 4 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 14. Ôn tập chương 4?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 14. Ôn tập chương 4, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 14. Ôn tập chương 4 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 14. Ôn tập chương 4 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 14. Ôn tập chương 4 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 14. Ôn tập chương 4 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 14. Ôn tập chương 4, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 14. Ôn tập chương 4?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 14. Ôn tập chương 4 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 14. Ôn tập chương 4?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 14. Ôn tập chương 4 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 14. Ôn tập chương 4?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 14. Ôn tập chương 4 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai15', 12, 'ketnoi', 'Bài 15. Thế điện cực và nguồn điện hoá học', 'Chương 5. Pin điện và điện phân', 15, 'Nguyên lý hoạt động của pin điện hóa. Tìm hiểu về thế điện cực chuẩn, suất điện động của pin và các loại nguồn điện thông dụng.', '[{"id":"mod1","type":"heading","content":{"text":"1. Nguyên lý hoạt động của Pin điện hóa","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Pin điện hóa là thiết bị chuyển hóa năng lượng của phản ứng oxi hóa - khử tự phát thành điện năng. Một pin điện hóa điển hình gồm hai nửa tế bào (hai điện cực) nối với nhau bằng cầu muối. Trong pin, dòng electron di chuyển từ cực âm sang cực dương ở mạch ngoài, tạo ra dòng điện một chiều."}},{"id":"mod3","type":"list","content":{"type":"bullet","items":["**Anode (Cực âm -):** Là điện cực xảy ra quá trình oxi hóa (kim loại mạnh hơn nhường electron). Ví dụ: $Zn \\\\rightarrow Zn^{2+} + 2e^-$.","**Cathode (Cực dương +):** Là điện cực xảy ra quá trình khử (ion kim loại yếu hơn nhận electron). Ví dụ: $Cu^{2+} + 2e^- \\\\rightarrow Cu$."]}},{"id":"mod4","type":"heading","content":{"text":"2. Pin Daniell và Cầu muối","level":"h2"}},{"id":"mod5","type":"infoBox","content":{"color":"blue","title":"Cấu tạo Pin Daniell","content":"Pin Daniell gồm thanh kẽm nhúng trong dung dịch $ZnSO_4$ và thanh đồng nhúng trong dung dịch $CuSO_4$, hai dung dịch nối với nhau bằng cầu muối (chứa dung dịch chất điện li trơ như $KNO_3$ hoặc $KCl$).\\n- **Vai trò cầu muối**: Giúp duy trì sự trung hòa điện trong cả hai nửa tế bào bằng cách cho các ion di chuyển qua lại, đảm bảo pin hoạt động liên tục."}},{"id":"mod6","type":"heading","content":{"text":"3. Thế điện cực chuẩn và Suất điện động","level":"h2"}},{"id":"mod7","type":"paragraph","content":{"text":"Để đánh giá sức mạnh oxi hóa - khử của một cặp điện cực, người ta sử dụng **Thế điện cực chuẩn** ($E^o$), được đo so với Điện cực Hydrogen chuẩn ($E^o(2H^+/H_2) = 0V$). Suất điện động của pin ($E^o_{pin}$) được tính bằng hiệu số giữa thế điện cực của cathode và anode:\\n**$E^o_{pin} = E^o_{cathode} - E^o_{anode}$**.\\nGiá trị $E^o_{pin}$ luôn dương đối với các pin điện hóa hoạt động tự phát."}},{"id":"mod8","type":"warningBox","content":{"color":"orange","title":"Pin và Acquy thực tế","content":"- **Pin sơ cấp**: Chỉ dùng một lần, phản ứng hóa học không thể đảo ngược (ví dụ: pin kẽm-carbon).\\n- **Pin thứ cấp (Acquy/Pin sạc)**: Có thể nạp điện (sạc) để sử dụng nhiều lần do phản ứng hóa học trong pin có tính thuận nghịch. Pin Lithium-ion trong điện thoại và xe điện là đại diện tiêu biểu nhờ mật độ năng lượng cao và tuổi thọ lớn."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=oKKg9Hs0xL0","title":"Bài giảng: Thế điện cực và Nguồn điện hóa học","thumbnail":"https://img.youtube.com/vi/oKKg9Hs0xL0/0.jpg","description":"Nguyên lý hoạt động của pin điện hóa, suất điện động và cách tính hiệu điện thế (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 15. Thế điện cực và nguồn điện hoá học là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 15. Thế điện cực và nguồn điện hoá học là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 15. Thế điện cực và nguồn điện hoá học?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 15. Thế điện cực và nguồn điện hoá học thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 15. Thế điện cực và nguồn điện hoá học?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 15. Thế điện cực và nguồn điện hoá học?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 15. Thế điện cực và nguồn điện hoá học trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 15. Thế điện cực và nguồn điện hoá học?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 15. Thế điện cực và nguồn điện hoá học, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 15. Thế điện cực và nguồn điện hoá học giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 15. Thế điện cực và nguồn điện hoá học là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 15. Thế điện cực và nguồn điện hoá học là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 15. Thế điện cực và nguồn điện hoá học?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 15. Thế điện cực và nguồn điện hoá học thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 15. Thế điện cực và nguồn điện hoá học?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 15. Thế điện cực và nguồn điện hoá học?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 15. Thế điện cực và nguồn điện hoá học trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 15. Thế điện cực và nguồn điện hoá học?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 15. Thế điện cực và nguồn điện hoá học, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 15. Thế điện cực và nguồn điện hoá học giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 15. Thế điện cực và nguồn điện hoá học tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 15. Thế điện cực và nguồn điện hoá học với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 15. Thế điện cực và nguồn điện hoá học thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 15. Thế điện cực và nguồn điện hoá học, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 15. Thế điện cực và nguồn điện hoá học?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 15. Thế điện cực và nguồn điện hoá học vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 15. Thế điện cực và nguồn điện hoá học?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 15. Thế điện cực và nguồn điện hoá học lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 15. Thế điện cực và nguồn điện hoá học?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 15. Thế điện cực và nguồn điện hoá học là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai17', 12, 'ketnoi', 'Bài 17. Ôn tập chương 5', 'Chương 5. Pin điện và điện phân', 17, 'Tổng kết kiến thức về pin điện hóa và điện phân. Phân biệt bản chất và quy tắc xác định sản phẩm tại các điện cực.', '[{"id":"mod1","type":"heading","content":{"text":"1. So sánh Pin điện và Điện phân","level":"h2"}},{"id":"mod2","type":"list","content":{"type":"bullet","items":["**Pin điện hóa:** Chuyển hóa năng lượng của phản ứng hóa học tự phát thành điện năng. Đây là nguồn điện (cung cấp dòng điện cho mạch ngoài).","**Điện phân:** Chuyển hóa điện năng từ nguồn ngoài thành năng lượng hóa học để thực hiện các phản ứng không tự phát. Đây là thiết bị tiêu thụ năng lượng điện."]}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Quy tắc xác định tên điện cực","content":"Một nguyên tắc thống nhất cho cả hai quá trình:\\n- **Anode** luôn là nơi xảy ra quá trình **oxi hóa**.\\n- **Cathode** luôn là nơi xảy ra quá trình **khử**.\\nTuy nhiên, dấu của điện cực sẽ khác nhau:\\n- Trong **Pin điện**: Anode là cực âm (-), Cathode là cực dương (+).\\n- Trong **Điện phân**: Anode nối với cực dương (+) của nguồn, Cathode nối với cực âm (-) của nguồn."}},{"id":"mod4","type":"heading","content":{"text":"2. Chiến thuật giải bài toán điện phân","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Để giải quyết các bài toán định lượng điện phân, cần sử dụng bảo toàn electron xuyên suốt các điện cực. Số mol electron trao đổi được tính theo công thức:\\n**$n_e = \\\\frac{I \\\\cdot t}{F}$**\\nSau đó, dựa vào các bán phương trình tại anode và cathode để tính khối lượng hay thể tích các chất tạo thành. Cần đặc biệt chú ý đến thứ tự ưu tiên của các ion và sự tham gia của nước khi các ion chính đã hết hoặc không bị điện phân."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=lryaZcP35kI","title":"Ôn tập chương 5: Pin điện và Điện phân","thumbnail":"https://img.youtube.com/vi/lryaZcP35kI/0.jpg","description":"Tổng kết kiến thức trọng tâm chương 5 và hướng dẫn giải các dạng bài tập thực tế (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 17. Ôn tập chương 5 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 17. Ôn tập chương 5 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 17. Ôn tập chương 5?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 17. Ôn tập chương 5 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 17. Ôn tập chương 5?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 17. Ôn tập chương 5?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 17. Ôn tập chương 5 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 17. Ôn tập chương 5?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 17. Ôn tập chương 5, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 17. Ôn tập chương 5 giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 17. Ôn tập chương 5 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 17. Ôn tập chương 5 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 17. Ôn tập chương 5?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 17. Ôn tập chương 5 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 17. Ôn tập chương 5?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 17. Ôn tập chương 5?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 17. Ôn tập chương 5 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 17. Ôn tập chương 5?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 17. Ôn tập chương 5, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 17. Ôn tập chương 5 giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 17. Ôn tập chương 5 tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 17. Ôn tập chương 5 với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 17. Ôn tập chương 5 thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 17. Ôn tập chương 5, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 17. Ôn tập chương 5?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 17. Ôn tập chương 5 vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 17. Ôn tập chương 5?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 17. Ôn tập chương 5 lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 17. Ôn tập chương 5?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 17. Ôn tập chương 5 là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":350,"rewardGem":30,"difficulty":4,"rewardItemId":"item_rare_crystal"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai18', 12, 'ketnoi', 'Bài 18. Cấu tạo và liên kết trong tinh thể kim loại', 'Chương 6. Đại cương về kim loại', 18, 'Cấu trúc nguyên tử, mạng tinh thể và bản chất liên kết kim loại thông qua mô hình ''biển electron'' tự do.', '[{"id":"mod1","type":"heading","content":{"text":"1. Vị trí và Cấu tạo nguyên tử Kim loại","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Trong bảng tuần hoàn, các nguyên tố kim loại chiếm đa số (hơn 80%), bao gồm các nhóm IA (trừ H), IIA, IIIA (trừ B), các nhóm B (từ IB đến VIIIB), họ lanthanide và actinide. Về cấu tạo nguyên tử, hầu hết các kim loại có ít electron ở lớp ngoài cùng (1, 2 hoặc 3e). Do bán kính nguyên tử thường lớn và số electron lớp ngoài cùng ít, các nguyên tử kim loại dễ nhường electron để đạt cấu hình electron bền vững của khí hiếm, thể hiện **tính khử** đặc trưng: $M \\\\rightarrow M^{n+} + ne$."}},{"id":"mod3","type":"heading","content":{"text":"2. Mạng tinh thể kim loại","level":"h2"}},{"id":"mod4","type":"paragraph","content":{"text":"Ở trạng thái rắn (trừ thủy ngân), các kim loại có cấu tạo mạng tinh thể. Trong đó, các ion dương kim loại nằm ở các nút mạng, còn các electron hóa trị liên kết lỏng lẻo với hạt nhân di chuyển tự do trong toàn bộ mạng lưới tinh thể."}},{"id":"mod5","type":"list","content":{"type":"bullet","items":["**Mạng lập phương tâm khối (bcc):** Nguyên tử/ion nằm ở các đỉnh và tâm của hình lập phương. Độ rỗng lớn (độ đặc khít 68%). Ví dụ: Li, Na, K, V, Cr..","**Mạng lập phương tâm diện (fcc):** Nguyên tử/ion nằm ở các đỉnh và tâm các mặt của hình lập phương. Độ đặc khít cao (74%). Ví dụ: Cu, Ag, Au, Al, Ni.","**Mạng lục phương xếp chặt (hcp):** Các nguyên tử/ion xếp khít nhau theo cấu trúc lục giác. Độ đặc khít cao (74%). Ví dụ: Mg, Zn, Be."]}},{"id":"mod6","type":"heading","content":{"text":"3. Liên kết kim loại","level":"h2"}},{"id":"mod7","type":"infoBox","content":{"color":"blue","title":"Mô hình Biển Electron tự do","content":"Liên kết kim loại là loại liên kết được hình thành giữa các nguyên tử và ion kim loại trong mạng tinh thể nhờ sự tham gia của các electron tự do. Các electron này không thuộc về riêng một hạt nhân nào mà di chuyển khắp mạng lưới, tạo thành một ''biển electron'' gắn kết các ion dương lại với nhau. Đây là nguyên nhân chính tạo nên các tính chất vật lí chung của kim loại như tính dẫn điện, dẫn nhiệt, tính dẻo và ánh kim."}},{"id":"mod8","type":"warningBox","content":{"color":"orange","title":"Phân biệt các loại liên kết","content":"- **Liên kết ion**: Lực hút tĩnh điện giữa các ion mang điện tích trái dấu (thường là kim loại điển hình và phi kim điển hình).\\n- **Liên kết cộng hóa trị**: Hình thành bằng các cặp electron dùng chung giữa hai nguyên tử phi kim.\\n- **Liên kết kim loại**: Hình thành nhờ các electron tự do dùng chung cho toàn bộ mạng tinh thể kim loại."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=dTWdi85PTpk","title":"Bài giảng: Cấu tạo nguyên tử và liên kết kim loại","thumbnail":"https://img.youtube.com/vi/dTWdi85PTpk/0.jpg","description":"Tìm hiểu cấu tạo tinh thể kim loại và bản chất của liên kết kim loại (mô hình biển electron) (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 18. Cấu tạo và liên kết trong tinh thể kim loại là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 18. Cấu tạo và liên kết trong tinh thể kim loại là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 18. Cấu tạo và liên kết trong tinh thể kim loại?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 18. Cấu tạo và liên kết trong tinh thể kim loại?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 18. Cấu tạo và liên kết trong tinh thể kim loại?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 18. Cấu tạo và liên kết trong tinh thể kim loại là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 18. Cấu tạo và liên kết trong tinh thể kim loại là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 18. Cấu tạo và liên kết trong tinh thể kim loại?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 18. Cấu tạo và liên kết trong tinh thể kim loại?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 18. Cấu tạo và liên kết trong tinh thể kim loại?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 18. Cấu tạo và liên kết trong tinh thể kim loại tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 18. Cấu tạo và liên kết trong tinh thể kim loại với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 18. Cấu tạo và liên kết trong tinh thể kim loại thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 18. Cấu tạo và liên kết trong tinh thể kim loại, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 18. Cấu tạo và liên kết trong tinh thể kim loại vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 18. Cấu tạo và liên kết trong tinh thể kim loại lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 18. Cấu tạo và liên kết trong tinh thể kim loại là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai19', 12, 'ketnoi', 'Bài 19. Tính chất vật lí và tính chất hoá học của kim loại', 'Chương 6. Đại cương về kim loại', 19, 'Các tính chất vật lí chung (dẻo, dẫn điện, nhiệt, ánh kim) và tính chất hóa học đặc trưng (tính khử) của kim loại.', '[{"id":"mod1","type":"heading","content":{"text":"1. Tính chất Vật lí của Kim loại","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Các tính chất vật lí chung của kim loại như tính dẻo, tính dẫn điện, dẫn nhiệt và ánh kim đều do sự có mặt của các electron tự do trong mạng tinh thể quyết định."}},{"id":"mod3","type":"list","content":{"type":"bullet","items":["**Tính dẻo:** Khi bị tác dụng lực, các lớp ion dương kim loại có thể trượt lên nhau nhưng vẫn liên kết với nhau nhờ biển electron tự do. Vàng là kim loại dẻo nhất.","**Tính dẫn điện:** Dòng electron tự do dịch chuyển có hướng dưới tác dụng của hiệu điện thế. Thứ tự dẫn điện giảm dần: $Ag > Cu > Au > Al > Fe$.","**Tính dẫn nhiệt:** Các electron tự do ở vùng nhiệt độ cao có động năng lớn, chuyển động hỗn loạn và truyền nhiệt năng cho các vùng khác thông qua va chạm.","**Ánh kim:** Các electron tự do phản xạ hầu hết các tia sáng nhìn thấy được khi chiếu vào bề mặt kim loại phẳng."]}},{"id":"mod4","type":"heading","content":{"text":"2. Tính chất Hóa học đặc trưng: Tính khử","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Đặc điểm cấu tạo nguyên tử của kim loại (ít electron lớp ngoài cùng, bán kính lớn) khiến chúng dễ nhường electron để trở thành ion dương. Vì vậy, kim loại thể hiện tính khử mạnh khi tác dụng với các chất oxi hóa."}},{"id":"mod6","type":"list","content":{"type":"bullet","items":["**Tác dụng với phi kim:** Kim loại phản ứng với $O_2$ (tạo oxide), $Cl_2$ (tạo chloride), $S$ (tạo sulfide)... ở nhiệt độ cao. Ví dụ: $3Fe + 2O_2 \\\\rightarrow Fe_3O_4$.","**Tác dụng với dung dịch acid thường ($HCl, H_2SO_4$ loãng):** Các kim loại đứng trước hydrogen trong dãy hoạt động hóa học đẩy được $H_2$ ra khỏi dung dịch acid. Ví dụ: $Fe + 2HCl \\\\rightarrow FeCl_2 + H_2 \\\\uparrow$.","**Tác dụng với dung dịch acid mạnh ($HNO_3, H_2SO_4$ đặc):** Phản ứng với hầu hết các kim loại (trừ $Au, Pt$) giải phóng các sản phẩm khử của $N$ hoặc $S$ ($NO_2, NO, SO_2...$) mà không giải phóng $H_2$. **Lưu ý**: $Al, Fe, Cr$ bị thụ động hóa trong $HNO_3, H_2SO_4$ đặc, nguội.","**Tác dụng với dung dịch muối:** Kim loại mạnh hơn (đứng trước) có thể đẩy kim loại yếu hơn (đứng sau) ra khỏi muối. Ví dụ: $Fe + CuSO_4 \\\\rightarrow FeSO_4 + Cu \\\\downarrow$."]}},{"id":"mod7","type":"warningBox","content":{"color":"green","title":"Dãy điện hóa của kim loại","content":"Thứ tự tính khử giảm dần của kim loại: $K, Na, Ba, Ca, Mg, Al, Zn, Fe, Ni, Sn, Pb, H, Cu, Hg, Ag, Pt, Au$. Kim loại càng đứng trước càng dễ nhường electron, ion kim loại càng đứng sau càng dễ nhận electron (tính oxi hóa mạnh hơn)."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=D5OosK53G6E","title":"Bài giảng: Tính chất vật lí và hóa học của kim loại","thumbnail":"https://img.youtube.com/vi/D5OosK53G6E/0.jpg","description":"Giải thích các tính chất vật lí chung của kim loại và đặc trưng phản ứng hóa học (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 19. Tính chất vật lí và tính chất hoá học của kim loại là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 19. Tính chất vật lí và tính chất hoá học của kim loại là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 19. Tính chất vật lí và tính chất hoá học của kim loại?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 19. Tính chất vật lí và tính chất hoá học của kim loại thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 19. Tính chất vật lí và tính chất hoá học của kim loại?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 19. Tính chất vật lí và tính chất hoá học của kim loại?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 19. Tính chất vật lí và tính chất hoá học của kim loại trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 19. Tính chất vật lí và tính chất hoá học của kim loại?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 19. Tính chất vật lí và tính chất hoá học của kim loại, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 19. Tính chất vật lí và tính chất hoá học của kim loại giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục