:["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 19. Tính chất vật lí và tính chất hoá học của kim loại?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 19. Tính chất vật lí và tính chất hoá học của kim loại, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 19. Tính chất vật lí và tính chất hoá học của kim loại giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 19. Tính chất vật lí và tính chất hoá học của kim loại tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 19. Tính chất vật lí và tính chất hoá học của kim loại với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 19. Tính chất vật lí và tính chất hoá học của kim loại thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 19. Tính chất vật lí và tính chất hoá học của kim loại, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 19. Tính chất vật lí và tính chất hoá học của kim loại?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 19. Tính chất vật lí và tính chất hoá học của kim loại vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 19. Tính chất vật lí và tính chất hoá học của kim loại?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 19. Tính chất vật lí và tính chất hoá học của kim loại lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 19. Tính chất vật lí và tính chất hoá học của kim loại?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 19. Tính chất vật lí và tính chất hoá học của kim loại là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":100,"rewardGem":5,"difficulty":1,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai2', 12, 'ketnoi', 'Bài 2. Xà phòng và chất giặt rửa', 'Chương 1. Ester – lipid', 2, 'Cơ chế hoạt động của xà phòng, phân biệt xà phòng tự nhiên với chất giặt rửa tổng hợp.', '[{"id":"mod1","type":"heading","content":{"text":"1. Xà phòng","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Xà phòng là hỗn hợp muối sodium ($Na^+$) hoặc potassium ($K^+$) của các acid béo cao (như palmitic acid, stearic acid, oleic acid). Xà phòng thường được sản xuất bằng cách đun nóng chất béo với dung dịch kiềm ($NaOH$ hoặc $KOH$). Muối sodium tạo ra xà phòng bánh cứng, trong khi muối potassium tạo ra xà phòng lỏng hoặc mềm."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Quy trình sản xuất xà phòng","content":"Trong công nghiệp, xà phòng được sản xuất chủ yếu từ chất béo tự nhiên. Tuy nhiên, để tiết kiệm nguồn thực phẩm, người ta còn oxi hóa paraffin (nhu phẩm dầu mỏ) để thu được các acid béo nhân tạo, sau đó trung hòa bằng kiềm. Glycerol ($C_3H_5(OH)_3$) là sản phẩm phụ quan trọng thu được từ quá trình này, được ứng dụng rộng rãi trong mỹ phẩm và dược phẩm."}},{"id":"mod4","type":"heading","content":{"text":"2. Chất giặt rửa tổng hợp","level":"h2"}},{"id":"mod5","type":"paragraph","content":{"text":"Chất giặt rửa tổng hợp (như bột giặt, nước rửa chén) là những hợp chất không phải muối của acid béo nhưng có tính năng tẩy rửa tương tự xà phòng. Các hợp chất này thường là muối sodium alkyl sulfate ($R-O-SO_3Na$) hoặc sodium alkylbenzene sulfonate ($R-C_6H_4-SO_3Na$). Chúng được tổng hợp từ các dẫn xuất của dầu mỏ."}},{"id":"mod6","type":"heading","content":{"text":"3. Cơ chế tẩy rửa và Ảnh hưởng của nước cứng","level":"h2"}},{"id":"mod7","type":"infoBox","content":{"color":"green","title":"Cấu trúc lưỡng tính và Hạt Micelle","content":"Cả xà phòng và chất giặt rửa tổng hợp đều có cấu trúc phân tử gồm hai phần: một ''đầu'' ưa nước (phân cực) và một ''đuôi'' kị nước (mạch dài hydrocarbon không phân cực). Khi tẩy rửa, các đuôi kị nước hòa tan vào vết dầu mỡ, trong khi các đầu ưa nước hướng ra ngoài nước, bao bọc vết bẩn tạo thành các hạt cẩu siêu nhỏ (micelle). Các hạt này đẩy nhau và bị dòng nước cuốn trôi, giúp làm sạch bề mặt vải hoặc vật dụng."}},{"id":"mod8","type":"warningBox","content":{"color":"orange","title":"Ưu nhược điểm và Tác động môi trường","content":"Xà phòng có ưu điểm là dễ bị phân hủy sinh học, thân thiện với môi trường. Tuy nhiên, nó bị mất tác dụng trong **nước cứng** (nước chứa nhiều ion $Ca^{2+}, Mg^{2+}$) do tạo thành kết tủa muối kị nước không tan. Chất giặt rửa tổng hợp không bị ảnh hưởng bởi nước cứng nhưng các loại chứa mạch carbon phân nhánh rất khó bị vi sinh vật phân hủy, gây ô nhiễm nguồn nước và hiện tượng bọt bao phủ bề mặt sông ngòi."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=ZD8onrVXsbY","title":"Bài giảng: Xà phòng và chất giặt rửa","thumbnail":"https://img.youtube.com/vi/ZD8onrVXsbY/0.jpg","description":"Tìm hiểu về cơ chế tẩy rửa của xà phòng và các loại chất giặt rửa tổng hợp (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 2. Xà phòng và chất giặt rửa là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 2. Xà phòng và chất giặt rửa là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 2. Xà phòng và chất giặt rửa?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 2. Xà phòng và chất giặt rửa thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 2. Xà phòng và chất giặt rửa?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 2. Xà phòng và chất giặt rửa?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 2. Xà phòng và chất giặt rửa trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 2. Xà phòng và chất giặt rửa?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 2. Xà phòng và chất giặt rửa, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 2. Xà phòng và chất giặt rửa giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 2. Xà phòng và chất giặt rửa là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 2. Xà phòng và chất giặt rửa là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 2. Xà phòng và chất giặt rửa?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 2. Xà phòng và chất giặt rửa thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 2. Xà phòng và chất giặt rửa?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 2. Xà phòng và chất giặt rửa?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 2. Xà phòng và chất giặt rửa trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 2. Xà phòng và chất giặt rửa?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 2. Xà phòng và chất giặt rửa, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 2. Xà phòng và chất giặt rửa giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 2. Xà phòng và chất giặt rửa tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 2. Xà phòng và chất giặt rửa với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 2. Xà phòng và chất giặt rửa thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 2. Xà phòng và chất giặt rửa, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 2. Xà phòng và chất giặt rửa?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 2. Xà phòng và chất giặt rửa vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 2. Xà phòng và chất giặt rửa?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 2. Xà phòng và chất giặt rửa lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 2. Xà phòng và chất giặt rửa?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 2. Xà phòng và chất giặt rửa là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai20', 12, 'ketnoi', 'Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại', 'Chương 6. Đại cương về kim loại', 20, 'Trạng thái tự nhiên của kim loại và các phương pháp luyện kim cơ bản: Nhiệt luyện, Thủy luyện và Điện phân.', '[{"id":"mod1","type":"heading","content":{"text":"1. Trạng thái tự nhiên của Kim loại","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Trong tự nhiên, hầu hết các kim loại tồn tại dưới dạng hợp chất (oxide, sulfide, carbonate, silicate...) gọi là quặng. Chỉ một số ít kim loại kém hoạt động (như Au, Pt) có thể tồn tại ở dạng đơn chất (trạng thái tự do). Tùy vào hàm lượng kim loại và trữ lượng mà các mỏ quặng được khai thác để phục vụ công nghiệp luyện kim."}},{"id":"mod3","type":"heading","content":{"text":"2. Nguyên tắc và Phương pháp Điều chế Kim loại","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Nguyên tắc chung của Luyện kim","content":"Bản chất của việc điều chế kim loại là khử các ion kim loại trong hợp chất thành nguyên tử:\\n**$M^{n+} + ne \\\\rightarrow M$**.\\nĐể thực hiện quá trình này, người ta sử dụng các tác nhân khử như hóa chất ($C, CO, H_2$, kim loại mạnh hơn) hoặc dòng điện một chiều."}},{"id":"mod5","type":"heading","content":{"text":"3. Các phương pháp luyện kim cơ bản","level":"h2"}},{"id":"mod6","type":"list","content":{"type":"bullet","items":["**Phương pháp Nhiệt luyện:** Dùng các chất khử mạnh ($C, CO, H_2, Al$) để khử ion kim loại trong oxide ở nhiệt độ cao. Phương pháp này áp dụng cho các kim loại có tính khử trung bình và yếu (sau Al trong dãy điện hóa) như Zn, Fe, Sn, Pb, Cu...","**Phương pháp Thủy luyện:** Dùng dung dịch hòa tan quặng (thường là acid hoặc kiềm) sau đó dùng kim loại mạnh hơn để đẩy kim loại yếu hơn ra khỏi dung dịch muối. Ví dụ: Dùng Fe đẩy Cu ra khỏi dung dịch $CuSO_4$.","**Phương pháp Điện phân:** \\n- **Điện phân nóng chảy**: Là phương pháp duy nhất để điều chế các kim loại hoạt động mạnh (kiềm, kiềm thổ, nhôm). Ví dụ: Điện phân nóng chảy $Al_2O_3$ (có thêm cryolite) để sản xuất nhôm.\\n- **Điện phân dung dịch**: Áp dụng cho các kim loại trung bình và yếu đứng sau Al."]}},{"id":"mod7","type":"warningBox","content":{"color":"orange","title":"Lưu ý về phương pháp Nhiệt nhôm","content":"Phản ứng nhiệt nhôm là một dạng của nhiệt luyện, sử dụng bột nhôm ($Al$) làm chất khử mạnh để điều chế các kim loại như Fe, Cr từ oxide tương ứng ở nhiệt độ rất cao. Phản ứng này tỏa nhiệt lượng cực lớn và thường được dùng cho các mục đích đặc biệt như hàn đường ray."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=4nRR7xtfi7E","title":"Bài giảng: Kim loại trong tự nhiên và tách kim loại","thumbnail":"https://img.youtube.com/vi/4nRR7xtfi7E/0.jpg","description":"Sơ lược về quặng kim loại và các phương pháp luyện kim: nhiệt luyện, thủy luyện, điện phân (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 20. Kim loại trong tự nhiên và phương pháp tách kim loại là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai21', 12, 'ketnoi', 'Bài 21. Hợp kim', 'Chương 6. Đại cương về kim loại', 21, 'Khái niệm, tính chất và ứng dụng của các loại hợp kim quan trọng như gang, thép, đồng thau và duralumin.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm và Tính chất của Hợp Kim","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Hợp kim là vật liệu kim loại có chứa một kim loại cơ bản và một số kim loại hoặc phi kim khác. Hợp kim thường được chế tạo bằng cách làm nóng chảy hỗn hợp các thành phần rồi để nguội cho kết tinh."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Ưu điểm của Hợp kim so với Kim loại nguyên chất","content":"- **Độ bền cơ học**: Hợp kim thường cứng và bền hơn kim loại thành phần do sự có mặt của các nguyên tử khác kích thước làm cản trở sự trượt của các lớp mạng tinh thể.\\n- **Khả năng chống ăn mòn**: Nhiều hợp kim có khả năng chịu hóa chất và chống gỉ sét vượt trội (như thép không gỉ).\\n- **Nhiệt độ nóng chảy**: Hợp kim thường có nhiệt độ nóng chảy thấp hơn các kim loại thành phần.\\n- **Tính dẫn điện và nhiệt**: Thường kém hơn kim loại nguyên khối do mạng tinh thể bị biến dạng."}},{"id":"mod4","type":"heading","content":{"text":"2. Một số Hợp kim quan trọng","level":"h2"}},{"id":"mod5","type":"list","content":{"type":"bullet","items":["**Hợp kim của Sắt:**\\n  - **Gang**: Hợp kim Fe-C (hàm lượng C từ 2 - 5%), ngoài ra còn có Si, Mn, S... Gang cứng và giòn.\\n  - **Thép**: Hợp kim Fe-C (hàm lượng C dưới 2%), bền, dẻo, dễ rèn và gia công. Thép không gỉ (Inox) chứa thêm Cr và Ni.","**Hợp kim của Đồng:**\\n  - **Đồng thau**: Hợp kim Cu-Zn, có màu vàng, độ bền cao, dùng chế tạo thiết bị điện, nhạc cụ.\\n  - **Đồng bạch**: Hợp kim Cu-Ni, bền trong nước biển.\\n  - **Đồng thiếc (Đồng thanh)**: Hợp kim Cu-Sn.","**Hợp kim của Nhôm:**\\n  - **Duralumin**: Hợp kim Al-Cu-Mg-Mn, nhẹ bằng 1/3 thép nhưng độ bền tương đương thép, dùng rộng rãi trong công nghiệp hàng không."]}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Ứng dụng thực tiễn","content":"Trong đời sống và sản xuất, hợp kim được sử dụng phổ biến hơn nhiều so với kim loại nguyên chất nhờ các đặc tính cơ lí đặc biệt, cho phép con người thiết kế các vật liệu chuyên dụng cho từng môi trường khắc nghiệt."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=w5WhyYGHt7I","title":"Bài giảng: Hợp kim","thumbnail":"https://img.youtube.com/vi/w5WhyYGHt7I/0.jpg","description":"Khái niệm vật liệu hợp kim và sự đa dạng hóa tính bền vững của kim loại gốc (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 21. Hợp kim là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 21. Hợp kim là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 21. Hợp kim?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 21. Hợp kim thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 21. Hợp kim?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 21. Hợp kim?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 21. Hợp kim trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 21. Hợp kim?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 21. Hợp kim, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 21. Hợp kim giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 21. Hợp kim là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 21. Hợp kim là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 21. Hợp kim?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 21. Hợp kim thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 21. Hợp kim?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 21. Hợp kim?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 21. Hợp kim trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 21. Hợp kim?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 21. Hợp kim, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 21. Hợp kim giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 21. Hợp kim tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 21. Hợp kim với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 21. Hợp kim thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 21. Hợp kim, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 21. Hợp kim?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 21. Hợp kim vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 21. Hợp kim?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 21. Hợp kim lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 21. Hợp kim?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 21. Hợp kim là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai22', 12, 'ketnoi', 'Bài 22. Sự ăn mòn kim loại', 'Chương 6. Đại cương về kim loại', 22, 'Nguyên nhân và cơ chế của sự ăn mòn kim loại. Phân biệt ăn mòn hóa học và ăn mòn điện hóa cùng các phương pháp bảo vệ.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm Sự ăn mòn kim loại","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Sự ăn mòn kim loại là sự phá hủy kim loại hoặc hợp kim do tác dụng hóa học của các chất trong môi trường xung quanh. Bản chất của quá trình này là sự oxi hóa kim loại: $M \\\\rightarrow M^{n+} + ne$."}},{"id":"mod3","type":"heading","content":{"text":"2. Phân loại Ăn mòn kim loại","level":"h2"}},{"id":"mod4","type":"infoBox","content":{"color":"blue","title":"Ăn mòn hóa học và Ăn mòn điện hóa","content":"- **Ăn mòn hóa học**: Là quá trình oxi hóa - khử, trong đó các electron của kim loại được chuyển trực tiếp đến các chất oxi hóa trong môi trường (như $O_2, Cl_2$) ở nhiệt độ cao. Không phát sinh dòng điện.\\n- **Ăn mòn điện hóa**: Là quá trình oxi hóa - khử xảy ra do tác dụng của dung dịch chất điện li và tạo nên dòng điện. Đây là dạng ăn mòn phổ biến và gây hại nghiêm trọng nhất trong thực tế (ví dụ: sự gỉ sét của gang, thép trong không khí ẩm)."}},{"id":"mod5","type":"list","content":{"type":"bullet","items":["**Điều kiện xảy ra ăn mòn điện hóa:**\\n  1. Có hai điện cực khác chất nhau (kim loại - kim loại hoặc kim loại - phi kim) tiếp xúc trực tiếp hoặc gián tiếp qua dây dẫn.\\n  2. Các điện cực cùng nhúng vào dung dịch chất điện li.\\n  3. Xảy ra quá trình nhường và nhận electron giữa hai điện cực thông qua mạch ngoài."]}},{"id":"mod6","type":"heading","content":{"text":"3. Phương pháp chống ăn mòn kim loại","level":"h2"}},{"id":"mod7","type":"paragraph","content":{"text":"**Phương pháp bảo vệ bề mặt**: Cách li kim loại với môi trường bằng các lớp phủ bảo vệ như sơn, mỡ, mạ các kim loại bền (Cr, Ni, Sn, Zn) hoặc tráng men.\\n\\n**Phương pháp điện hóa (Bảo vệ bằng vật hi sinh)**: Dùng một kim loại hoạt động mạnh hơn làm vật hi sinh để bảo vệ kim loại cơ bản. Ví dụ: Gắn các khối kẽm ($Zn$) vào vỏ tàu biển bằng thép ($Fe$). Khi đó kẽm là anode sẽ bị ăn mòn trước, thép là cathode được bảo vệ."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=a0p1rzZYwoY","title":"Bài giảng: Sự ăn mòn kim loại","thumbnail":"https://img.youtube.com/vi/a0p1rzZYwoY/0.jpg","description":"Phân loại Ăn mòn Hóa học và Ăn mòn Điện hóa cùng các biện pháp bảo vệ (VietJack)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 22. Sự ăn mòn kim loại là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 22. Sự ăn mòn kim loại là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 22. Sự ăn mòn kim loại?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 22. Sự ăn mòn kim loại thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 22. Sự ăn mòn kim loại?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 22. Sự ăn mòn kim loại?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 22. Sự ăn mòn kim loại trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 22. Sự ăn mòn kim loại?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 22. Sự ăn mòn kim loại, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 22. Sự ăn mòn kim loại giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Bài 22. Sự ăn mòn kim loại là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 22. Sự ăn mòn kim loại là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 22. Sự ăn mòn kim loại?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 22. Sự ăn mòn kim loại thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 22. Sự ăn mòn kim loại?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 22. Sự ăn mòn kim loại?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 22. Sự ăn mòn kim loại trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 22. Sự ăn mòn kim loại?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 22. Sự ăn mòn kim loại, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Bài 22. Sự ăn mòn kim loại giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Bài 22. Sự ăn mòn kim loại tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Bài 22. Sự ăn mòn kim loại với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Bài 22. Sự ăn mòn kim loại thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Bài 22. Sự ăn mòn kim loại, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Bài 22. Sự ăn mòn kim loại?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Bài 22. Sự ăn mòn kim loại vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Bài 22. Sự ăn mòn kim loại?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Bài 22. Sự ăn mòn kim loại lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Bài 22. Sự ăn mòn kim loại?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Bài 22. Sự ăn mòn kim loại là gì?"}]}', '[]', '[]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', null), ('hoa12_kntt_bai23', 12, 'ketnoi', 'Bài 23. Ôn tập chương 6', 'Chương 6. Đại cương về kim loại', 23, 'Tổng kết kiến thức về đại cương kim loại: Dãy điện hóa, quy tắc Alpha và các cơ chế ăn mòn.', '[{"id":"mod1","type":"heading","content":{"text":"1. Dãy điện hóa của Kim loại","level":"h2"}},{"id":"mod2","type":"infoBox","content":{"color":"blue","title":"Ý nghĩa của dãy điện hóa","content":"Dãy điện hóa cho phép so sánh tính khử của các kim loại và tính oxi hóa của các ion kim loại:\\n- Từ trái sang phải: Tính khử của kim loại giảm dần, tính oxi hóa của ion kim loại tăng dần.\\n- Kim loại đứng trước có tính khử mạnh hơn kim loại đứng sau. Ion kim loại đứng sau có tính oxi hóa mạnh hơn ion kim loại đứng trước."}},{"id":"mod3","type":"heading","content":{"text":"2. Quy tắc Alpha ($\\\\alpha$)","level":"h2"}},{"id":"mod4","type":"paragraph","content":{"text":"Quy tắc Alpha xác định chiều của phản ứng oxi hóa - khử giữa hai cặp oxi hóa - khử: Chất oxi hóa mạnh nhất sẽ phản ứng với chất khử mạnh nhất để tạo ra chất oxi hóa yếu hơn và chất khử yếu hơn.\\nVí dụ: Giữa cặp $Mg^{2+}/Mg$ và $Cu^{2+}/Cu$, phản ứng xảy ra là: $Mg + Cu^{2+} \\\\rightarrow Mg^{2+} + Cu$."}},{"id":"mod5","type":"heading","content":{"text":"3. Phân biệt Ăn mòn hóa học và Ăn mòn điện hóa","level":"h2"}},{"id":"mod6","type":"paragraph","content":{"text":"Trong ôn tập, cần đặc biệt lưu ý các dấu hiệu nhận biết ăn mòn điện hóa: \\n- Phải có sự tiếp xúc của hai chất dẫn điện khác nhau.\\n- Cùng nhúng trong một dung dịch chất điện li (thường là không khí ẩm hoặc nước biển).\\n- Kim loại có tính khử mạnh hơn luôn là anode và bị ăn mòn."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=QUtfBVwseS4","title":"Ôn tập chương 6: Đại cương về kim loại","thumbnail":"https://img.youtube.com/vi/QUtfBVwseS4/0.jpg","description":"Tổng kết dãy điện hóa, tính chất và các quy luật phản ứng của kim loại (Tech12h)."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Bài 23. Ôn tập chương 6 là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Bài 23. Ôn tập chương 6 là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Bài 23. Ôn tập chương 6?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Bài 23. Ôn tập chương 6 thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Bài 23. Ôn tập chương 6?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Bài 23. Ôn tập chương 6?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Bài 23. Ôn tập chương 6 trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Bài 23. Ôn tập chương 6?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Bài 23. Ôn tập chương 6, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các t