lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Giới thiệu Hợp chất hữu cơ với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Giới thiệu Hợp chất hữu cơ thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Giới thiệu Hợp chất hữu cơ, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Giới thiệu Hợp chất hữu cơ?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Giới thiệu Hợp chất hữu cơ vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Giới thiệu Hợp chất hữu cơ?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Giới thiệu Hợp chất hữu cơ lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Giới thiệu Hợp chất hữu cơ?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Giới thiệu Hợp chất hữu cơ là gì?"}]}', '[]', '[{"type":"image-selection","images":["https://images.unsplash.com/photo-1605600611284-19561ad7ddf4?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1543163521-1bf539c55dd2?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1595113316349-9fa4ee24f884?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=400&q=80"],"source":"Đời sống quanh ta","question":"Hình ảnh nào mô tả túi nilon — một sản phẩm hữu cơ polymer phổ biến nhất?","narrative":"Hợp chất hữu cơ có mặt ở khắp mọi nơi, từ thực phẩm chúng ta ăn đến các loại đồ dùng hàng ngày. Bạn có nhận ra vật thể nào làm từ PE (một loại dẫn xuất hữu cơ) không?","targetType":"nhận biết","correctAnswer":0},{"type":"matching","items":[{"id":"o1","label":"Đường, Rượu, Protein, Vitamin"},{"id":"o2","label":"Muối ăn (NaCl), Axit sunfuric"},{"id":"o3","label":"$CO, CO_2,$ Muối Carbonate"}],"source":"Khái niệm nền tảng","question":"Phân loại các chất thành Hữu cơ hoặc Vô cơ.","leftItems":[{"id":"o1","label":"Hợp chất Hữu cơ"},{"id":"o2","label":"Hợp chất Vô cơ"},{"id":"o3","label":"Trường hợp ngoại lệ (Vô cơ)"}],"narrative":"Thế giới vật chất được chia thành hai ''vương quốc''. Hãy giúp tôi phân loại chúng thật chính xác nhé.","correctOrder":["o1","o2","o3"]},{"type":"multiple-choice","source":"Nguyên tố cốt lõi","options":["Carbon (C)","Oxygen (O)","Hydrogen (H)","Nitrogen (N)"],"question":"Nguyên tố nào buộc phải có mặt trong mọi hợp chất hữu cơ?","narrative":"Mọi hợp chất hữu cơ đều có một nguyên tố ''xương sống'' tạo nên cấu trúc mạch dài. Đó là nguyên tố nào?","correctAnswer":0},{"type":"fill-in-the-blank","source":"Phân loại","question":"Tên gọi của nhóm hợp chất chứa C, H và nguyên tố khác là gì?","narrative":"Hợp chất hữu cơ được chia thành hai nhóm: Hydrocarbon (chỉ có C and H) và ... của hydrocarbon (có thêm O, N, Cl...).","placeholder":"Nhập thuật ngữ...","correctAnswer":"Dẫn xuất"},{"type":"drag-drop","items":[{"id":"c1","label":"Dễ cháy"},{"id":"c2","label":"Kém bền nhiệt"},{"id":"c3","label":"Nóng chảy thấp"}],"source":"Tính chất chung","question":"Sắp xếp 3 đặc điểm hóa lý đặc trưng nhất của hợp chất hữu cơ.","narrative":"Đặc tính ''nhạy cảm'' với nhiệt là đặc trưng của hữu cơ. Hãy hoàn thành các đặc điểm chung sau.","correctOrder":["c1","c2","c3"]}]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227908/chemistry-odyssey/curriculum/yiutxcsdkaoy9tg8rvae.mp4'), ('hoa9_kntt_bai6', 9, 'ketnoi', 'Bài 6: Alkane', null, 6, 'Khám phá cấu trúc, tính chất vật lí và hóa học đặc trưng của nhóm Hydrocarbon NO - những ''viên gạch'' đầu tiên của hóa hữu cơ.', '[{"id":"mod1","type":"heading","content":{"text":"1. Alkane là gì?","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Alkane là những Hydrocarbon mạch hở mà trong phân tử chỉ có các liên kết đơn. Công thức tổng quát là $C_nH_{2n+2}$ ($n \\\\ge 1$)."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Methane ($CH_4$) - Thủ lĩnh Alkane","content":"Là chất khí không màu, không mùi, nhẹ hơn không khí ($d \\\\approx 0.55$). Methane là thành phần chính trong khí thiên nhiên, khí mỏ dầu và khí bùn ao."}},{"id":"mod4","type":"heading","content":{"text":"2. Tính chất hóa học đặc trưng","level":"h2"}},{"id":"mod5","type":"list","content":{"items":["**Phản ứng Cháy:** Tỏa nhiều nhiệt, tạo thành $CO_2$ và $H_2O$. Phương trình: $CH_4 + 2O_2 \\\\xrightarrow{t^o} CO_2 + 2H_2O$.","**Phản ứng Thế (Đặc trưng):** Khi có ánh sáng, một nguyên tử Clo sẽ thế vào chỗ của một nguyên tử Hidro. Ví dụ: $CH_4 + Cl_2 \\\\xrightarrow{as} CH_3Cl + HCl$."]}},{"id":"mod6","type":"warningBox","content":{"color":"red","title":"Nguy hiểm cháy nổ","content":"Hỗn hợp Methane và Oxy theo tỷ lệ thể tích 1:2 là hỗn hợp nổ cực mạnh. Đây là nguyên nhân chính gây ra các vụ nổ mỏ than thảm khốc."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=thDcSdqDd38","title":"Alkane: Gia đình Hydrocarbon NO","thumbnail":"https://img.youtube.com/vi/thDcSdqDd38/0.jpg","description":"Tại sao Methane lại được gọi là ''khí bùn ao''?"}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Alkane là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Alkane là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Alkane?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Alkane thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Alkane?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Alkane?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Alkane trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Alkane?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Alkane, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Alkane giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Alkane là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Alkane là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Alkane?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Alkane thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Alkane?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Alkane?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Alkane trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Alkane?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Alkane, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Alkane giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Alkane tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Alkane với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Alkane thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Alkane, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Alkane?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Alkane vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Alkane?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Alkane lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Alkane?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Alkane là gì?"}]}', '[]', '[{"type":"image-selection","images":["https://images.unsplash.com/photo-1542332213-9b5a5a3fad35?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1595113316349-9fa4ee24f884?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1628155930542-3c7a64e2c833?auto=format&fit=crop&w=400&q=80"],"source":"Trạng thái tự nhiên","question":"Hình ảnh nào mô tả khu vực đầm lầy — nơi sản sinh ra lượng lớn Methane tự nhiên?","narrative":"Methane thường xuất hiện ở những nơi giàu chất hữu cơ phân hủy thiếu oxy. Bạn có biết hình ảnh nào bên dưới mô tả nguồn gốc tự nhiên của ''khí bùn ao'' không?","targetType":"nhận biết","correctAnswer":0},{"type":"matching","items":[{"id":"me1","label":"Chỉ có liên kết đơn C-H"},{"id":"me2","label":"Nhẹ hơn không khí, không màu"},{"id":"me3","label":"Phản ứng thế đặc trưng với Clo"}],"source":"Tổng hợp kiến thức","question":"Kết nối đối tượng với thuộc tính tương ứng của Methane.","leftItems":[{"id":"me1","label":"Cấu tạo"},{"id":"me2","label":"Vật lí"},{"id":"me3","label":"Hóa học"}],"narrative":"Hãy giúp tôi phân loại đặc điểm của Methane ($CH_4$) - thủ lĩnh của gia tộc Alkane.","correctOrder":["me1","me2","me3"]},{"type":"multiple-choice","source":"Điều kiện phản ứng","options":["Ánh sáng mặt trời (hoặc ánh sáng khuếch tán)","Nhiệt độ cực thấp","Chất xúc tác là Sắt","Dòng điện cao thế"],"question":"Điều kiện cần thiết cho phản ứng thế của Alkane với Clo là gì?","narrative":"Trong cuộc chiến thay đổi ''nhân sự'', Methane mời Chlorine vào thay thế vị trí của Hydrogen. Điều kiện tiên quyết để phản ứng này xảy ra là gì?","correctAnswer":0},{"type":"fill-in-the-blank","source":"An toàn cháy nổ","question":"Tỷ lệ thể tích của Oxy trong hỗn hợp nổ mạnh nhất với Methane là bao nhiêu?","narrative":"Hỗn hợp nổ nguy hiểm nhất của Methane và Oxy xảy ra khi tỷ lệ số phân tử Methane : Oxy là 1 : ...","placeholder":"Nhập con số...","correctAnswer":"2"},{"type":"drag-drop","items":[{"id":"r1","label":"$CH_4$"},{"id":"r2","label":"+"},{"id":"r3","label":"$2O_2$"},{"id":"r4","label":"\\\\xrightarrow{t^o}"},{"id":"r5","label":"$CO_2 + 2H_2O$"}],"source":"Phương trình hóa học","question":"Sắp xếp phương trình phản ứng đúng trình tự.","narrative":"Thử thách cân bằng: Hãy sắp xếp các mảnh ghép để hoàn thiện phương trình phản ứng cháy của Methane.","correctOrder":["r1","r2","r3","r4","r5"]}]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227912/chemistry-odyssey/curriculum/v4a3rxdyv82vo52dhiv8.mp4'), ('hoa9_kntt_bai7', 9, 'ketnoi', 'Bài 7: Alkene', null, 7, 'Tìm hiểu về Ethylene ($C_2H_4$) - đại diện tiêu biểu của nhóm Alkene với liên kết đôi bứt phá và khả năng tạo nên vật liệu nhựa PE thần kỳ.', '[{"id":"mod1","type":"heading","content":{"text":"1. Cấu trúc Liên kết Đôi","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Khác với Alkane chỉ có liên kết đơn, Alkene chứa ít nhất một **liên kết đôi** ($C=C$). Trong liên kết đôi này, có một liên kết bền và một liên kết kém bền (liên kết $\\\\pi$) dễ bị bẻ gãy."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Ethylene ($C_2H_4$) - Đại diện tiêu biểu","content":"Là chất khí không màu, không mùi, ít tan trong nước. Đặc biệt, Ethylene có khả năng kích thích trái cây chín nhanh một cách tự nhiên."}},{"id":"mod4","type":"heading","content":{"text":"2. Phản ứng hóa học đặc trưng","level":"h2"}},{"id":"mod5","type":"list","content":{"items":["**Phản ứng Cộng (Đặc trưng):** Ethylene làm mất màu dung dịch nước Brom. Phương trình: $CH_2=CH_2 + Br_2 \\\\rightarrow CH_2Br-CH_2Br$.","**Phản ứng Trùng hợp:** Nhiều phân tử Ethylene kết hợp lại tạo thành chuỗi dài gọi là Polyethylene (nhựa PE).","**Phản ứng Cháy:** Tạo ra $CO_2$ và $H_2O$, tỏa nhiều nhiệt."]}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Nhận biết Hydrocarbon không no","content":"Dung dịch **Brom** là ''thuốc thử'' vàng để phân biệt Alkene (mất màu Brom) và Alkane (không phản ứng ở điều kiện thường)."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=Tp3V2Jfcux4","title":"Ethylene: Nguồn gốc của Nhựa","thumbnail":"https://img.youtube.com/vi/Tp3V2Jfcux4/0.jpg","description":"Khám phá bí mật về liên kết đôi giúp trái cây chín nhanh và tạo ra polymer."}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Alkene là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Alkene là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Alkene?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Alkene thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Alkene?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Alkene?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Alkene trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Alkene?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Alkene, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Alkene giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Alkene là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Alkene là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Alkene?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Alkene thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Alkene?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Alkene?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Alkene trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Alkene?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Alkene, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Alkene giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Alkene tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Alkene với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Alkene thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Alkene, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Alkene?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Alkene vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Alkene?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Alkene lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Alkene?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Alkene là gì?"}]}', '[]', '[{"type":"image-selection","images":["https://images.unsplash.com/photo-1528825871115-3581a5387919?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1542332213-9b5a5a3fad35?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1550989460-0adf9ea622e2?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=400&q=80"],"source":"Ứng dụng thực tế","question":"Hình ảnh nào mô tả những nải chuối chín vàng nhờ tác động của Ethylene?","narrative":"Ethylene có một ứng dụng rất thú vị trong nông nghiệp là giúp trái cây chín vàng đều. Đâu là hình ảnh minh họa cho ứng dụng này?","targetType":"nhận biết","correctAnswer":0},{"type":"matching","items":[{"id":"et1","label":"Có một liên kết đôi $C=C$"},{"id":"et2","label":"Làm mất màu nước Brom"},{"id":"et3","label":"Tạo ra nhựa PE dùng làm túi nilon"}],"source":"Tính chất & Ứng dụng","question":"Kết nối đặc tính với hiện tượng/ứng dụng tương ứng.","leftItems":[{"id":"et1","label":"Liên kết"},{"id":"et2","label":"Nhận biết"},{"id":"et3","label":"Trùng hợp"}],"narrative":"Hãy giúp tôi phân loại các đặc điểm hóa lý của Ethylene.","correctOrder":["et1","et2","et3"]},{"type":"multiple-choice","source":"Bản chất cấu tạo","options":["Vì Ethylene có liên kết đôi kém bền","Vì Ethylene là chất khí","Vì Ethylene nhẹ hơn không khí","Vì Ethylene có nhiều nguyên tử Carbon hơn"],"question":"Nguyên nhân chính dẫn đến phản ứng cộng đặc trưng của Alkene là gì?","narrative":"Tại sao Ethylene lại có phản ứng cộng, trong khi Methane thì không?","correctAnswer":0},{"type":"fill-in-the-blank","source":"Thí nghiệm","question":"Hiện tượng quan sát được khi Ethylene phản ứng with nước Brom là gì?","narrative":"Khi dẫn khí Ethylene vào dung dịch nước Brom màu da cam, ta sẽ thấy dung dịch dần dần bị ...","placeholder":"Nhập hiện tượng...","correctAnswer":"Mất màu"},{"type":"drag-drop","items":[{"id":"s1","label":"$C_2H_4$"},{"id":"s2","label":"+"},{"id":"s3","label":"$Br_2$"},{"id":"s4","label":"\\\\rightarrow"},{"id":"s5","label":"$C_2H_4Br_2$"}],"source":"Phương trình hóa học","question":"Sắp xếp phương trình phản ứng cộng Brom đúng.","narrative":"Hãy hoàn thành phương trình phản ứng cộng giữa Ethylene và Brom.","correctOrder":["s1","s2","s3","s4","s5"]}]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227916/chemistry-odyssey/curriculum/umimhzz7otfrzd8wwmen.mp4'), ('hoa9_kntt_bai8', 9, 'ketnoi', 'Bài 8: Nguồn nhiên liệu', null, 8, 'Tìm hiểu về các loại nhiên liệu hóa thạch, cách khai thác và sử dụng năng lượng một cách hiệu quả, bền vững để bảo vệ hành tinh xanh.', '[{"id":"mod1","type":"heading","content":{"text":"1. Khái niệm và Phân loại","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Nhiên liệu là những chất khi cháy tỏa nhiều nhiệt và phát sáng. Dựa trên trạng thái, ta chia thành: Nhiên liệu khí (gas), lỏng (xăng, dầu) và rắn (than, củi)."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Nhiên liệu Hóa thạch","content":"Bao gồm than đá, dầu mỏ và khí thiên nhiên. Đây là nguồn năng lượng không tái tạo, mất hàng triệu năm để hình thành sâu trong lòng đất."}},{"id":"mod4","type":"heading","content":{"text":"2. Sử dụng Nhiên liệu Hiệu quả","level":"h2"}},{"id":"mod5","type":"list","content":{"items":["**Cung cấp đủ Oxy:** Để nhiên liệu cháy hoàn toàn, không tạo ra khí độc CO và bụi than đen.","**Tăng diện tích tiếp xúc:** Chẻ nhỏ củi, tán nhỏ than hoặc phun tơi dầu mỏ để tăng hiệu suất cháy.","**Điều chỉnh lượng gió:** Duy trì ngọn lửa xanh (cháy hoàn toàn) thay vì ngọn lửa vàng, đỏ (cháy thiếu oxy)."]}},{"id":"mod6","type":"warningBox","content":{"color":"red","title":"Hiệu ứng Nhà kính","content":"Việc đốt quá nhiều nhiên liệu hóa thạch thải ra lượng lớn $CO_2$, làm Trái đất nóng lên và gây biến đổi khí hậu trên diện rộng."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=ziljRrHcN4s","title":"Nhiên liệu: Hơi thở của Công nghiệp","thumbnail":"https://img.youtube.com/vi/ziljRrHcN4s/0.jpg","description":"Tại sao chúng ta phải chuyển dịch từ năng lượng hóa thạch sang năng lượng sạch?"}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Nguồn nhiên liệu là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Nguồn nhiên liệu là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Nguồn nhiên liệu?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Nguồn nhiên liệu thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Nguồn nhiên liệu?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Nguồn nhiên liệu?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Nguồn nhiên liệu trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Nguồn nhiên liệu?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Nguồn nhiên liệu, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Nguồn nhiên liệu giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Nguồn nhiên liệu là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Nguồn nhiên liệu là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Nguồn nhiên liệu?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Nguồn nhiên liệu thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Nguồn nhiên liệu?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Nguồn nhiên liệu?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Nguồn nhiên liệu trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Nguồn nhiên liệu?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Nguồn nhiên liệu, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Nguồn nhiên liệu giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Nguồn nhiên liệu tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Nguồn nhiên liệu với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Nguồn nhiên liệu thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Nguồn nhiên liệu, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Nguồn nhiên liệu?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Nguồn nhiên liệu vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Nguồn nhiên liệu?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Nguồn nhiên liệu lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Nguồn nhiên liệu?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Nguồn nhiên liệu là gì?"}]}', '[]', '[{"type":"image-selection","images":["https://images.unsplash.com/photo-1509391366360-fe5bb629340c?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1548337138-e87d889cc369?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1521613688612-a73315024c3e?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1466611653911-95282fc36567?auto=format&fit=crop&w=400&q=80"],"source":"Năng lượng sạch","question":"Hình ảnh nào mô tả nguồn năng lượng từ gió và mặt trời — giải pháp bền vững cho tương lai?","narrative":"Để giảm thiểu ô nhiễm môi trường, cả thế giới đang hướng tới các nguồn năng lượng sạch và bền vững. Bạn có thể chọn ra đâu là nguồn năng lượng tái tạo không?","targetType":"nhận biết","correctAnswer":3},{"type":"matching","items":[{"id":"f1","label":"Than đá, Than gỗ, Củi"},{"id":"f2","label":"Xăng, Dầu hỏa, Cồn"},{"id":"f3","label":"Khí Gas, Khí thiên nhiên"}],"source":"Phân loại vật lý","question":"Nối loại nhiên liệu với ví dụ tương ứng.","leftItems":[{"id":"f1","label":"Rắn"},{"id":"f2","label":"Lỏng"},{"id":"f3","label":"Khí"}],"narrative":"Hãy giúp tôi phân loại các loại nhiên liệu theo trạng thái vật lý của chúng.","correctOrder":["f1","f2","f3"]},{"type":"multiple-choice","source":"An toàn đời sống","options":["Vì sẽ tạo ra khí CO cực độc gây ngạt","Vì ngọn lửa sẽ làm căn phòng quá nóng","Vì sẽ tốn nhiều oxy hơn bình thường","Vì tro than sẽ làm bẩn đồ đạc"],"question":"Nguy cơ lớn nhất khi đốt than trong phòng kín là gì?","narrative":"Để đảm bảo an toàn và sức khỏe, tại sao không bao giờ được đặt bếp than tổ ong đang cháy trong phòng kín?","correctAnswer":0},{"type":"fill-in-the-blank","source":"Năng lượng tái tạo","question":"Loại khí nhiên liệu sinh học phổ biến ở nông thôn là gì?","narrative":"Nhiên liệu ... là nguồn năng lượng được tạo ra từ việc ủ các chất thải hữu cơ như phân gia súc, rác thải nông nghiệp.","placeholder":"Nhập tên (ví dụ: Biogas)...","correctAnswer":"Biogas"},{"type":"drag-drop","items":[{"id":"d1","label":"Hạ nhiệt độ (Dùng nước)"},{"id":"d2","label":"+"},{"id":"d3","label":"Cách ly Oxy (Dùng bình chữa cháy)"},{"id":"d4","label":"→"},{"id":"d5","label":"Dập tắt ngọn lửa"}],"source":"Kỹ năng phòng cháy","question":"Sắp xếp quy trình dập tắt sự cháy.","narrative":"Sắp xếp các bước để dập tắt một đám cháy hiệu quả dựa trên nguyên lý tam giác lửa.","correctOrder":["d1","d2","d3","d4","d5"]}]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227921/chemistry-odyssey/curriculum/hl8hmi5y99ggaaewz0e5.mp4'), ('hoa9_kntt_bai9', 9, 'ketnoi', 'Bài 9: Ethylic alcohol', null, 9, 'Khám phá cấu tạo phân tử, tính chất và những ứng dụng rộng rãi của cồn (Ethanol) trong đời sống, y tế và công nghiệp năng lượng.', '[{"id":"mod1","type":"heading","content":{"text":"1. Cấu tạo phân tử","level":"h2"}},{"id":"mod2","type":"paragraph","content":{"text":"Ethylic alcohol (hay Ethanol) có công thức phân tử $C_2H_6O$ và công thức cấu tạo $CH_3-CH_2-OH$. Đặc điểm quan trọng nhất là nhóm **-OH** (nhóm hydroxyl) gắn vào gốc hydrocarbon."}},{"id":"mod3","type":"infoBox","content":{"color":"blue","title":"Tính chất vật lý","content":"Là chất lỏng không màu, mùi đặc trưng, vị cay, nhẹ hơn nước và **tan vô hạn** trong nước. Ethanol hòa tan được nhiều chất như iodine, benzene..."}},{"id":"mod4","type":"heading","content":{"text":"2. Tính chất hóa học","level":"h2"}},{"id":"mod5","type":"list","content":{"items":["**Tác dụng với Natri:** Giải phóng khí Hydrogen. Phương trình: $2C_2H_5OH + 2Na \\\\rightarrow 2C_2H_5ONa + H_2 \\\\uparrow$.","**Phản ứng Cháy:** Cháy với ngọn lửa màu xanh nhạt, tỏa nhiều nhiệt: $C_2H_5OH + 3O_2 \\\\xrightarrow{t^o} 2CO_2 + 3H_2O$.","**Phản ứng với Axit:** Tạo thành Este (sẽ học kỹ ở bài sau)."]}},{"id":"mod6","type":"warningBox","content":{"color":"orange","title":"Độ Rượu","content":"Là số ml rượu nguyên chất có trong 100 ml hỗn hợp rượu với nước. Ví dụ: Rượu 45 độ nghĩa là trong 100ml hỗn hợp có 45ml rượu nguyên chất."}}]', '[{"id":"v1","url":"https://www.youtube.com/watch?v=OQRVerxJ6l0","title":"Ethylic Alcohol: Hợp chất của những giấc say","thumbnail":"https://img.youtube.com/vi/OQRVerxJ6l0/0.jpg","description":"Tại sao Rượu lại tan vô hạn trong nước?"}]', '{"level1":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc tìm hiểu cơ bản đặc trưng của Ethylic alcohol là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ethylic alcohol là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ethylic alcohol?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ethylic alcohol thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ethylic alcohol?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ethylic alcohol?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ethylic alcohol trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ethylic alcohol?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ethylic alcohol, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ethylic alcohol giúp ích trực tiếp cho chúng ta điều gì?"}],"level2":[{"answer":1,"options":["Chỉ để ghi nhớ công thức","Hiểu rõ bản chất và ứng dụng của nó","Để thực hiện các phản ứng sinh lý","Tạo ra các chất nguy hiểm"],"question":"Mục đích chính của việc nghiên cứu đặc trưng của Ethylic alcohol là gì?"},{"answer":0,"options":["Có các tính chất đặc trưng và quy luật riêng biệt","Không có tính chất nào đáng chú ý","Luôn luôn biến đổi vô định","Giống hệt mọi đối tượng khác"],"question":"Đặc điểm cơ bản nhất liên quan đến Ethylic alcohol là gì?"},{"answer":2,"options":["Vị trí địa lý thực hiện thí nghiệm","Nhiệt độ, nồng độ và áp suất","Màu sắc của bình phản ứng","Kích thước của phòng thí nghiệm"],"question":"Yếu tố môi trường nào thường ảnh hưởng lớn nhất trong các bài toán về Ethylic alcohol?"},{"answer":3,"options":["Không có giá trị thực tiễn","Dùng để phân biệt các chất sinh học","Giải quyết bài toán hóa học và cải tiến sản xuất","Chỉ dùng trong sách vở học thuật"],"question":"Trong thực tế, việc am hiểu về Ethylic alcohol thường được ứng dụng để làm gì?"},{"answer":1,"options":["Sử dụng thiết bị đo lường chuẩn xác","Ngửi và nếm trực tiếp hóa chất","Ước lượng cảm tính bằng mắt thường","Đoán kết quả dựa trên linh cảm"],"question":"Phương pháp nào thường được ưu tiên dùng để đo đạc và đánh giá Ethylic alcohol?"},{"answer":0,"options":["Kết quả thực nghiệm có thể bị thay đổi rõ rệt","Không bao giờ có sự thay đổi nào","Luôn luôn gây ra hiện tượng cháy nổ","Các chất ban đầu sẽ tự động biến mất"],"question":"Điều gì xảy ra nếu ta thay đổi bất ngờ các điều kiện thí nghiệm khi khảo sát Ethylic alcohol?"},{"answer":2,"options":["Chỉ đóng vai trò phụ trong hóa hữu cơ","Là nền tảng cốt lõi để hiểu bản chất quá trình","Là các khái niệm đã cũ không còn dùng","Không mang lại lợi ích cho học sinh"],"question":"Vai trò trọng tâm của kiến thức về Ethylic alcohol trong hóa học phổ thông là gì?"},{"answer":3,"options":["Lắng nghe âm thanh từ ống nghiệm","Dùng tay không chạm trực tiếp vào vật chất","Quan sát hiện tượng và đo đạc các thông số","Chỉ cần nếm thử dung dịch"],"question":"Làm thế nào để nhận biết rõ ràng nhất một hiện tượng có liên quan đến Ethylic alcohol?"},{"answer":1,"options":["Sự biến đổi vật chất tuân theo các định luật bảo toàn","Mọi chất đều phản ứng giống hệt nhau","Khối lượng trong hệ kín luôn bị thất thoát","Mọi phản ứng hóa học đều xảy ra ngay lập tức"],"question":"Khi đưa ra nhận định về Ethylic alcohol, phát biểu nào sau đây có khả năng đúng nhất?"},{"answer":0,"options":["Tính toán và dự đoán kết quả định lượng một cách chính xác","Loại bỏ hoàn toàn các tai nạn hóa học","Tạo ra vật chất từ hư không","Làm các thí nghiệm nguy hiểm mà không cần bảo hộ"],"question":"Công thức, phương trình hay nguyên tắc về Ethylic alcohol giúp ích trực tiếp cho chúng ta điều gì?"}],"level3":[{"answer":1,"options":["Các định luật và nguyên lý hóa học cơ bản","Các quy luật mang tính ngẫu nhiên","Định luật di truyền sinh học","Hoàn toàn không có quy luật cố định"],"question":"Trong trường hợp tổng quát của chương trình học, Ethylic alcohol tuân thủ quy luật nào?"},{"answer":2,"options":["Số lượng nguyên tử ở lớp vỏ","Bản chất cấu tạo, tương tác và sự chuyển hóa","Không có điểm khác biệt, tất cả đều như nhau","Sự khác biệt về màu sắc bên ngoài"],"question":"Nếu so sánh Ethylic alcohol với các khái niệm nền tảng khác, điểm khác biệt tạo nên đặc trưng là gì?"},{"answer":3,"options":["Năm chính xác tìm ra nguyên tố","Tên nhà khoa học phát hiện ra phản ứng","Các chỉ số khối lượng, nồng độ, thể tích hoặc hiệu suất","Độ cao của phòng thí nghiệm"],"question":"Một bài toán vận dụng cao liên quan đến Ethylic alcohol thường yêu cầu học sinh tìm đại lượng nào?"},{"answer":0,"options":["Hóa chất lẫn tạp hoặc thao tác dụng cụ chưa chuẩn","Do áp suất không khí ngoài trời quá cao","Do ánh sáng đèn điện trong phòng thí nghiệm","Do tên gọi hóa chất quá dài và phức tạp"],"question":"Nếu xảy ra sai số quá lớn khi tiến hành thực nghiệm để kiểm chứng Ethylic alcohol, nguyên nhân phổ biến là gì?"},{"answer":1,"options":["Phân tích dữ kiện, viết phương trình và lập hệ bảo toàn","Chỉ đoán mò và ghi đáp số","Ghi chép lại toàn bộ lý thuyết","Bỏ qua các dữ kiện số liệu quá nhỏ"],"question":"Đâu là hướng tiếp cận logic và chính xác nhất khi giải một bài tập tính toán phức tạp về Ethylic alcohol?"},{"answer":2,"options":["Thứ tự thực hiện thí nghiệm trong ngày","Tỉ lệ tương quan giữa các chất và điều kiện phản ứng","Hình dáng của các dụng cụ thí nghiệm","Người thực hiện thí nghiệm là ai"],"question":"Khi tích hợp Ethylic alcohol vào một hệ thống chuỗi phản ứng đa bước, kết quả thu được phụ thuộc mật thiết vào yếu tố nào?"},{"answer":3,"options":["Việc nắm vững lý thuyết là yêu cầu bắt buộc","Luyện tập bài tập đa dạng giúp củng cố tư duy","Có thể bỏ qua mọi quy tắc an toàn nếu đã làm nhiều lần","Cần phải ghi chép số liệu thực nghiệm cẩn thận"],"question":"Nhận định nào sau đây là hoàn toàn SAI lầm khi nghiên cứu và thực hành về Ethylic alcohol?"},{"answer":0,"options":["Nó cung cấp nền tảng tư duy hóa học logic cho các bài sau","Vì đó là bài khó nhất để phân loại học sinh","Vì nó yêu cầu ghi nhớ máy móc","Vì nó mang tính xu hướng thời đại"],"question":"Tại sao chủ đề Ethylic alcohol lại đóng vai trò là kiến thức bản lề trong chương trình hóa học?"},{"answer":1,"options":["Số mol, định luật bảo toàn khối lượng và nguyên tố","Giá thành của các hóa chất tham gia phản ứng","Mùi vị và màu sắc ban đầu của chất","Loại ống nghiệm được sử dụng"],"question":"Loại dữ kiện nào thường là chiếc \\"chìa khóa\\" quan trọng nhất để phá vỡ bế tắc trong bài toán về Ethylic alcohol?"},{"answer":2,"options":["Các kiến thức này chỉ dùng để đi thi","Sự biến đổi của vật chất luôn có tính quy luật và định lượng chặt chẽ","Hóa học là tập hợp của các phản ứng ngẫu nhiên","Hóa học chỉ là lý thuyết suông trên giấy"],"question":"Tóm lại, kết luận quan trọng nhất mà học sinh cần khắc sâu sau khi ôn tập về Ethylic alcohol là gì?"}]}', '[]', '[{"type":"image-selection","images":["https://images.unsplash.com/photo-1595113316349-9fa4ee24f884?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1628155930542-3c7a64e2c833?auto=format&fit=crop&w=400&q=80","https://images.unsplash.com/photo-1509391366360-fe5bb629340c?auto=format&fit=crop&w=400&q=80"],"source":"Ứng dụng thực tiễn","question":"Hình ảnh nào mô tả cây xăng cung cấp xăng sinh học E5 (chứa 5% Ethanol)?","narrative":"Ethanol không chỉ dùng làm đồ uống mà còn là một loại nhiên liệu sinh học tuyệt vời. Đâu là hình ảnh minh họa cho việc sử dụng Ethanol làm nhiên liệu cho phương tiện giao thông?","targetType":"nhận biết","correctAnswer":0},{"type":"matching","items":[{"id":"al1","label":"Nhóm định chức hydroxyl -OH"},{"id":"al2","label":"Tan vô hạn trong nước"},{"id":"al3","label":"Thế Hidro trong nhóm -OH bằng Natri"}],"source":"Tổng kết bài học","question":"Kết nối đặc tính với bản chất tương ứng.","leftItems":[{"id":"al1","label":"Cấu tạo"},{"id":"al2","label":"Vật lý"},{"id":"al3","label":"Hóa học"}],"narrative":"Hãy giúp tôi phân loại các đặc điểm của Ethylic alcohol.","correctOrder":["al1","al2","al3"]},{"type":"multiple-choice","source":"Kiến thức đời sống","options":["Trong 100ml dung dịch có 30ml rượu nguyên chất","Rượu này sẽ sôi ở nhiệt độ 30 độ C","Có 30g rượu trong 1 lít nước","Rượu này đã được đun nóng đến 30 độ C"],"question":"Ý nghĩa của con số ''độ rượu'' trên bao bì sản phẩm là gì?","narrative":"Một chai rượu có nhãn ghi ''30 độ''. Điều này có ý nghĩa gì về mặt định lượng?","correctAnswer":0},{"type":"fill-in-the-blank","source":"Sản xuất","question":"Phương pháp truyền thống để sản xuất rượu từ ngũ cốc là gì?","narrative":"Để điều chế Ethanol từ tinh bột (như gạo, ngô), người ta thực hiện quá trình ... rượu bằng men vi sinh.","placeholder":"Nhập tên quá trình...","correctAnswer":"Lên men"},{"type":"drag-drop","items":[{"id":"s1","label":"$2C_2H_5OH$"},{"id":"s2","label":"+"},{"id":"s3","label":"$2Na$"},{"id":"s4","label":"\\\\rightarrow"},{"id":"s5","label":"$2C_2H_5ONa + H_2 \\\\uparrow$"}],"source":"Phương trình hóa học","question":"Sắp xếp phương trình phản ứng thế Natri đúng.","narrative":"Hoàn thiện phương trình phản ứng giữa Ethylic alcohol và kim loại Natri.","correctOrder":["s1","s2","s3","s4","s5"]}]', '{"type":"quiz-rush","rewardXp":150,"rewardGem":10,"difficulty":2,"rewardItemId":"item_basic_flask"}', false, '2026-04-10 04:08:03.638445+00', '2026-04-10 04:08:03.638445+00', 'https://res.cloudinary.com/dpcorzgkm/video/upload/v1778227925/chemistry-odyssey/curriculum/sjs7gkrmnmdpvwbpin6v.mp4');